#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution always exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n >= 2) and preserves the set of adjacent sums.
    // The sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums for reversed p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will result in the same fingerprint.
    // The reversed permutation p' is different from p unless p is a palindrome.
    // However, the problem statement guarantees a solution exists, and this
    // simple reversal is the intended solution for competitive programming problems
    // of this type when a simple transformation works.
    // For n=2, p=[1,2], reversed p'=[2,1]. F(p)=[3], F(p')=[3]. Different.
    // For n=6, p=[2,1,6,5,4,3], reversed p'=[3,4,5,6,1,2].
    // F(p) = sort([3,7,11,9,7]) = [3,7,7,9,11].
    // F(p') = sort([7,9,11,7,3]) = [3,7,7,9,11]. Different.
    // For n=5, p=[2,4,3,1,5], reversed p'=[5,1,3,4,2].
    // F(p) = sort([6,7,4,6]) = [4,6,6,7].
    // F(p') = sort([6,4,7,6]) = [4,6,6,7]. Different.
    // The example outputs for n=6 and n=5 are NOT simple reversals.
    // This implies that a simple reversal is not always the output,
    // but it is a valid solution. The problem asks for *any* solution.
    // The example output for n=2 IS a simple reversal.

    // Let's check the example outputs.
    // n=6, p=[2,1,6,5,4,3], output=[1,2,5,6,3,4]
    // This is not a reversal.
    // n=5, p=[2,4,3,1,5], output=[3,1,5,2,4]
    // This is not a reversal.

    // The problem states "We can prove that for every permutation satisfying the input constraints, a solution exists."
    // A simple reversal is always a valid solution for F(p') = F(p).
    // The only case where p' (reversed p) is not different from p is if p is a palindrome.
    // E.g., p = [1,2,3,2,1].
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome if n > 1.
    // If n is odd, the middle element is unique.
    // If n is even, p_1 != p_n, p_2 != p_{n-1}, etc.
    // For a permutation to be a palindrome, p_i = p_{n-i+1}.
    // But all elements must be distinct.
    // If p_1 = p_n, then p_1 and p_n are the same value, which is not allowed in a permutation unless n=1.
    // Since n >= 2, p_1 != p_n. Thus, a permutation cannot be a palindrome.
    // Therefore, reversing a permutation always yields a different permutation.
    // So, reversing the input permutation is always a valid solution.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

