#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long haybales_in_pile1 = a[0];
    long long days_remaining = d;

    for (int i = 1; i < n; ++i) {
        // Pile i is at index i, which is (i+1)-th pile.
        // Distance from pile (i+1) to pile 1 is i.
        // Cost to move one haybale is i days.
        long long distance = i; 

        if (days_remaining <= 0) {
            break; // No more days left to move haybales
        }

        if (a[i] == 0) {
            continue; // No haybales in this pile to move
        }

        // Calculate how many haybales we can move from pile (i+1) to pile 1
        // Each haybale costs 'distance' days.
        // We have 'a[i]' haybales in this pile.
        // We have 'days_remaining' days.

        long long max_haybales_from_this_pile = a[i];
        long long haybales_movable_by_days = days_remaining / distance;

        long long haybales_to_move = std::min(max_haybales_from_this_pile, haybales_movable_by_days);

        haybales_in_pile1 += haybales_to_move;
        days_remaining -= haybales_to_move * distance;
    }

    std::cout << haybales_in_pile1 << std::endl;
}

