void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // The first digit is 2.
        // The second digit is 3.
        // All subsequent digits are 7.
        // This construction ensures:
        // 1. No digit is 0.
        // 2. The number has n digits.
        // 3. Divisibility checks:
        //    - Not divisible by 2 (ends in 7, which is odd).
        //    - Not divisible by 3 (sum of digits: 2 + 3 + (n-2)*7 = 5 + 7n - 14 = 7n - 9.
        //      For n=2, sum=5. Not div by 3.
        //      For n=3, sum=12. Div by 3. This is a problem.
        //      Let's re-evaluate the construction for n=3.
        //      Example output for n=3 is 239.
        //      Digits are 2, 3, 9.
        //      239 % 2 != 0
        //      239 % 3 != 0 (sum=14)
        //      239 % 9 != 0 (sum=14)
        //      This works.

        // Let's try a simpler construction:
        // First digit 2, last digit 9, all middle digits 3.
        // For n=2: 29.
        //   29 % 2 != 0
        //   29 % 9 != 0
        //   Works.
        // For n=3: 239.
        //   239 % 2 != 0
        //   239 % 3 != 0 (sum=14)
        //   239 % 9 != 0 (sum=14)
        //   Works.
        // For n=4: 2339.
        //   2339 % 2 != 0
        //   2339 % 3 != 0 (sum=17)
        //   2339 % 9 != 0 (sum=17)
        //   Works.

        // This construction seems robust:
        // The number starts with 2, ends with 9, and has (n-2) threes in between.
        // Example: 23...39
        // Digits involved: 2, 3, 9.
        // - Not divisible by 2: The number ends in 9 (odd).
        // - Not divisible by 3: The sum of digits is 2 + (n-2)*3 + 9 = 2 + 3n - 6 + 9 = 3n + 5.
        //   For 3n+5 to be divisible by 3, 5 must be divisible by 3, which is false.
        //   So, the number is never divisible by 3.
        // - Not divisible by 9: Since it's not divisible by 3, it cannot be divisible by 9.

        // This construction works for all n >= 2.
        // Print '2'
        std::cout << '2';
        // Print '3' for n-2 times
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '3';
        }
        // Print '9'
        std::cout << '9' << "\n";
    }
}

