#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        p[i] = max_val_for_i;
    }

    // Check if any element in p is n-1 and no element is n.
    // If so, it means n was not present in any min(p_i, p_j) for i!=j.
    // This happens if p_k = n for some k, and all other p_j < n.
    // In this case, min(p_k, p_j) = p_j.
    // So max_{j!=k} a[k][j] = max_{j!=k} p_j = n-1.
    // And for any j!=k, max_{i!=j} a[j][i] will be p_j.
    // So if n is not present in the calculated p, we need to find the
    // element that should be n. This element is the one whose calculated
    // value is n-1, and all other elements are less than n-1.
    // Or more simply, if n is not present, change one of the n-1s to n.
    // Since the problem guarantees a solution, there will be exactly one
    // such position that should be n.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means one of the elements that should be n
        // was calculated as n-1. We need to change one of these n-1s to n.
        // Since the problem guarantees a solution, there will be at least one
        // n-1, and changing any one of them to n will work.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = -1; // Position of the last 'R' encountered, or -1 for cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we are at cell i+1 (1-indexed) and s[i] is 'R',
                // it means we can jump right from this cell.
                // The distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_R_pos + 1)
                // which simplifies to i - last_R_pos.
                // We need to be able to jump from last_R_pos+1 to i+1.
                // The required d for this segment is (i+1) - (last_R_pos+1) = i - last_R_pos.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or 0 if no 'R's) to the target n+1.
        // The distance is (n+1) - (last_R_pos + 1) = n - last_R_pos.
        max_dist = std::max(max_dist, n - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost_base = 1; // Represents 2^k - 1
        long long current_cost_sum = 1;  // Represents (2^k - 1) * (2^k) / 2

        while (x >= current_cost_sum) {
            x -= current_cost_sum;
            count++;

            // Calculate next cost
            // If current_cost_base = 2^k - 1, then next_cost_base = 2^(k+1) - 1
            // next_cost_base = 2 * current_cost_base + 1
            // next_cost_sum = next_cost_base * (next_cost_base + 1) / 2

            // Check for overflow before calculating next_cost_base
            // current_cost_base can be up to 2*10^9 for x=10^18.
            // 2 * current_cost_base + 1 can exceed 2*10^9, but still fit in long long.
            // The maximum value for current_cost_base is when current_cost_sum is around 10^18.
            // (2^k-1)(2^k)/2 approx (2^k)^2/2 = 2^(2k-1)
            // If 2^(2k-1) approx 10^18, then 2k-1 approx log2(10^18) approx 18 * log2(10) approx 18 * 3.32 approx 59.79
            // So 2k approx 60, k approx 30.
            // current_cost_base = 2^k - 1 approx 2^30 - 1 approx 10^9.
            // next_cost_base = 2^(k+1) - 1 approx 2^31 - 1 approx 2*10^9.
            // next_cost_sum = (2^(k+1)-1)(2^(k+1))/2 approx (2^31)^2/2 = 2^62/2 = 2^61.
            // 2^61 is about 2.3 * 10^18, which fits in long long.
            // So, direct calculation is fine.

            current_cost_base = 2 * current_cost_base + 1;
            current_cost_sum = current_cost_base * (current_cost_base + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The total number of students divided by 3.
        // 2. The number of coders (each team needs at least one).
        // 3. The number of mathematicians (each team needs at least one).
        // 4. The sum of coders and mathematicians (each team needs at least one of each).
        //    This is equivalent to min(c, m) because if we have k teams, we need k coders and k mathematicians.
        //    The remaining k students can be filled by x, or by additional c/m.
        //    The total number of students available for 'specialized' roles (coder or mathematician) is c+m.
        //    The total number of students available for 'any' role is c+m+x.

        // Let 'k' be the number of teams.
        // Each team needs 1 coder, 1 mathematician, and 1 other student.
        // The 'other' student can be an unspecialized student (from x),
        // an additional coder (from c), or an additional mathematician (from m).

        // The number of teams 'k' must satisfy:
        // k <= c (we need at least k coders)
        // k <= m (we need at least k mathematicians)
        // 3k <= c + m + x (total students used cannot exceed total available)

        // Combining the first two, k <= min(c, m).
        // So, k <= min(c, m, (c + m + x) / 3).
        // This is the upper bound for k.

        // Let's check if this upper bound is always achievable.
        // Suppose we want to form k teams.
        // We need k coders and k mathematicians.
        // This uses k students from c and k students from m.
        // Remaining students: c' = c - k, m' = m - k, x' = x.
        // We still need to fill k "third slots".
        // The total number of students available for these third slots is c' + m' + x'.
        // We need to ensure c' + m' + x' >= k.
        // Substituting c' and m': (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k

        // So, the maximum number of teams is indeed limited by the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // This cut forms a smaller triangle similar to the original carrot.
    // Let the height of this smaller triangle be x.
    // Let the base of this smaller triangle be b_x.
    // By similarity, b_x / 1 = x / h, so b_x = x / h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We need to find x_1, x_2, ..., x_{n-1}.
    // The first piece is the triangle from the apex to the first cut x_1.
    // Its area should be A_piece. So, A_{x_1} = A_piece.
    // x_1^2 / (2h) = h / (2n)
    // x_1^2 = h^2 / n
    // x_1 = h / sqrt(n)

    // The second piece is the region between cut x_1 and cut x_2.
    // The area from the apex to cut x_2 should be 2 * A_piece.
    // A_{x_2} = 2 * A_piece
    // x_2^2 / (2h) = 2 * h / (2n) = 2h / (2n)
    // x_2^2 = 2 * h^2 / n
    // x_2 = h * sqrt(2/n)

    // In general, for the i-th cut (from 1 to n-1), the area from the apex to x_i should be i * A_piece.
    // A_{x_i} = i * A_piece
    // x_i^2 / (2h) = i * h / (2n)
    // x_i^2 = i * h^2 / n
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where r > l, the number 2 will always be a divisor
        // for at least floor(r/2) - floor((l-1)/2) numbers.
        // If r >= 2*l, then the range [l, r] contains at least one multiple of 2 (if l is even)
        // or at least one multiple of 2 (if l is odd, then l+1 is even).
        // In fact, if r > l, there are always at least two consecutive numbers in the range.
        // One of them must be even. So 2 will always appear at least once.
        //
        // Consider any number k > 2.
        // The count of multiples of k in [l, r] is floor(r/k) - floor((l-1)/k).
        // The count of multiples of 2 in [l, r] is floor(r/2) - floor((l-1)/2).
        //
        // If r < 2*l, then any number k >= l will have at most one multiple in [l, r] (which is k itself, if k is in the range).
        // For k > r/2, there can be at most one multiple of k in [l, r].
        // For k <= r/2, there can be multiple multiples of k.
        //
        // If r < 2*l, then for any k > 1, the multiples of k are k, 2k, 3k, ...
        // If k >= l, then only k itself can be in the range [l, r]. (Because 2k >= 2l > r).
        // So, for k >= l, count is 1 if k is in [l, r], else 0.
        // If k < l, then the first multiple of k in [l, r] is k * ceil(l/k).
        // The next multiple is k * (ceil(l/k) + 1).
        // If k * (ceil(l/k) + 1) > r, then there is at most one multiple of k in [l, r].
        // This condition is equivalent to k * (floor((l-1)/k) + 2) > r.
        //
        // If r < 2*l, then for any k > 1:
        //   If k >= l, count is 1 (if k is in range).
        //   If k < l:
        //     The smallest multiple of k >= l is m1 = k * ceil(l/k).
        //     The next multiple is m2 = k * (ceil(l/k) + 1).
        //     Since k < l, we know m1 >= l.
        //     Since r < 2l, and k < l, then m2 = m1 + k < m1 + l.
        //     If m1 >= l, then m2 = m1 + k >= l + k.
        //     If m1 >= l, then m2 = m1 + k.
        //     Is m2 <= r?
        //     We know m1 >= l.
        //     If k < l, then m1 >= l.
        //     If m2 <= r, then m1 + k <= r.
        //     Since r < 2l, we have m1 + k < 2l.
        //     This means k < 2l - m1.
        //     Since m1 >= l, then 2l - m1 <= l.
        //     So k < l. This is consistent.
        //
        // The crucial observation is that if r < 2*l, then for any k > 1,
        // there can be at most one multiple of k in the range [l, r].
        // Proof: Assume there are two multiples, m1 and m2, such that l <= m1 < m2 <= r.
        // Then m2 = m1 + c*k for some integer c >= 1.
        // So m2 >= m1 + k.
        // Since m1 >= l, then m2 >= l + k.
        // Since m2 <= r, we have l + k <= r.
        // If k >= l, then l + k >= 2l. So 2l <= r. This contradicts r < 2l.
        // If k < l, then l + k < 2l. This doesn't immediately contradict r < 2l.
        // However, if k < l, then m1 = qk for some q.
        // If m1 >= l, then qk >= l.
        // If there are two multiples, m1 and m2, then m2 = m1 + k.
        // We need m1 >= l and m1 + k <= r.
        // If r < 2l, then m1 + k <= r < 2l.
        // This implies m1 + k < 2l.
        // If k >= l, then m1 + k >= l + l = 2l. This contradicts m1 + k < 2l.
        // So if r < 2l, then k must be < l.
        // If k < l, then m1 + k < l + l = 2l. This is possible.
        //
        // Let's re-evaluate:
        // If r < 2*l, then for any integer k > 1, there is at most one multiple of k in [l, r].
        // Proof: Suppose there are two multiples, x and y, such that l <= x < y <= r.
        // Then y = x + m*k for some integer m >= 1.
        // So y >= x + k.
        // Since x >= l, y >= l + k.
        // Since y <= r, we have l + k <= r.
        // But we are given r < 2*l.
        // So l + k <= r < 2*l.
        // This implies k < l.
        // So, if r < 2*l, any divisor k that appears more than once must satisfy k < l.
        // However, if k < l, then the smallest multiple of k that is >= l is k * ceil(l/k).
        // Let this be x. The next multiple is x + k.
        // If x + k <= r, then k appears twice.
        // But we know r < 2l.
        // And x >= l.
        // So x + k >= l + k.
        // If l + k > r, then k appears at most once.
        // This is true if r < l + k.
        //
        // The only way for k to appear more than once is if l + k <= r.
        // If r < 2l, then l + k <= r < 2l. This implies k < l.
        // So if r < 2l, any k that appears more than once must be less than l.
        //
        // But if r < 2l, then for any k > 1, the maximum count of its multiples in [l, r] is 1.
        // Example: l=19, r=29. Here r < 2l (29 < 38).
        // Multiples of 2: {20, 22, 24, 26, 28} (count 5)
        // Multiples of 3: {21, 24, 27} (count 3)
        // Multiples of 4: {20, 24, 28} (count 3)
        // Multiples of 5: {20, 25} (count 2)
        // Multiples of 6: {24} (count 1)
        // ...
        // The logic "at most one multiple" is incorrect.
        // The proof "l + k <= r < 2l implies k < l" is correct.
        // The error is in assuming that if k < l, then there can't be multiple occurrences.
        //
        // The key is that 2 is the smallest prime number.
        // Any number k > 2 will have its multiples spread out further than multiples of 2.
        // The count of multiples of k in [l, r] is floor(r/k) - floor((l-1)/k).
        // This count is maximized when k is smallest.
        // The smallest possible divisor (greater than 1) is 2.
        // So, 2 will always be the most frequent divisor, or tied for most frequent.
        //
        // Example: l=3, r=6.
        // Multiples of 2: {4, 6} (count 2)
        // Multiples of 3: {3, 6} (count 2)
        // Multiples of 4: {4} (count 1)
        // Multiples of 5: {5} (count 1)
        // Multiples of 6: {6} (count 1)
        // Here, 2 and 3 are tied. Outputting 2 is fine.
        //
        // The only edge case is when l=r. In this case, the only number is l.
        // Its divisors (except 1) are its prime factors and their products.
        // The problem asks for *any* of them.
        // If l=r=2, output 2.
        // If l=r=3, output 3.
        // If l=r=4, output 2.
        // If l=r=6, output 2 or 3.
        // The problem statement says "If there are multiple answers, print any of them."
        // So if l=r, printing l itself is a valid answer, as l is a divisor of l.
        //
        // For l != r, the number 2 will always be the most frequent divisor.
        // This is because for any k > 2, the number of multiples of k in [l, r]
        // is less than or equal to the number of multiples of 2 in [l, r].
        // Count(k) = floor(r/k) - floor((l-1)/k)
        // Count(2) = floor(r/2) - floor((l-1)/2)
        // Since k > 2, r/k < r/2 and (l-1)/k < (l-1)/2.
        // This implies floor(r/k) <= floor(r/2) and floor((l-1)/k) >= floor((l-1)/2) is not necessarily true.
        //
        // Example: l=19, r=29.
        // Count(2) = floor(29/2) - floor(18/2) = 14 - 9 = 5.
        // Count(3) = floor(29/3) - floor(18/3) = 9 - 6 = 3.
        // Count(4) = floor(29/4) - floor(18/4) = 7 - 4 = 3.
        // Count(5) = floor(29/5) - floor(18/5) = 5 - 3 = 2.
        //
        // The number 2 is the smallest possible divisor greater than 1.
        // Therefore, it has the highest density of multiples.
        // For any k > 2, the multiples of k are a subset of the multiples of 2 if k is even,
        // or they are less dense than multiples of 2 if k is odd.
        //
        // The number of multiples of k in [l, r] is approximately (r-l+1)/k.
        // This value is maximized when k is minimized.
        // The smallest possible divisor (greater than 1) is 2.
        // So, 2 will always be the answer unless l=r.
        //
        // The only case where 2 might not be the answer is if l=r and l is odd.
        // For example, l=r=3. Divisors of 3 (except 1) is {3}. Max is 3.
        // But the problem says "If there are multiple answers, print any of them."
        // If l=r, then l itself is a divisor of l. So printing l is always valid.
        //
        // The problem statement implies that we need to find the *integer* that appears maximum number of times.
        // If l=r=3, the only divisor is 3. So 3 is the answer.
        // If l=r=4, the divisors are {2, 4}. Both appear once. So 2 or 4.
        // If l=r=6, the divisors are {2, 3, 6}. All appear once. So 2, 3, or 6.
        //
        // The simplest solution is to always output 2 if l != r.
        // If l = r, output l.
        // This covers all cases and is correct.
        //
        // Let's verify the examples:
        // Input: 19 29
        // l=19, r=29. l != r. Output 2. Correct.
        // Input: 3 6
        // l=3, r=6. l != r. Output 2. Example output is 3.
        //
        // My reasoning for "always 2" is flawed for the case where multiple answers are allowed.
        // The example 3 6 -> 3 shows that 2 is not necessarily the *only* answer, and 3 is also valid.
        // The problem says "print any of them". So 2 would be a valid output for 3 6.
        //
        // Why did the example output 3 for 3 6?
        // For range [3, 6]:
        // Numbers: 3, 4, 5, 6
        // Divisors (excluding 1):
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        //
        // Counts:
        // 2: appears in 4, 6 (2 times)
        // 3: appears in 3, 6 (2 times)
        // 4: appears in 4 (1 time)
        // 5: appears in 5 (1 time)
        // 6: appears in 6 (1 time)
        //
        // Both 2 and 3 appear 2 times, which is the maximum.
        // So, outputting 2 or 3 is correct.
        // My logic "always 2" is valid because 2 is one of the correct answers.
        // The example outputting 3 doesn't invalidate my logic.
        //
        // So, the solution is:
        // If l == r, print l.
        // If l != r, print 2.
        // This is because 2 is the smallest prime, and thus its multiples are the most frequent.
        // If l=r, then the only number is l. Its divisors are what we care about.
        // If l=r=2, output 2.
        // If l=r=3, output 3.
        // If l=r=4, output 4 (or 2).
        // If l=r=6, output 6 (or 2 or 3).
        // In the l=r case, l itself is always a divisor of l. So printing l is always a valid answer.
        //
        // This seems too simple for a competitive programming problem, but the constraints (10^9)
        // suggest that an O(1) or O(log N) solution is required, not iterating through divisors.
        // The "not an NP problem" hint also suggests a simple, direct solution.
        //
        // Final check:
        // Case 1: l = r.
        // The only number is l. Its divisors (except 1) are what we count.
        // The number l itself is always a divisor of l.
        // So, l is a divisor that appears once.
        // If l is prime, it's the only divisor.
        // If l is composite, it has other divisors (e.g., 2 for even l).
        // But l itself is always a divisor. So printing l is always valid.
        //
        // Case 2: l < r.
        // We are looking for k > 1 that maximizes floor(r/k) - floor((l-1)/k).
        // Let f(k) = floor(r/k) - floor((l-1)/k).
        // We want to maximize f(k) for k > 1.
        // As k increases, r/k and (l-1)/k decrease.
        // Generally, f(k) is a decreasing function of k.
        // For example, f(2) = floor(r/2) - floor((l-1)/2).
        // f(3) = floor(r/3) - floor((l-1)/3).
        // Since r/2 >= r/3 and (l-1)/2 >= (l-1)/3, it's generally true that f(2) >= f(3).
        // There might be specific ranges where f(k) is equal for small k, like f(2)=f(3) for [3,6].
        // But f(2) will always be among the maximums.
        // So, printing 2 when l < r is always a correct answer.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers
    // The sequence will be: left, right, left+1, right-1, ...
    // Example: k=4. left=1, right=5.
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    // This generates k distinct differences from k down to 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            p[i] = left;
            left++;
        } else { // Odd index, take from right
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are from k+2 to n.
    // To avoid introducing new distinct differences, we append them in increasing order.
    // The last number used in the alternating sequence was either `left-1` or `right+1`.
    // The next available number is `left` (which is `k/2 + 2` if k is even, or `(k+1)/2 + 1` if k is odd).
    // Or simply, `left` is the smallest unused number after the alternating sequence.
    // `right` is the largest unused number after the alternating sequence.
    // The numbers used are `1, ..., k+1`.
    // So, the remaining numbers are `k+2, k+3, ..., n`.
    // We append them in increasing order to ensure the difference is always 1.
    // This will not introduce new differences if 1 is already among the k differences.
    // Since we generate differences from k down to 1, 1 is always included.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

