    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This marks the end of the initial non-increasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n-1 = 6, a[6]=2
    // i=5: a[5]=5, a[6]=2. a[5] > a[6]. OK.
    // i=4: a[4]=4, a[5]=5. a[4] < a[5]. Stop. i=4.
    // Suffix is [a[4], ..., a[n-1]] = [4, 5, 2]
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now `i` is the first index of the non-increasing suffix.
    // Example: [4, 3, 3, 8, 4, 5, 2] -> i=4. Suffix [4,5,2]
    // Example: [1, 2, 3, 4] -> i=3. Suffix [4]
    // Example: [5, 4, 3, 2, 3] -> i=4. Suffix [3]

    // From this point `i`, we need to find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-decreasing part before the non-increasing part.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // i=4. Suffix is [4, 5, 2].
    // j starts at i=4.
    // j=4: a[4]=4, a[5]=5. a[4] < a[5]. OK.
    // j=3: a[3]=8, a[4]=4. a[3] > a[4]. Stop. j=3.
    // The prefix to remove is of length `j`.
    // In this example, j=3. So remove a[0], a[1], a[2]. Length 3.
    // The remaining array is [8, 4, 5, 2]. This is not good.
    // The problem states: "find the length of the shortest prefix of elements you need to erase from a to make it a good array."
    // This means we are looking for the smallest `k` such that `a[k...n-1]` is good.
    // The logic above finds the smallest `k` such that `a[k...n-1]` is a "mountain" or "valley" shape.
    // The `i` found above is the start of the non-increasing suffix.
    // The `j` found below is the start of the non-decreasing part that precedes it.
    // The elements `a[0...j-1]` must be removed.

    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now `j` is the first index of the non-decreasing prefix that leads to the non-increasing suffix.
    // The elements `a[0...j-1]` must be removed.
    // The length of the prefix to remove is `j`.

    std::cout << j << std::endl;
