void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment is just [1] at pos[1].
    // min=1, max=1, length=1. So m=1 is always beautiful.
    ans[0] = '1';

    // Initialize current min_idx and max_idx for the segment containing 1.
    // For m=1, the segment is just p[pos[1]...pos[1]].
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update current_min_idx and current_max_idx to include the new number 'm'.
        // The segment must contain all numbers from 1 to m.
        // So, the segment must span from the minimum index seen so far (among 1 to m-1)
        // to the maximum index seen so far (among 1 to m-1), AND also include 'm'.
        // This means the new segment's boundaries will be min(current_min_idx, pos[m])
        // and max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx ... current_max_idx]
        // satisfies the conditions for being a permutation of 1 to m.
        // 1. It must contain all numbers from 1 to m. (Guaranteed by how current_min_idx/max_idx are updated)
        // 2. The minimum value in this segment must be 1. (Guaranteed, as 1 is always included)
        // 3. The maximum value in this segment must be m. (Guaranteed, as m is the largest value added)
        // 4. The length of the segment must be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        } else {
            ans[m - 1] = '0';
        }
    }

    std::cout << ans << "\n";
}

