void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, assuming a[0] becomes 0, a[1] becomes 1, etc.
    // This means a[i] must be at least i.
    // If a[i] < i, then it's impossible to make a[0...i] strictly increasing
    // starting from 0, 1, ... i.
    int max_left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_left_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, assuming a[n-1] becomes 0, a[n-2] becomes 1, etc.
    // This means a[i] must be at least (n-1-i).
    // If a[i] < (n-1-i), then it's impossible to make a[i...n-1] strictly decreasing
    // ending with 0.
    int max_right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            max_right_len = n - i;
        } else {
            break;
        }
    }

    // If the sum of the maximum possible lengths of the left and right parts
    // is greater than or equal to n, it means there's an overlap or they meet.
    // This implies there exists a peak k such that the conditions can be met.
    // max_left_len is the count of elements from the left that can form an increasing sequence.
    // max_right_len is the count of elements from the right that can form a decreasing sequence.
    // If max_left_len + max_right_len >= n, it means there's at least one element
    // that can be part of both sequences (the peak element).
    if (max_left_len + max_right_len >= n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

