    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for elements smaller than s that should be <= s
    // These are elements a[0]...a[median_idx-1]
    // If a[i] > s for i < median_idx, we must decrease a[i] to s.
    // This is not strictly correct. We only need a[i] <= s.
    // The median element a[median_idx] must be s.
    // All elements a[0]...a[median_idx-1] must be <= s.
    // All elements a[median_idx+1]...a[n-1] must be >= s.

    // First, make the median element equal to s.
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] was originally less than s, it was increased to s.
    // Now, consider elements to the left of median_idx.
    // They must be <= s. If any a[i] (i < median_idx) is > s, it must be decreased to s.
    // This is because if a[i] > s, and a[median_idx] is s, then a[i] would be greater than the median.
    // To maintain the sorted order and median property, a[i] must be <= s.
    // Since we want minimum operations, we only change a[i] if a[i] > s, and change it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // If a[median_idx] was originally greater than s, it was decreased to s.
    // Now, consider elements to the right of median_idx.
    // They must be >= s. If any a[i] (i > median_idx) is < s, it must be increased to s.
    // This is because if a[i] < s, and a[median_idx] is s, then a[i] would be smaller than the median.
    // To maintain the sorted order and median property, a[i] must be >= s.
    // Since we want minimum operations, we only change a[i] if a[i] < s, and change it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

