    // The problem allows appending up to 3 elements, and doesn't require minimizing.
    // So, we can always append 2 elements.

    // The problem statement says "If an array is good already you are allowed to not append elements."
    // My strategy above always appends 2 elements.
    // Let's check if the initial array is good first.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // Append current_xor_sum and current_sum + current_xor_sum
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

