int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long current_a_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be "jumped over" by
            // any 'a's to its left. Each such 'a' will perform an 'ab' -> 'bba'
            // operation, effectively doubling the number of 'a's that can jump
            // over the next 'b' to the left.
            // The number of 'a's that can jump over this 'b' is current_a_count.
            // Each such jump adds 1 step.
            total_steps = (total_steps + current_a_count) % MOD;
            // After all current_a_count 'a's jump over this 'b', each 'a'
            // effectively creates a new 'b' and moves to the right.
            // So, for the next 'b' to the left, there will be twice as many
            // 'a's that can jump over it.
            current_a_count = (current_a_count * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' can potentially jump
            // over 'b's to its right. We increment the count of 'a's that
            // are currently "active" and can jump over future 'b's (to its left).
            current_a_count = (current_a_count + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

