// Function to convert a non-negative integer to its parity pattern string
// The pattern string will have a fixed length of 18, padded with '0's from the left.
// Each character in the string represents the parity of the corresponding digit:
// '0' for even, '1' for odd.
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to a fixed length of 18
    // The pattern is built in reverse, so we pad at the end and then reverse.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    // Reverse the pattern to get the correct order (most significant digit first)
    // This is important because the problem states "i-th from the right digit"
    // and we want to store it in a canonical form.
    // Example: 92 -> "10" (9 is odd, 2 is even). Padded: "00...010".
    // The map key will be this canonical form.
    std::reverse(pattern.begin(), pattern.end());
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of numbers for each parity pattern.
    // The key is the 18-character parity pattern string.
    // The value is the count of numbers in the multiset that generate this pattern.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to length 18
            // This ensures it matches the canonical form stored in the map.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }
            std::cout << pattern_counts[padded_s] << "\n";
        }
    }

    return 0;
}

