    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[i][0] stores count of 'x' in s[0...i-1]
    // prefix_counts[i][1] stores count of 'y' in s[0...i-1]
    // prefix_counts[i][2] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(3, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[i + 1][0] = prefix_counts[i][0];
        prefix_counts[i + 1][1] = prefix_counts[i][1];
        prefix_counts[i + 1][2] = prefix_counts[i][2];
        if (s[i] == 'x') {
            prefix_counts[i + 1][0]++;
        } else if (s[i] == 'y') {
            prefix_counts[i + 1][1]++;
        } else { // s[i] == 'z'
            prefix_counts[i + 1][2]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts for the substring s[l-1 ... r-1]
        int count_x = prefix_counts[r][0] - prefix_counts[l - 1][0];
        int count_y = prefix_counts[r][1] - prefix_counts[l - 1][1];
        int count_z = prefix_counts[r][2] - prefix_counts[l - 1][2];

        // Find min and max counts among x, y, z
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        // If max_count - min_count <= 1, then the counts are balanced enough
        // (e.g., (k, k, k), (k, k, k+1), (k, k+1, k+1)).
        // In this case, it's always possible to form a string where all 3-char
        // substrings are permutations of 'x', 'y', 'z', and thus terminate.
        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
    // We want to maximize x.
    // The strategy is to remove prime factors from p that are also in q,
    // one prime factor at a time, until p is no longer divisible by q.
    // For each prime factor f of q, we try to remove as few f's from p as possible
    // to make p not divisible by q.
    // Specifically, we find the largest divisor of p that is not divisible by q.

    long long ans = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            long long count_i_in_p = 0;
            while (current_p > 0 && current_p % i == 0) {
                current_p /= i;
                count_i_in_p++;
            }

            long long count_i_in_q = 0;
            while (temp_q % i == 0) {
                temp_q /= i;
                count_i_in_q++;
            }

            // If p has enough factors of i to be divisible by q (with respect to factor i)
            // and q has factor i, we need to reduce p's factors of i.
            // The largest x not divisible by q (due to factor i) would be p / (i^(count_i_in_q - 1 + 1))
            // which is p / (i^count_i_in_q).
            // This ensures that x has one less factor of i than q requires, making it not divisible by q.
            // We take the maximum of such candidates.
            if (count_i_in_p >= count_i_in_q) {
                ans = std::max(ans, p / (long long)std::pow(i, count_i_in_q));
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long i = temp_q;
        long long current_p = p;
        long long count_i_in_p = 0;
        while (current_p > 0 && current_p % i == 0) {
            current_p /= i;
            count_i_in_p++;
        }

        long long count_i_in_q = 1; // temp_q is a prime factor itself

        if (count_i_in_p >= count_i_in_q) {
            ans = std::max(ans, p / (long long)std::pow(i, count_i_in_q));
        }
    }

    return ans;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

