#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    // (n * (n + 1) / 2) % MOD
    // We need to handle division by 2.
    // Since MOD is prime (10^9 + 7), we can use modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004; 

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    if (term1 % 2 == 0) {
        term1 /= 2;
    } else {
        term2 /= 2;
    }

    return (term1 * term2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r_val = sum_arithmetic_series(b - 1);

    // Sum_k_term = sum_{k=1 to a} (k * b + 1)
    // Sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // Sum_k_term = b * sum_{k=1 to a} k + a
    // Sum_k_term = b * (a * (a + 1) / 2) + a
    long long sum_k_val = sum_arithmetic_series(a);

    long long term1 = (b % MOD * sum_k_val) % MOD;
    long long term2 = a % MOD;
    long long sum_k_term_val = (term1 + term2) % MOD;

    long long total_sum = (sum_r_val * sum_k_term_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

