// Function to compute the Z-array for a given string
std::vector<int> compute_z_array(const std::string& str) {
    int n = str.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && str[z[i]] == str[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all suffixes of s
    // z_arrays[i] stores the Z-array for s.substr(i)
    // z_arrays[i][j] is the length of the longest common prefix of s.substr(i) and s.substr(i+j)
    // This is equivalent to LCP(s[i..N-1], s[i+j..N-1])
    // We need LCP(s, s[j..N-1]) for various j.
    // Let's rephrase: we need LCP(s[x..N-1], s[y..N-1]) for various x, y.
    // This is equivalent to z_array_for_s_from_x[y-x] if y >= x.
    // Or, more simply, LCP(s.substr(x), s.substr(y))
    // We can compute LCP(s.substr(x), s.substr(y)) by computing Z-array for s.substr(x) + '#' + s.substr(y)
    // Or, more efficiently, by using a generalized suffix structure or suffix array.
    // For N=5000, N^2 LCP queries are too slow if each takes N.
    // N^2 LCP queries where each LCP is computed in O(1) after O(N log N) or O(N) preprocessing is fine.
    // A simpler approach for LCP(s[i..], s[j..]) is to use a 2D array or compute on demand.
    // LCP[i][j] = length of longest common prefix of s[i..] and s[j..]
    // LCP[i][j] = 0 if s[i] != s[j]
    // LCP[i][j] = 1 + LCP[i+1][j+1] if s[i] == s[j]
    // This is O(N^2) to precompute.
    // LCP[i][j] can be computed in O(1) after O(N^2) precomputation.
    // LCP[i][j] = LCP(s.substr(i), s.substr(j))

    std::vector<std::vector<int>> lcp(n + 1, std::vector<int>(n + 1, 0));
    for (int i = n - 1; i >= 0; --i) {
        for (int j = n - 1; j >= 0; --j) {
            if (s[i] == s[j]) {
                lcp[i][j] = 1 + lcp[i + 1][j + 1];
            } else {
                lcp[i][j] = 0;
            }
        }
    }

    // `wins` stores the number of `k` values for which Vasya can win.
    long long wins = 0;

    // Iterate over all possible initial shifts `k_actual` (0 to N-1)
    // This `k_actual` is Kolya's chosen shift.
    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char first_char = s[k_actual]; // Vasya learns this character

        // `possible_k_indices` stores all `k'` such that s[k'] == first_char.
        std::vector<int> possible_k_indices;
        for (int i = 0; i < n; ++i) {
            if (s[i] == first_char) {
                possible_k_indices.push_back(i);
            }
        }

        // If only one `k'` is possible, Vasya wins immediately.
        if (possible_k_indices.size() == 1) {
            wins++;
            continue;
        }

        // Vasya needs to choose an optimal position `p` (1 to N-1)
        // `max_p_wins` stores the maximum number of `k'` values that can be uniquely determined
        // for the current `k_actual` and a chosen `p`.
        int max_p_wins = 0;

        // Iterate over all possible positions `p` Vasya can choose (1 to N-1)
        for (int p = 1; p < n; ++p) {
            // `t[p]` is `s[(k_actual + p) % N]`
            char char_at_p = s[(k_actual + p) % n];

            // `remaining_k_indices` stores `k'` values that match both `t[0]` and `t[p]`.
            std::vector<int> remaining_k_indices;
            for (int k_prime : possible_k_indices) {
                if (s[(k_prime + p) % n] == char_at_p) {
                    remaining_k_indices.push_back(k_prime);
                }
            }

            // If only one `k'` remains, Vasya wins for this `p`.
            if (remaining_k_indices.size() == 1) {
                max_p_wins = std::max(max_p_wins, 1); // Vasya wins if he can uniquely determine k
                continue;
            }

            // If multiple `k'` remain, Vasya needs to check if any of them are "equivalent"
            // to `k_actual` based on the information `t[0]` and `t[p]`.
            // Vasya loses if there are at least two `k'` that fit the information.
            // This means Vasya loses if `remaining_k_indices.size() > 1`.
            // So, if `remaining_k_indices.size() > 1`, this `p` does not lead to a win.
            // We are looking for a `p` that makes `remaining_k_indices.size() == 1`.
            // If no such `p` exists, `max_p_wins` will remain 0.
        }

        // If `max_p_wins` is 1, it means there exists at least one `p` for which Vasya wins.
        // So, for this `k_actual`, Vasya wins.
        if (max_p_wins == 1) {
            wins++;
        }
    }

    // The probability is `wins / N`.
    double probability = static_cast<double>(wins) / n;

    std::cout << std::fixed << std::setprecision(15) << probability << std::endl;

    return 0;
}

