int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition (no internal elements)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_zeros[i]: count of consecutive zeros ending at i
    if (a[0] == 0) {
        left_zeros[0] = 1;
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
        } else {
            left_zeros[i] = 0;
        }
    }

    // Calculate right_ones[i]: count of consecutive ones starting at i
    if (a[n - 1] == 1) {
        right_ones[n - 1] = 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = right_ones[i + 1] + 1;
        } else {
            right_ones[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) { // Found a 01 boundary
            int k_val = std::min(left_zeros[i], right_ones[i + 1]);
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> result_a = a;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) { // Found a 01 boundary
            int k_val = std::min(left_zeros[i], right_ones[i + 1]);
            if (k_val > 0) {
                // Change 0s to 1s
                for (int j = 0; j < k_val - max_k; ++j) {
                    result_a[i - j] = 1;
                }
                // Change 1s to 0s
                for (int j = 0; j < k_val - max_k; ++j) {
                    result_a[i + 1 + j] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

