            std::swap(n, m);
        }

        // Case 1: k < m (or k < n, since n <= m)
        // It's impossible to reach (n,m) in k moves if k is less than the maximum coordinate.
        // This is because each move can change a coordinate by at most 1.
        if (k < m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Now we know k >= m.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is limited by min(n, m).
        // Let's try to make as many diagonal moves as possible to reach (n,m).
        // We can make n diagonal moves of type (1,1) to reach (n,n).
        // This uses n moves. We still need to reach (n,m) from (n,n) in k-n moves.
        // The remaining distance is (0, m-n).
        // We need to cover (m-n) units in y-direction.
        // This requires at least m-n straight moves (0,1).
        // Total moves so far: n (diagonal) + (m-n) (straight) = m moves.
        // We are at (n,m) and have used m moves.
        // We have k-m moves remaining.

        long long remaining_moves = k - m;
        long long ans;

        // If n and m have different parities, then (n,m) has different parity from (0,0)
        // if n+m is odd.
        // The parity of (x+y) changes with each diagonal move (x+dx+y+dy = x+y+dx+dy, dx+dy is 0 or +-2).
        // The parity of (x+y) changes with each straight move (x+dx+y+dy = x+y+dx or x+y+dy, dx or dy is +-1).
        // So, (x+y) parity always flips with each move.
        // Thus, (n+m) must have the same parity as k.
        // If (n+m) % 2 != k % 2, it's impossible.
        // This is equivalent to (m-n) % 2 != remaining_moves % 2.
        // (n+m) % 2 == k % 2  <=>  (n+m-k) % 2 == 0.
        // (n+m-k) % 2 == 0  <=>  (m-n) % 2 == (k-2n) % 2.
        // (m-n) % 2 == (k-n-n) % 2.
        // (m-n) % 2 == (k-n) % 2 - n % 2.
        // (m-n) % 2 == (k-m + m-n) % 2.
        // (m-n) % 2 == (remaining_moves + m-n) % 2.
        // This means remaining_moves must have the same parity as 0, i.e., remaining_moves must be even.
        // If remaining_moves is odd, and (m-n) is even, then (m-n) % 2 != remaining_moves % 2.
        // If remaining_moves is odd, and (m-n) is odd, then (m-n) % 2 == remaining_moves % 2.
        // This is getting complicated. Let's use the (n+m) % 2 == k % 2 condition directly.

        if ((n + m) % 2 != k % 2) {
            // If (n+m) and k have different parities, it's impossible.
            // Example: (2,2) in 3 moves. n+m=4 (even), k=3 (odd). Impossible.
            // Wait, example output for (2,2,3) is 1.
            // My parity argument is flawed.
            // Let's re-evaluate parity.
            // Each move changes (x+y) by dx+dy.
            // For diagonal moves, dx, dy are +-1. So dx+dy is 0 or +-2 (even). (x+y) parity doesn't change.
            // For straight moves, one of dx, dy is 0, the other is +-1. So dx+dy is +-1 (odd). (x+y) parity flips.
            // Let D be diagonal moves, S be straight moves.
            // Initial (x+y) = 0. Final (x+y) = n+m.
            // Parity of (n+m) must be equal to parity of S.
            // We know D+S = k. So S = k-D.
            // Parity of (n+m) must be equal to parity of (k-D).
