                        break;
                    }
                    if (visited[current_path_x]) { // Already computed
                        current_path_y_sum += dp[current_path_x].second;
                        current_path_x = dp[current_path_x].first;
                        break;
                    }

                    // Mark as in current path
                    in_stack[current_path_x] = true;
                    path_stack.push_back(current_path_x);

                    // Calculate the two steps for current_path_x
                    long long val_at_current_path_x = a_fixed[current_path_x - 1];
                    int temp_next_x_after_first_op = current_path_x + val_at_current_path_x;
                    long long temp_y_added_first_op = val_at_current_path_x;

                    if (temp_next_x_after_first_op <= 0 || temp_next_x_after_first_op > n) {
                        // Terminates after first op
                        current_path_y_sum += temp_y_added_first_op;
                        current_path_x = 0; // Mark as terminated
                        terminated_in_path = true;
                        break;
                    }

                    long long temp_val_at_next_x = a_fixed[temp_next_x_after_first_op - 1];
                    int temp_final_x_after_two_ops = temp_next_x_after_first_op - temp_val_at_next_x;
                    long long temp_y_added_second_op = temp_val_at_next_x;

                    current_path_y_sum += temp_y_added_first_op + temp_y_added_second_op;
                    current_path_x = temp_final_x_after_two_ops;
                }

                // After the loop, current_path_x holds the final x or 0 if terminated.
                // current_path_y_sum holds the total y accumulated.

                // Now, update dp values for all nodes in the path_stack
                // and mark them as visited.
                for (int node_in_path : path_stack) {
                    if (cycle_detected) {
                        dp[node_in_path] = {-1, -1}; // Mark as infinite loop
                    } else {
                        dp[node_in_path] = {current_path_x, current_path_y_sum};
                    }
                    visited[node_in_path] = true;
                    in_stack[node_in_path] = false; // Remove from current path stack
                }
            }
        }
    }

    // Now, for each i from 1 to n-1, run the program.
    for (int i = 1; i < n; ++i) {
        long long a1_val = i; // This is the a_1 for the current test case.

        long long current_y = 0;
        int current_x = 1;

        // First pair of operations (using a_1)
        // Step 2: x = x + a_x, y = y + a_x
        current_y += a1_val;
        current_x += a1_val;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: y = y + a_x, x = x - a_x
        long long val_at_current_x = a_fixed[current_x - 1];
        current_y += val_at_current_x;
        current_x -= val_at_current_x;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now current_x is within [1, n]. We can use the DP table.
        // The DP table stores the result of two operations (x -> x+a[x] -> x+a[x]-a[x+a[x]]).
        // So we just need to add dp[current_x].second to current_y and update current_x.

        if (dp[current_x].first == -1) { // Infinite loop detected by DP
            std::cout << -1 << "\n";
        } else {
            current_y += dp[current_x].second;
            std::cout << current_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <tuple>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0); // We can initialize with 0, then adjust based on constraints
    std::vector<long long> min_val_at_idx(n, 2000000000000000000LL); // Represents M_j - sum_d_j

    // First pass: Process type 2 operations to find upper bounds for initial_a[j]
    // and determine the relative values of initial_a[j] for type 1 operations.
    // We are looking for a_0[j] such that a_0[j] + sum_d_j <= M_j.
    // This means a_0[j] <= M_j - sum_d_j.
    // We want to find the tightest upper bound for each a_0[j].
    // Let's denote current_sum_d[j] as the sum of d's applied to index j up to the current operation.
    // For a type 2 operation (l, r, M), we have max_{j=l..r} (a_0[j] + current_sum_d[j]) = M.
    // This implies a_0[j] + current_sum_d[j] <= M for all j in [l, r].
    // So, a_0[j] <= M - current_sum_d[j].
    // We need to find the minimum of these (M - current_sum_d[j]) values for each j.

    std::vector<long long> current_sum_d(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_sum_d[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], ops[i].val - current_sum_d[j]);
            }
        }
    }

    // Initialize initial_a with the tightest upper bounds found.
    // If no type 2 operation constrained an element, it can be anything, e.g., 0.
    // The problem states |a_i| <= 10^9.
    // If min_val_at_idx[j] is still its initial large value, it means no type 2 op constrained it.
    // We can set initial_a[j] to 0 in such cases, or any value within [-10^9, 10^9].
    // For simplicity, let's use min_val_at_idx[j] as the initial_a[j] if it was constrained.
    // If not constrained, we can set it to 0.
    for (int i = 0; i < n; ++i) {
        if (min_val_at_idx[i] == 2000000000000000000LL) {
            initial_a[i] = 0; // Default for unconstrained elements
        } else {
            initial_a[i] = min_val_at_idx[i];
        }
    }

    // Second pass: Verify if this initial_a satisfies all type 2 operations.
    // If max_{j=l..r} (initial_a[j] + current_sum_d[j]) != M, then no solution.
    // Also, check if initial_a[j] + current_sum_d[j] <= M for all j in [l, r].
    // The way initial_a was constructed guarantees initial_a[j] + current_sum_d[j] <= M for all j in [l, r]
    // for the specific current_sum_d[j] at the time of that type 2 operation.
    // We need to check if the maximum is *exactly* M.

    std::fill(current_sum_d.begin(), current_sum_d.end(), 0);
    std::vector<long long> current_a(n);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_sum_d[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = -3000000000000000000LL; // Sufficiently small
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] = initial_a[j] + current_sum_d[j];
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraints for initial_a
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not happen if the problem guarantees a solution
            // within these bounds, and our construction is correct.
            // However, if min_val_at_idx[i] was very large/small, it might exceed.
            // The problem states "all numbers in his array didn't exceed 10^9 in their absolute value".
            // This implies that if a solution exists, there is one within these bounds.
            // Our construction finds the largest possible initial_a[i] that satisfies all <= M constraints.
            // If this largest possible value exceeds 10^9, it means no solution exists within bounds.
            // However, the problem statement implies that if a solution exists, it's within bounds.
            // So, if we found a solution, it should be within bounds.
            // Let's just output NO if it's out of bounds.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // The length of string a can be increased by appending its parity.
    // This means we can effectively make string a as long as we want.
    // The maximum length of a string we might need to consider is |b|.
    // If |a| < |b|, we must append characters to a.
    // If |a| > |b|, we must remove characters from a.
    // If |a| == |b|, we might do nothing, or remove/append.

    // The crucial insight is that if we can reach a string of length L with P ones,
    // we can then reach a string of length L+1 with P or P+1 ones (depending on P%2).
    // And we can always remove characters from the front.

    // Let's consider the number of '1's.
    // If we have `k` ones in string `s`, and we append `parity(s)`,
    // the new string `s'` will have `k + (k % 2)` ones.
    // This means the number of ones can only increase or stay the same.
    // Specifically, if `k` is even, `k % 2 = 0`, so `k` ones.
    // If `k` is odd, `k % 2 = 1`, so `k+1` ones.
    // In both cases, the number of ones is `k` if `k` is even, and `k+1` if `k` is odd.
    // This is equivalent to saying the number of ones becomes `k` if `k` is even,
    // and `k+1` if `k` is odd.
    // This is also equivalent to saying the number of ones becomes `k` if `k` is even,
    // and `k` if `k` is odd, PLUS `k % 2`.
    // The number of ones in the new string is `k + (k % 2)`.
    // This means the number of ones in the new string is always even if `k` is even,
    // and always even if `k` is odd (k+1 is even).
    // So, after the first append operation, the number of ones becomes even.
    // And subsequent appends will always append '0' (since parity of an even number of ones is 0).
    // This means after the first append operation, the number of ones will be even,
    // and all subsequent appends will add '0's, keeping the number of ones even.

    // Let's re-evaluate:
    // Initial string `a` has `parity_a` (0 or 1) and `ones_count_a` ones.
    // If we append `parity_a`, the new string `a'` has `ones_count_a + parity_a` ones.
    // The parity of `a'` is `(ones_count_a + parity_a) % 2`.
    // If `ones_count_a` is even, `parity_a = 0`. `a'` has `ones_count_a` ones. `parity(a') = 0`.
    // If `ones_count_a` is odd, `parity_a = 1`. `a'` has `ones_count_a + 1` ones. `parity(a') = 0`.
    // In both cases, `parity(a')` is 0.
    // This means after the first append operation, the string will have an even number of ones.
    // Any subsequent append operations will append '0' (since parity is 0).
    // So, if we perform at least one append operation, the number of ones in `a` effectively becomes
    // `ones_count_a` if `ones_count_a` is even, or `ones_count_a + 1` if `ones_count_a` is odd.
    // Let this value be `effective_ones_a`. This `effective_ones_a` is always even.
    // And `effective_ones_a` is the minimum number of ones we can achieve if we need to append.

    // The number of ones in `b` is `ones_count_b`.
    int ones_count_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_count_a++;
        }
    }

    int ones_count_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_count_b++;
        }
    }

    // Case 1: We don't need to append any characters to 'a'.
    // This means we only use the 'remove first character' operation.
    // In this case, 'b' must be a suffix of 'a'.
    // And the number of ones must be exactly `ones_count_b`.
    // This is equivalent to checking if `a` contains `b` as a suffix.
    // If `a` is shorter than `b`, this is impossible.
    if (a.length() >= b.length()) {
        if (a.substr(a.length() - b.length()) == b) {
            std::cout << "YES\n";
            return 0;
        }
    }

    // Case 2: We need to append characters to 'a'.
    // This implies we perform at least one 'append parity' operation.
    // After the first append operation, the number of ones in `a` becomes `ones_count_a` if `ones_count_a` is even,
    // or `ones_count_a + 1` if `ones_count_a` is odd.
    // Let's call this `min_ones_after_append_a`.
    int min_ones_after_append_a = ones_count_a;
    if (ones_count_a % 2 != 0) { // If initial ones_count_a is odd
        min_ones_after_append_a++; // It becomes even by appending '1'
    }
    // Now, `min_ones_after_append_a` is the minimum number of '1's we can have in `a`
    // if we perform at least one append operation.
    // All subsequent appends will add '0's, so the number of '1's will not change further.

    // For `b` to be reachable, its number of ones (`ones_count_b`) must be less than or equal to
    // `min_ones_after_append_a`.
    // If `ones_count_b` is greater than `min_ones_after_append_a`, it's impossible.
    if (ones_count_b <= min_ones_after_append_a) {
        // If we can reach `ones_count_b` ones, and we can make `a` arbitrarily long,
        // then we can always form `b`.
        // The only constraint is the number of ones.
        // If `ones_count_b` is achievable, we can always construct a string `a'`
        // that has `ones_count_b` ones and is long enough to contain `b` as a suffix.
        // For example, we can append `min_ones_after_append_a - ones_count_b` '0's to `a`
        // (if `min_ones_after_append_a` is greater than `ones_count_b`),
        // and then append enough '0's to make its length at least `|b|`.
        // Then we can remove characters from the front to match `b`.
        // This logic holds because the 'remove first character' operation allows us to effectively
        // choose any suffix of the extended string `a`.
        // Since we can append '0's indefinitely after the first parity append,
        // we can always make the string long enough.
        // The only thing that matters is if the number of '1's in `b` can be matched.
        // And we've established that `min_ones_after_append_a` is the minimum number of '1's
        // we can have if we append. If `ones_count_b` is less than or equal to this, it's possible.
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_office_cry_volume = children[i].v;
        long long total_hall_cry_volume = 0; // Accumulates d_j from children leaving due to chain reaction

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply office cry effect
            if (current_office_cry_volume > 0) {
                children[j].p -= current_office_cry_volume;
                current_office_cry_volume--;
            }

            // Apply accumulated hall cry effect
            children[j].p -= total_hall_cry_volume;

            // Check if child j leaves due to low confidence
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_hall_cry_volume += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

