        // This logic seems to be missing a case.
        // What if a[i] >= prev_b, but a[i] is "too far" from prev_b in the cyclic sense?
        // Example: m=10, a[i]=8, prev_b=1, x=3.
        // If we set b[i]=a[i]=8, then prev_b becomes 8.
        // Next element a[i+1] might need to be >= 8.
        // But if we increment a[i] by 3, it becomes (8+3)%10 = 1.
        // This is also >= prev_b=1.
        // And it's smaller than 8, which is better for the next element.
        // So, if a[i] >= prev_b, we have two options for b_i:
        //   1. b_i = a[i]. Operations = 0.
        //   2. b_i = (a[i] + k) % m for some k <= x, such that (a[i] + k) % m >= prev_b.
        //      This means we are looking for a b_i in the range [prev_b, (a[i]+x)%m] if it wraps around.
        //      Or [prev_b, a[i]+x] if it doesn't wrap around.
        //
        // Let's define `b_i_min_val` as the smallest value `b_i` can take such that `b_i >= prev_b`.
        // And `b_i_max_val` as the largest value `b_i` can take such that `b_i` is reachable from `a_i` with at most `x` operations.
        //
        // The values `b_i` can take from `a_i` with at most `x` operations are:
        // `a_i`, `(a_i+1)%m`, ..., `(a_i+x)%m`.
        //
        // We need to find `b_i` such that `b_i >= prev_b` AND `(b_i - a_i + m) % m <= x`.
        //
        // Let's consider two cases for `a[i]` relative to `prev_b`:
        //
        // Case 1: `a[i] >= prev_b`.
        //   We can choose `b_i = a[i]`. This satisfies `b_i >= prev_b` and requires 0 operations, which is `<= x`.
        //   So, `b_i = a[i]` is a valid choice.
        //   However, we might be able to choose a smaller `b_i` that is still `>= prev_b` by incrementing `a[i]` and wrapping around.
        //   For example, if `m=10, a[i]=8, prev_b=1, x=3`.
        //   If we choose `b_i = a[i] = 8`, then `prev_b` becomes 8.
        //   If we choose `b_i = (a[i]+3)%m = 1`, then `prev_b` becomes 1. This is better for future elements.
        //   This choice `b_i = 1` is valid because `1 >= prev_b` (1 >= 1) and `(1 - 8 + 10) % 10 = 3 <= x`.
        //   So, if `a[i] >= prev_b`, we have two options for `b_i`:
        //     Option A: `b_i = a[i]`. This requires 0 operations.
        //     Option B: `b_i = (a[i] + k) % m` for some `k` such that `(a[i] + k) % m < a[i]`. This means `a[i] + k >= m`.
        //               And we need `(a[i] + k) % m >= prev_b`.
        //               The number of operations `k` must be `<= x`.
        //               The smallest value `(a[i] + k) % m` can take is 0 (if `a[i]+k` is a multiple of `m`).
        //               The largest value `(a[i] + k) % m` can take is `(a[i]+x)%m`.
        //               If `a[i] + x >= m`, then `(a[i]+x)%m` is a value `v < a[i]`.
        //               If this `v` is `>= prev_b`, then we can choose `b_i = prev_b`.
        //               The operations needed for `a[i]` to become `prev_b` is `(prev_b - a[i] + m) % m`.
        //               If this is `<= x`, then we can set `b_i = prev_b`.
        //               This is the best choice because it keeps `prev_b` as small as possible.
        //               So, if `a[i] >= prev_b`:
        //                 Calculate `ops_to_reach_prev_b = (prev_b - a[i] + m) % m`.
        //                 If `ops_to_reach_prev_b <= x`:
        //                   We can set `b_i = prev_b`.
        //                 Else (`ops_to_reach_prev_b > x`):
        //                   We cannot reach `prev_b` by incrementing `a[i]` and wrapping around.
        //                   We are forced to use `b_i = a[i]` (or some `a[i]+k` without wrap-around).
        //                   Since `a[i] >= prev_b`, `b_i = a[i]` is a valid choice.
        //                   So, we must set `prev_b = a[i]`.
        //
        // Case 2: `a[i] < prev_b`.
        //   We *must* increment `a[i]` to reach at least `prev_b`.
        //   The number of operations needed to reach `prev_b` from `a[i]` is `ops_needed = (prev_b - a[i] + m) % m`.
        //   If `ops_needed <= x`:
        //     We can achieve `b_i = prev_b`. So, we set `prev_b = prev_b` (no change).
        //   Else (`ops_needed > x`):
        //     We cannot reach `prev_b` by incrementing `a[i]` by at most `x`.
        //     It's impossible to satisfy `b_i >= prev_b`.
        //     So, return `false`.
        //
        // Combining these:
        // If `a[i] >= prev_b`:
        //   `diff = a[i] - prev_b`.
        //   If `diff <= x`: // This means `a[i]` is "close enough" to `prev_b` that we can increment `a[i]` to wrap around and become `prev_b`.
        //                    // Specifically, `(prev_b - a[i] + m) % m` is the number of operations to get from `a[i]` to `prev_b` by wrapping.
        //                    // This is `m - diff`.
        //                    // If `m - diff <= x`, then we can set `b_i = prev_b`.
        //                    // This is equivalent to `m - (a[i] - prev_b) <= x`.
        //                    // Or `prev_b - a[i] + m <= x`.
        //                    // This is the number of operations to go from a[i] to prev_b by wrapping around.
        //                    // If `a[i] >= prev_b`, then `a[i]` is already a valid choice for `b_i`.
        //                    // We want to keep `prev_b` as small as possible.
        //                    // So, if we can make `b_i = prev_b` by incrementing `a[i]` (possibly wrapping around), we should.
        //                    // The number of operations to make `a[i]` become `prev_b` is `(prev_b - a[i] + m) % m`.
        //                    // If `a[i] >= prev_b`, this value is `m - (a[i] - prev_b)`.
        //                    // If `m - (a[i] - prev_b) <= x`, then we can set `b_i = prev_b`.
        //                    // Otherwise, we must set `b_i = a[i]`.
        //   Let `ops_to_reach_prev_b_by_wrap = (prev_b - current_a + m) % m`.
        //   If `ops_to_reach_prev_b_by_wrap <= x`:
        //     // We can make `a[i]` become `prev_b` by incrementing.
        //     // This is the best choice for `b_i` as it keeps `prev_b` minimal.
        //     // So `prev_b` remains unchanged.
        //     continue;
        //   Else:
        //     // We cannot make `a[i]` become `prev_b` by incrementing and wrapping around within `x` operations.
        //     // Since `current_a >= prev_b`, we must use `current_a` as `b_i`.
        //     // This requires 0 operations, which is `<= x`.
        //     // So, `prev_b` becomes `current_a`.
        //     prev_b = current_a;
        //
        // If `a[i] < prev_b`:
        //   `ops_needed = prev_b - a[i]`.
        //   If `ops_needed <= x`:
        //     // We can make `a[i]` become `prev_b` by incrementing.
        //     // So `prev_b` remains unchanged.
        //     continue;
        //   Else:
        //     // We cannot make `a[i]` become `prev_b` within `x` operations.
        //     // It's impossible to satisfy `b_i >= prev_b`.
        //     return false;
        //
        // This logic seems correct and covers all cases.

        if (current_a >= prev_b) {
            // Option 1: Don't increment a[i] at all. b[i] = a[i]. Operations = 0.
            // This is valid if 0 <= x.
            // Option 2: Increment a[i] such that it wraps around and becomes a value >= prev_b.
            // The smallest such value is prev_b.
            // Operations needed to make a[i] become prev_b (by wrapping): (prev_b - current_a + m) % m.
            // If current_a >= prev_b, this is m - (current_a - prev_b).
            long long ops_to_wrap_to_prev_b = (prev_b - current_a + m) % m;

            if (ops_to_wrap_to_prev_b <= x) {
                // We can make a[i] become prev_b by incrementing.
                // This is the best choice for b[i] as it keeps prev_b minimal.
                // So prev_b remains unchanged.
                // Example: a[i]=8, prev_b=1, m=10, x=3.
                // ops_to_wrap_to_prev_b = (1 - 8 + 10) % 10 = 3.
                // 3 <= x. So we can make b[i]=1. prev_b remains 1.
                // This is correct.
            } else {
                // We cannot make a[i] become prev_b by incrementing and wrapping around within x operations.
                // Since current_a >= prev_b, we must use current_a as b[i].
                // This requires 0 operations, which is <= x.
                // So, prev_b becomes current_a.
                // Example: a[i]=8, prev_b=1, m=10, x=2.
                // ops_to_wrap_to_prev_b = (1 - 8 + 10) % 10 = 3.
                // 3 > x. So we cannot make b[i]=1.
                // We must use b[i]=a[i]=8. prev_b becomes 8.
                // This is correct.
                prev_b = current_a;
            }
        } else { // current_a < prev_b
            // We must increment a[i] to reach at least prev_b.
            // The number of operations needed to reach prev_b from a[i] is prev_b - current_a.
            long long ops_needed = prev_b - current_a;
            if (ops_needed <= x) {
                // We can make a[i] become prev_b by incrementing.
                // So prev_b remains unchanged.
                // Example: a[i]=1, prev_b=3, m=10, x=2.
                // ops_needed = 3 - 1 = 2.
                // 2 <= x. So we can make b[i]=3. prev_b remains 3.
                // This is correct.
            } else {
                // We cannot make a[i] become prev_b within x operations.
                // It's impossible to satisfy b[i] >= prev_b.
                // Example: a[i]=1, prev_b=4, m=10, x=2.
                // ops_needed = 4 - 1 = 3.
                // 3 > x. Impossible.
                return false;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a_0 and a_1 into different subsequences.
    // This ensures that a_0 + a_1 + h is a possible value.
    // To minimize max_f - min_f, we want to make min_f as large as possible
    // and max_f as small as possible.
    //
    // If a_0 is in S1 and a_1 is in S2:
    // min_f will be min(a_0 + a_1 + h, a_0 + a_2, a_1 + a_2)
    // max_f will be max(a_{n-2} + a_{n-1}, a_{n-1} + a_0 + h, a_{n-1} + a_1 + h)
    //
    // Consider putting a_0 in S1 and all other elements in S2.
    // min_f = min(a_0 + a_1 + h, a_1 + a_2)
    // max_f = max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h)
    //
    // Consider putting a_0, a_1 in S1 and all other elements in S2.
    // min_f = min(a_0 + a_1, a_0 + a_2 + h, a_1 + a_2 + h, a_2 + a_3)
    // max_f = max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h, a_1 + a_{n-1} + h)
    //
    // The key observation is that if we put a_0 in S1 and a_1, ..., a_{n-1} in S2,
    // then the minimum value of f is min(a_0 + a_1 + h, a_1 + a_2).
    // The maximum value of f is max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1}).
    //
    // Let's try a specific partition:
    // Put elements[0] into S1.
    // Put elements[1], ..., elements[n-1] into S2.
    //
    // Values of f:
    // 1. a_0 + a_j + h for j = 1, ..., n-1. (S1-S2 pairs)
    // 2. a_i + a_j for i, j = 1, ..., n-1, i != j. (S2-S2 pairs)
    //
    // min_f = min(a_0 + a_1 + h, a_1 + a_2)
    // max_f = max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1})
    //
    // goodness2 = max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1}) - min(a_0 + a_1 + h, a_1 + a_2)
    long long min_f2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    long long max_f2 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
    long long goodness2 = max_f2 - min_f2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute prefix sums of '0's
    std::vector<int> prefix_zeros(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
    }

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', it cannot be the start of a substring with value > 0.
            // The only possible good substring starting with '0' is "0" itself,
            // if its length (1) equals its value (0). This is not possible.
            // So, we only consider substrings starting with '1' for the small_len_limit.
            // For large_len_limit, we need to handle leading zeros.
            continue;
        }

        // Case 1: Substrings where length is small enough for direct calculation
        // Max length for direct calculation: 18-20 bits. Let's use 20 for safety.
        // Max value for length 20 is 2^20 - 1 ~ 10^6.
        // Max length of string is 2e5.
        // If length is L, value is V. We need L = V.
        // If L > 20, V can be at most 2^20-1. So L > V is very likely.
        // If L <= 20, V can be up to 2^20-1.
        // Let's pick a limit, say 20.
        // If a substring has length L, its value V.
        // If L > 20, then V <= 2^L - 1.
        // If L > 20, and V = L, then V must be > 20.
        // The maximum value of L is N (2e5).
        // The maximum value of V for a substring of length L is 2^L - 1.
        // If L = V, then L = 2^L - 1 is not possible for L > 1.
        // If L = V, and L is large, then V must be large.
        // The maximum value of V for a substring of length L is 2^L - 1.
        // The minimum value of V for a substring of length L starting with '1' is 2^(L-1).
        // So we need L = V.
        // If L is large, say L > 20, then 2^(L-1) is much larger than L.
        // For example, if L=20, 2^(19) = 524288. L=20. No match.
        // So, we only need to check small lengths directly.
        // What is the maximum length L such that L could be equal to its binary value?
        // L = f(s_l...s_r).
        // If s_l = '1', then f(s_l...s_r) >= 2^(L-1).
        // We need L >= 2^(L-1).
        // For L=1, 1 >= 2^0 = 1. (1 is good)
        // For L=2, 2 >= 2^1 = 2. (10 is good)
        // For L=3, 3 >= 2^2 = 4. (False)
        // So, for s_l = '1', we only need to check L=1 and L=2.
        // This is incorrect. The value can be small due to leading zeros.
        // The problem states f(011) = 3, f(00101) = 5.
        // This means leading zeros are part of the substring.
        // The condition is $r - l + 1 = f(s_l \dots s_r)$.
        // The substring $s_l \dots s_r$ can have leading zeros.
        // Example: $s = 0110$. $s_2 \dots s_4 = 110$. Length 3. Value 6. Not good.
        // Example: $s = 0110$. $s_1 \dots s_4 = 0110$. Length 4. Value 6. Not good.
        // Example: $s = 0110$. $s_2 \dots s_3 = 11$. Length 2. Value 3. Not good.
        // Example: $s = 0110$. $s_1 \dots s_1 = 0$. Length 1. Value 0. Not good.
        // Example: $s = 0110$. $s_2 \dots s_2 = 1$. Length 1. Value 1. Good.
        // Example: $s = 0110$. $s_3 \dots s_3 = 1$. Length 1. Value 1. Good.
        // Example: $s = 0110$. $s_4 \dots s_4 = 0$. Length 1. Value 0. Not good.
        // Example: $s = 0110$. $s_1 \dots s_2 = 01$. Length 2. Value 1. Not good.
        // Example: $s = 0110$. $s_1 \dots s_3 = 011$. Length 3. Value 3. Good.
        // Example: $s = 0110$. $s_2 \dots s_4 = 110$. Length 3. Value 6. Not good.
        // Example: $s = 0110$. $s_1 \dots s_4 = 0110$. Length 4. Value 6. Not good.
        // Output for 0110 is 4. My manual check:
        // s_1..s_1 = 0, len 1, val 0. No.
        // s_2..s_2 = 1, len 1, val 1. Yes.
        // s_3..s_3 = 1, len 1, val 1. Yes.
        // s_4..s_4 = 0, len 1, val 0. No.
        // s_1..s_2 = 01, len 2, val 1. No.
        // s_2..s_3 = 11, len 2, val 3. No.
        // s_3..s_4 = 10, len 2, val 2. Yes.
        // s_1..s_3 = 011, len 3, val 3. Yes.
        // s_2..s_4 = 110, len 3, val 6. No.
        // s_1..s_4 = 0110, len 4, val 6. No.
        // Total: 4. Matches example.

        // The maximum length of a substring is N = 2e5.
        // If a substring has length L, its value V.
        // If L is large, say L > 20, then V can be at most 2^L - 1.
        // If L = V, then L must be small.
        // For L=1, V=1.
        // For L=2, V=2.
        // For L=3, V=3.
        // For L=4, V=4.
        // ...
        // For L=18, V=18.
        // For L=19, V=19.
        // For L=20, V=20.
        // The maximum value of L for which L = V is possible is when L is roughly log2(N).
        // If L = V, and L is the length of the substring, then V must be at most N.
        // So V <= 2e5.
        // The maximum number of bits to represent 2e5 is ceil(log2(2e5)) = 18.
        // So, if L > 18, then V must be at most 2^18 - 1.
        // If L > 18, and L = V, then V > 18.
        // This means we only need to check substrings of length up to ~18+K.
        // Let's say we check up to length 20.
        // For each starting position `i`:
        long long current_val = 0;
        for (int j = i; j < std::min(n, i + 20); ++j) { // Check up to 20 characters
            current_val = (current_val << 1) | (s[j] - '0');
            int len = j - i + 1;
            if (current_val == len) {
                good_substrings_count++;
            }
        }

        // Case 2: Substrings where length is large.
        // These substrings must have many leading zeros.
        // If a substring $s_l \dots s_r$ has length $L = r - l + 1$ and value $V = f(s_l \dots s_r)$.
        // We are looking for $L = V$.
        // If $L > 20$, then $V$ must be small (at most $2^{20}-1 \approx 10^6$).
        // But $L$ can be up to $2 \cdot 10^5$.
        // If $L = V$, then $V$ must be at most $2 \cdot 10^5$.
        // This means $V$ can be represented by at most 18 bits (since $2^{17} < 2 \cdot 10^5 < 2^{18}$).
        // So, if $L = V$, and $L > 18$, then the substring $s_l \dots s_r$ must have many leading zeros.
        // Specifically, if $V$ is represented by $k$ bits (i.e., $2^{k-1} \le V < 2^k$),
        // then the substring $s_l \dots s_r$ must have $L-k$ leading zeros.
        // The first '1' in $s_l \dots s_r$ would be at index $l + (L-k)$.
        // So, $s_l \dots s_{l+(L-k)-1}$ must all be '0'.
        // And $s_{l+(L-k)}$ must be '1'.
        // The actual binary value $V$ is formed by $s_{l+(L-k)} \dots s_r$.
        // The length of this part is $k$.
        // So, for a fixed $i$ (start of substring), we iterate $j$ (end of substring).
        // We already handled $j-i+1 \le 20$.
        // Now consider $j-i+1 > 20$.
        // Let $k$ be the number of bits required to represent $V$.
        // $k \le 18$ (since $V \le N \le 2 \cdot 10^5$).
        // The substring $s_i \dots s_j$ has length $L = j-i+1$.
        // The value $V$ is formed by $s_i \dots s_j$.
        // If $s_i \dots s_j$ has $Z$ leading zeros, then $V$ is formed by the last $L-Z$ bits.
        // $V = f(s_{i+Z} \dots s_j)$.
        // The length of this significant part is $L-Z$.
        // So $L-Z$ must be $k$.
        // We need $L = V$.
        // The number of leading zeros in $s_i \dots s_j$ is $Z = prefix\_zeros[j+1] - prefix\_zeros[i]$.
        // If $s_i = '1'$, then $Z=0$.
        // If $s_i = '0'$, then $Z > 0$.
        // The actual value $V$ is formed by $s_{i+Z} \dots s_j$.
        // The length of this part is $j - (i+Z) + 1$. Let this be $k_{actual}$.
        // We need $L = V$.
        // $V$ is at most $2 \cdot 10^5$. So $k_{actual}$ is at most 18.
        // This means $j - (i+Z) + 1 \le 18$.
        // So $j$ can be at most $i+Z+18-1$.
        // For each $i$, we iterate $j$ from $i+20$ up to $n-1$.
        // But we only need to check $j$ such that $j - (i+Z) + 1 \le 18$.
        // This means $j$ is not too far from $i+Z$.
        // The number of leading zeros from $s_i$ to $s_j$ is $Z = prefix\_zeros[j+1] - prefix\_zeros[i]$.
        // The first '1' is at index $i+Z$.
        // The value $V$ is $f(s_{i+Z} \dots s_j)$.
        // The length of the substring is $L = j-i+1$.
        // We need $L = V$.
        // The number of bits in $V$ is $k_{actual} = j - (i+Z) + 1$.
        // Since $V \le N$, $k_{actual}$ is at most 18.
        // So $j - (i+Z) + 1 \le 18$.
        // This means $j \le i+Z+17$.
        // For a fixed $i$, we iterate $Z$ from $0$ up to $n-1-i$.
        // The index of the first '1' is $p_1 = i+Z$.
        // If $p_1 \ge n$, then all are zeros, $V=0$. $L=0$ is not possible.
        // If $s_{p_1} = '0'$, then $Z$ is not the count of leading zeros.
        // We need to find the first '1' starting from $i$.
        // Let $p_1$ be the index of the first '1' at or after $i$.
        // If no '1' exists, then all are '0's, $V=0$. $L=0$ is not possible.
        // If $s_i = '0'$, then $p_1 > i$.
        // The number of leading zeros is $p_1 - i$.
        // The value $V$ is formed by $s_{p_1} \dots s_j$.
        // The length of this part is $k_{actual} = j - p_1 + 1$.
        // We need $k_{actual} \le 18$.
        // So $j \le p_1 + 17$.
        // For each $i$:
        // Find the first '1' at or after $i$. Let its index be `first_one_idx`.
        // If `first_one_idx` is not found (all '0's till end), then no good substring starts at `i` with value > 0.
        // If `first_one_idx` is found:
        // Iterate `j` from `first_one_idx` up to `min(n-1, first_one_idx + 17)`.
        // For each such `j`, calculate `V = f(s_{first_one_idx} \dots s_j)`.
        // Calculate `L = j - i + 1`.
        // If `L == V`, increment count.

        // This approach is better:
        // For each `i` from `0` to `n-1`:
        //   `current_val = 0`
        //   `num_leading_zeros = 0`
        //   For `j` from `i` to `n-1`:
        //     If `s[j] == '0'`:
        //       If `current_val == 0`: `num_leading_zeros++`
        //       `current_val = current_val << 1`
        //     Else (`s[j] == '1'`):
        //       `current_val = (current_val << 1) | 1`
        //     `len = j - i + 1`
        //     If `current_val == len`: `good_substrings_count++`
        //     If `current_val > len + 18` (or some small constant like 20): break (value grows much faster than length)
        //     If `len > current_val + 18` (or some small constant like 20): break (length grows much faster than value)
        // This is still O(N*K) where K is the max length to check. K=20 is fine.
        // The problem is when `s[i]` is '0'.
        // Example: `s = 000000000000000000001000` (20 zeros, then 1000)
        // `i=0`. `j=0..19` (all zeros). `current_val=0`. `len=1..20`. No match.
        // `j=20` (`s[20]=1`). `current_val=1`. `len=21`. No match.
        // `j=21` (`s[21]=0`). `current_val=2`. `len=22`. No match.
        // `j=22` (`s[22]=0`). `current_val=4`. `len=23`. No match.
        // `j=23` (`s[23]=0`). `current_val=8`. `len=24`. No match.
        // This is still O(N*K).

        // Let's refine the two cases:
        // Case 1: Substrings $s_i \dots s_j$ where $j-i+1 \le \text{MAX_LEN_CHECK}$.
        // MAX_LEN_CHECK can be around 20.
        // For each $i$, iterate $j$ from $i$ to $\min(n-1, i + \text{MAX_LEN_CHECK} - 1)$.
        // Calculate $V = f(s_i \dots s_j)$. If $V = j-i+1$, increment count.
        // This is $O(N \cdot \text{MAX_LEN_CHECK})$.

        // Case 2: Substrings $s_i \dots s_j$ where $j-i+1 > \text{MAX_LEN_CHECK}$.
        // Let $L = j-i+1$. We need $L = V$.
        // Since $L > \text{MAX_LEN_CHECK}$, $V$ must also be $>\text{MAX_LEN_CHECK}$.
        // The maximum possible value for $V$ is $N = 2 \cdot 10^5$.
        // This means $V$ can be represented by at most 18 bits ($2^{17} < 2 \cdot 10^5 < 2^{18}$).
        // So, the "significant" part of the binary string $s_i \dots s_j$ (i.e., from the first '1' to $s_j$)
        // must have length at most 18.
        // Let $p_1$ be the index of the first '1' in $s_i \dots s_j$.
        // If $s_i \dots s_j$ consists only of '0's, then $V=0$. $L=0$ is not possible.
        // So $p_1$ must exist.
        // The length of the significant part is $k_{actual} = j - p_1 + 1$.
        // We need $k_{actual} \le 18$.
        // So for each $i$, we find $p_1 = \text{first '1' at or after } i$.
        // If $p_1$ doesn't exist, continue.
        // Then we iterate $j$ from $p_1$ to $\min(n-1, p_1 + 17)$.
        // For each such $j$, we calculate $V = f(s_{p_1} \dots s_j)$.
        // We need to check if $L = j-i+1 = V$.
        // The number of leading zeros in $s_i \dots s_j$ is $p_1 - i$.
        // So $L = (p_1 - i) + (j - p_1 + 1) = (p_1 - i) + k_{actual}$.
        // We need $(p_1 - i) + k_{actual} = V$.
        // For a fixed $i$, and fixed $j$ (which implies fixed $p_1$ and $k_{actual}$ and $V$),
        // we need to check if $V - k_{actual} = p_1 - i$.
        // $V - k_{actual}$ is the number of leading zeros required for the value $V$ to match length $L$.
        // $p_1 - i$ is the actual number of leading zeros in $s_i \dots s_j$.
        // So we need $V - k_{actual} = p_1 - i$.
        // This means $p_1 - i$ must be equal to $V - (j - p_1 + 1)$.
        // And $p_1 - i \ge 0$.
        // This check is for $j-i+1 > \text{MAX_LEN_CHECK}$.
        // So $p_1 - i + k_{actual} > \text{MAX_LEN_CHECK}$.
        // Since $k_{actual} \le 18$, this implies $p_1 - i$ must be large.
        // $p_1 - i > \text{MAX_LEN_CHECK} - k_{actual}$.
        // For each $i$:
        //   `current_val = 0`
        //   For `j` from `i` to `min(n-1, i + 18 + 18)` (max length of significant part + max leading zeros for small V)
        //   Let's use a fixed window for the significant part.
        //   For each `i` from `0` to `n-1`:
        //     `current_val = 0`
        //     `first_one_idx = -1`
        //     For `j` from `i` to `n-1`:
        //       If `first_one_idx == -1`:
        //         If `s[j] == '1'`: `first_one_idx = j`
        //         Else: // `s[j] == '0'` and `first_one_idx == -1`
        //           // This is a leading zero. `current_val` remains 0.
        //           // `len = j - i + 1`. `V = 0`. `len == V` is `j-i+1 == 0`, impossible.
        //           // So no good substring if all are zeros.
        //           continue;
        //       
        //       // Now `first_one_idx` is set. `s[j]` is part of the significant value.
        //       `current_val = (current_val << 1) | (s[j] - '0')`
        //       If `current_val > n + 18`: // Optimization: value too large to be a length
        //         break;
        //       
        //       `len = j - i + 1`
        //       If `current_val == len`:
        //         `good_substrings_count++`
        //       
        //       // Optimization: If `current_val` is small, but `len` is already much larger,
        //       // it's unlikely they will match later.
        //       // `len = (j - first_one_idx + 1) + (first_one_idx - i)`
        //       // `len = k_actual + num_leading_zeros`
        //       // `V = current_val`
        //       // We need `k_actual + num_leading_zeros = V`.
        //       // If `k_actual > 18`, then `V` would be very large.
        //       // If `j - first_one_idx + 1 > 18`:
        //       //   `current_val` is already formed by more than 18 bits.
        //       //   `current_val` will be at least `2^18`.
        //       //   `len` is at most `N = 2e5`.
        //       //   `2^18 = 262144`. So `current_val` will be greater than `len`.
        //       //   So if `j - first_one_idx + 1 > 18`, we can break.
        //       If `j - first_one_idx + 1 > 18`:
        //         break;
        // This is the correct logic. The inner loop runs at most 18 times after `first_one_idx` is found.
        // Before `first_one_idx` is found, it just skips '0's.
        // So for each `i`, the inner loop runs `(first_one_idx - i) + 18` times in worst case.
        // Total complexity: Sum over `i` of `(first_one_idx_for_i - i) + 18`.
        // The `18` part is `N * 18`.
        // The `(first_one_idx_for_i - i)` part is sum of number of leading zeros for each `i`.
        // This sum can be `O(N^2)` in worst case (e.g., `000...01`).
        // Example: `000...01`. `i=0`, `first_one_idx = N-1`. Loop runs `N-1 + 18` times.
        // This is `O(N^2)`. Max N=2e5. N^2 is too slow.

        // The issue is `first_one_idx - i` can be large.
        // We need to optimize finding `first_one_idx`.
        // We can precompute `next_one[k]` = index of first '1' at or after `k`.
        // `next_one[k]` can be computed in `O(N)` by iterating backwards.
        // `next_one[n-1] = (s[n-1] == '1' ? n-1 : n)`
        // `next_one[k] = (s[k] == '1' ? k : next_one[k+1])`
        // Then `first_one_idx = next_one[i]`.
        // The loop for `j` will be:
        // `first_one_idx = next_one[i]`
        // If `first_one_idx == n`, continue (all zeros from `i` to `n-1`).
        // `current_val = 0`
        // For `j` from `first_one_idx` to `min(n-1, first_one_idx + 17)`:
        //   `current_val = (current_val << 1) | (s[j] - '0')`
        //   `len = j - i + 1`
        //   If `current_val == len`:
        //     `good_substrings_count++`
        // This is `O(N * 18)`. This is efficient enough.

    } // End of original loop for i

    std::vector<int> next_one(n + 1, n); // next_one[k] = index of first '1' at or after k. n if no '1'.
    for (int k = n - 1; k >= 0; --k) {
        if (s[k] == '1') {
            next_one[k] = k;
        } else {
            next_one[k] = next_one[k + 1];
        }
    }

    for (int i = 0; i < n; ++i) {
        int first_one_idx = next_one[i];
        if (first_one_idx == n) { // All zeros from i to n-1
            continue;
        }

        long long current_val = 0;
        // Iterate j from first_one_idx.
        // The length of the significant part (from first_one_idx to j) is `j - first_one_idx + 1`.
        // This length must be at most 18 for `current_val` to be <= N.
        // So `j` goes up to `first_one_idx + 17`.
        for (int j = first_one_idx; j < std::min(n, first_one_idx + 18); ++j) {
            current_val = (current_val << 1) | (s[j] - '0');
            int len = j - i + 1; // Total length of substring s[i...j]

            // Check if current_val is too large to be equal to len.
            // Max len is N = 2e5. Max current_val for 18 bits is 2^18-1 = 262143.
            // If current_val > N, it can't be equal to len.
            // This check is implicitly handled by `j < first_one_idx + 18` because `current_val`
            // will not exceed `2^18-1`.
            // However, `len` can be small if `i` is close to `j`.
            // `len = (j - first_one_idx + 1) + (first_one_idx - i)`
            // `len = k_actual + num_leading_zeros`
            // We need `V = len`.
            // `V = k_actual + num_leading_zeros`.
            // `num_leading_zeros = first_one_idx - i`.
            // So `V - k_actual = first_one_idx - i`.
            // This means `first_one_idx - i` must be exactly `V - k_actual`.
            // And `first_one_idx - i` must be non-negative.
            // `k_actual = j - first_one_idx + 1`.

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

