int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that s[l-1...r-1] contains a triple.
                                                // If no such r exists, it's n+1.

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible step sizes k.
        // The maximum k is such that x + 2k < n. So 2k < n - x, k < (n - x) / 2.
        // Since k >= 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a triple: s[x], s[x+k], s[x+2k] are all equal.
                // This triple is valid for any substring s[l-1...r-1] where l <= x+1 and r >= x+2k+1.
                // The minimum l for this triple is x+1.
                // The minimum r for this triple is x+2k+1.

                // We want to update min_r_for_l[l] for all l from 1 to x+1.
                // For a fixed l, the smallest r that includes this triple is x+2k+1.
                // So, for l from 1 to x+1, we can potentially update min_r_for_l[l] with x+2k+1.
                // Since we are iterating x from left to right, and k from small to large,
                // x+2k+1 will be increasing.
                // This means for a fixed l, the first triple (x,k) we find that satisfies l <= x+1
                // will give us the smallest x+2k+1.
                // However, we need to consider all x,k.
                // The current triple (x, k) implies that for any l_prime <= x+1,
                // the substring s[l_prime-1 ... x+2k] contains this triple.
                // So, for each l_prime from 1 to x+1, we can update min_r_for_l[l_prime] = min(min_r_for_l[l_prime], x+2k+1).
                // This is equivalent to:
                // min_r_for_l[x+1] = min(min_r_for_l[x+1], x+2k+1);
                // min_r_for_l[x] = min(min_r_for_l[x], x+2k+1);
                // ...
                // min_r_for_l[1] = min(min_r_for_l[1], x+2k+1);

                // This can be done efficiently.
                // For a given x, the smallest r that contains a triple starting at x is x+2k+1.
                // This means for l = x+1, the minimum r is x+2k+1.
                // For l = x, the minimum r is also x+2k+1 (if this is the first triple found for x).
                // The crucial observation is that if s[x], s[x+k], s[x+2k] is a triple,
                // then for any l_prime <= x+1, the substring s[l_prime-1 ... x+2k] contains this triple.
                // So, for each l_prime from 1 to x+1, the minimum r for l_prime is at most x+2k+1.
                // We want to find the smallest r for each l.
                // So, for each l from 1 to x+1, we update min_r_for_l[l] = min(min_r_for_l[l], x+2k+1).
                // This is a range update.
                // However, the problem constraints on k are small.
                // k can be at most 4. If k >= 5, then 2k >= 10.
                // If s[x] == s[x+k] == s[x+2k], then s[x] == s[x+k] and s[x+k] == s[x+2k].
                // This implies that if k >= 5, then x+2k >= x+10.
                // If we have a triple (x, k) with k >= 5, then the indices are x, x+k, x+2k.
                // The minimum r for this triple is x+2k+1.
                // Consider the triple (x, 1). If s[x] == s[x+1] == s[x+2], then min_r_for_l[x+1] = x+3.
                // Consider the triple (x, 2). If s[x] == s[x+2] == s[x+4], then min_r_for_l[x+1] = x+5.
                // Consider the triple (x, 3). If s[x] == s[x+3] == s[x+6], then min_r_for_l[x+1] = x+7.
                // Consider the triple (x, 4). If s[x] == s[x+4] == s[x+8], then min_r_for_l[x+1] = x+9.
                // If k >= 5, then x+2k+1 >= x+11.
                // Any triple with k >= 5 will have its rightmost index x+2k at least x+10.
                // If there is a triple (x, k) with k >= 5, then the substring s[x...x+2k] contains it.
                // The length of this substring is at least 11.
                // Any substring of length 11 or more must contain a triple if one exists.
                // The maximum length of a substring that does NOT contain a triple is 10.
                // This is because if a substring has length 11, say s[i...i+10],
                // and it does not contain a triple, then for any x, k such that i <= x < x+2k <= i+10,
                // s[x], s[x+k], s[x+2k] are not all equal.
                // This implies that if we find a triple (x, k), we only need to consider k up to 4.
                // If k >= 5, then x+2k >= x+10.
                // The minimum r for this triple is x+2k+1.
                // For any l_prime <= x+1, min_r_for_l[l_prime] is updated to min(min_r_for_l[l_prime], x+2k+1).
                // The maximum value of k we need to check is limited.
                // If k is large, say k=5, then x+2k = x+10.
                // If s[x] == s[x+5] == s[x+10], then for any l <= x+1, r >= x+11, this pair (l,r) is counted.
                // The maximum length of a string that does not contain such a triple is 10.
                // This means if a substring has length 11 or more, it must contain a triple.
                // So, if r - l + 1 >= 11, then (l,r) is always counted.
                // This simplifies the problem. We only need to consider triples where x+2k+1 - (x+1) + 1 <= 10.
                // This means 2k+1 <= 10, so 2k <= 9, k <= 4.
                // So we only need to check k from 1 to 4.

                // Update min_r_for_l for l from 1 to x+1.
                // The current triple (x, k) makes (l, r) valid if l <= x+1 and r >= x+2k+1.
                // So for each l_prime from 1 to x+1, we update min_r_for_l[l_prime] with x+2k+1.
                // This is a range minimum update.
                // Since we iterate x from 0 to n-1, and for each x, k from 1 to 4,
                // we can update min_r_for_l[x+1] with x+2k+1.
                // Then, we can propagate these minimums backwards.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
            // Optimization: if k reaches 5, we can break.
            // Any triple with k >= 5 implies a length of at least 11.
            // If a substring has length >= 11, it is guaranteed to contain a triple.
            // This is a known property for binary strings and patterns like 'aaa'.
            // The maximum length of a binary string without 'aaa' is 10.
            // For example, 0011001100.
            // So, if we find a triple (x, k) with k >= 5, it means x+2k+1 >= x+11.
            // This means for any l <= x+1, r >= x+11, the pair (l,r) is counted.
            // The min_r_for_l[l] values will be at most x+11.
            // This means we only need to check k up to 4.
            if (k == 4) break; // Max k to check is 4.
        }
    }

    // Propagate minimums backwards: min_r_for_l[l] should be min(min_r_for_l[l], min_r_for_l[l+1])
    // This ensures that if a triple is valid for (l+1, r_prime), it's also valid for (l, r_prime).
    // So, min_r_for_l[l] should be at most min_r_for_l[l+1].
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p_idx == m) {
            break; // All required tracks covered
        }

        long long current_h = h[i];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // Find the first track p[p_idx] that can be covered by current_h
        // It must be within [left_reach, right_reach]
        if (p[p_idx] > right_reach) {
            // This head cannot reach p[p_idx] or any subsequent tracks.
            // Since heads are sorted and p are sorted, if current_h cannot reach p[p_idx],
            // then current_h cannot cover p[p_idx] and current_h cannot cover any p[k] for k > p_idx.
            // And since h[i+1] > h[i], h[i+1] might be able to cover p[p_idx],
            // but we are trying to cover p[p_idx] with current_h.
            // If p[p_idx] is too far right for current_h, then current_h cannot cover it.
            // We need to find the first p[p_idx] that current_h can cover.
            // If p[p_idx] is already too far right, this head cannot help with it.
            // This logic is slightly off. We need to find the first p[k] that current_h can cover.
            // If current_h cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head can only cover tracks to its left or around it.
            // If p[p_idx] is to the right of current_h + T, then current_h cannot cover it.
            // This head is useless for p[p_idx] and subsequent tracks.
            // This means we need to use a different head for p[p_idx].
            // The current head h[i] must cover some p[k] where k >= p_idx.
            // If h[i] cannot cover p[p_idx], it means p[p_idx] is too far right.
            // This head cannot cover p[p_idx].
            // The logic should be: for each head, cover as many tracks as possible starting from p[p_idx].
            continue; // This head cannot reach p[p_idx], try next head.
        }

        // If p[p_idx] is within [left_reach, right_reach], this head can cover it.
        // Now, we need to determine the maximum range this head can cover,
        // considering it must cover p[p_idx].
        // The head can move to any position x such that |x - current_h| <= T.
        // If it moves to x, it covers [x-T, x+T].
        // To cover p[p_idx], x must be in [p[p_idx]-T, p[p_idx]+T].
        // Also, x must be in [current_h-T, current_h+T].
        // So, x must be in [max(current_h-T, p[p_idx]-T), min(current_h+T, p[p_idx]+T)].
        // To maximize the rightmost covered track, we should choose x as large as possible.
        // The largest possible x is min(current_h+T, p[p_idx]+T).
        // If we choose x = min(current_h+T, p[p_idx]+T), the range covered is [x-T, x+T].
        // The rightmost point covered is x+T = min(current_h+T, p[p_idx]+T) + T.
        // This is not quite right.
        // The head starts at current_h. It can move to any position `pos` such that `abs(pos - current_h) <= T`.
        // From `pos`, it can cover tracks in `[pos - T, pos + T]`.
        // We need to cover `p[p_idx]`. So, `p[p_idx]` must be in `[pos - T, pos + T]`.
        // This means `pos` must be in `[p[p_idx] - T, p[p_idx] + T]`.
        // Combining these, `pos` must be in `[max(current_h - T, p[p_idx] - T), min(current_h + T, p[p_idx] + T)]`.
        // To maximize the rightmost track covered, we should choose `pos` to be the largest possible value in this range.
        // Let `optimal_pos = min(current_h + T, p[p_idx] + T)`.
        // The rightmost track covered by this head would be `optimal_pos + T`.
        // However, this is only if `optimal_pos` is a valid position.
        // The actual rightmost track covered is `max_covered_right`.
        // If `p[p_idx]` is covered, the head can be moved to `p[p_idx]`. This takes `abs(p[p_idx] - current_h)` time.
        // Remaining time is `T - abs(p[p_idx] - current_h)`.
        // With this remaining time, the head can move further.
        // So, from `p[p_idx]`, it can reach `p[p_idx] + (T - abs(p[p_idx] - current_h))`.
        // This is `p[p_idx] + T - abs(p[p_idx] - current_h)`.
        // This is the rightmost point it can reach *after* covering p[p_idx].
        // This is the correct logic for the rightmost point covered by this head.
        long long max_covered_right = p[p_idx] + (T - std::abs(p[p_idx] - current_h));

        // Advance p_idx to the first track not covered by this head.
        while (p_idx < m && p[p_idx] <= max_covered_right) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10. A head can move 10^10 to cover a point, and then 10^10 more to cover another point. So 2*10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

