long long solve() {
    long long a, b;
    std::cin >> a >> b;

    if (a == b) {
        return 0;
    }

    long long diff = std::abs(a - b);
    long long count = 0;

    // Greedy approach: use largest denominations first
    // Number of 5s
    count += diff / 5;
    diff %= 5;

    // Now diff is 0, 1, 2, 3, or 4
    if (diff == 0) {
        // No remaining difference
    } else if (diff == 1) {
        // Can be 1 (+1 or -1)
        // Can be 2-1 (+2 then -1)
        // Can be 5-2-2 (if diff was 1, then 5-2-2 = 1)
        // Optimal for 1 is 1 press (+1 or -1)
        count += 1;
    } else if (diff == 2) {
        // Can be 2 (+2 or -2)
        // Optimal for 2 is 1 press (+2 or -2)
        count += 1;
    } else if (diff == 3) {
        // Can be 3 (+1, +2) or (+1, +1, +1)
        // Can be 5-2 (+5 then -2)
        // Optimal for 3 is 2 presses (e.g., +1, +2 or +5, -2)
        count += 2;
    } else if (diff == 4) {
        // Can be 4 (+2, +2) or (+1, +1, +2) or (+1, +1, +1, +1)
        // Can be 5-1 (+5 then -1)
        // Optimal for 4 is 2 presses (e.g., +2, +2 or +5, -1)
        count += 2;
    }

    return count;
}

