void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long haybales_in_pile1 = a[0];

    for (int i = 1; i < n; ++i) {
        // Distance from pile i+1 (0-indexed i) to pile 1 (0-indexed 0) is i.
        long long distance = i; 

        if (d == 0) {
            break; // No more days left
        }

        // Calculate how many haybales can be moved from pile i to pile 1
        // Each haybale costs 'distance' days.
        // We have 'a[i]' haybales in pile i.
        // We have 'd' days remaining.

        long long haybales_to_move = 0;
        if (distance <= d) { // Only if we have enough days for at least one haybale
            haybales_to_move = std::min(a[i], d / distance);
        }

        haybales_in_pile1 += haybales_to_move;
        d -= haybales_to_move * distance;
    }

    std::cout << haybales_in_pile1 << std::endl;
}

