#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as it's the minimum for the suffix starting at n-1
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        // If the current price a[i] is greater than the minimum price found so far in the suffix to its right
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is a new minimum for the suffix starting at i
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

