#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n. If not, it means n was not the maximum
    // in any row, which implies n was not present in any min(p_i, p_j)
    // for i != j. This can only happen if n is one of the p_i values,
    // and for that p_i, all other p_j are smaller than n.
    // In this case, max_val_in_row for that p_i would be max(p_j) for j != i.
    // If n is not present in p, then the maximum value in p is n-1.
    // The problem guarantees a solution exists.
    // If n is not found in the current p, it means one of the p[i] must be n.
    // The one that should be n is the one whose current value is max(p_j) for j != i.
    // This means that for this specific i, p[i] was actually n, and all other p[j] < n.
    // So min(p[i], p[j]) = p[j]. The max of these p[j] is max(p_j) for j != i.
    // This max(p_j) would be n-1.
    // So if n is not in p, we find the maximum value in p (which must be n-1)
    // and replace one occurrence of it with n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        int max_p_val = 0;
        for (int val : p) {
            if (val > max_p_val) {
                max_p_val = val;
            }
        }
        // max_p_val must be n-1.
        // Replace the first occurrence of max_p_val with n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_p_val) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

