        long long count = 0;
        long long current_k = 1;
        while (true) {
            long long cells_needed = current_k * (current_k + 1) / 2;
            long long total_cells_for_staircase = cells_needed + (current_k - 1) * current_k / 2; // This is 2*cells_needed - current_k

            if (total_cells_for_staircase <= x) {
                count++;
                x -= total_cells_for_staircase;
                current_k = current_k * 2 + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, (i + 1) - (last_R_pos + 1) + 1);
                last_R_pos = i + 1;
            }
        }
        // After the loop, consider the gap from the last 'R' to cell n+1
        // If no 'R' was found, last_R_pos is -1, so the gap is from cell 0 to cell n+1.
        // If 'R's were found, last_R_pos is the cell number of the last 'R'.
        // The distance from last_R_pos to n+1 is (n+1) - last_R_pos.
        // The number of cells in this gap is (n+1) - last_R_pos.
        // The required d for this gap is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, ((int)s.length() + 1) - (last_R_pos + 1) + 1);
        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining students: c - mid, m - mid, x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So we need (3 * mid) - mid - mid = mid more members.
            // These 'mid' members can come from remaining coders, mathematicians, or non-specialized students.
            // The total pool of available students for these 'mid' slots is (c - mid) + (m - mid) + x.
            // If this pool is at least 'mid', then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between the medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        // The optimal strategy is to assign the first n elements to one class
        // and the remaining n elements to the other class.
        // This means the first class gets a_0, ..., a_{n-1} and the second class gets a_n, ..., a_{2n-1}.
        // The sizes of these classes are n.
        // For this to be a valid partition, n must be odd.
        // If n is odd, then the median of the first class (a_0, ..., a_{n-1}) is a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) is a_{n + (n-1)/2} = a_{(3n-1)/2}.
        // The difference would be a_{(3n-1)/2} - a_{(n-1)/2}.
        //
        // However, the problem statement says "each class has odd number of students".
        // This implies that n must be odd.
        // If n is even, this specific partition (n students in each class) is not allowed.
        //
        // Let's re-read the problem carefully: "each class has odd number of students".
        // "The number of students in the classes may be equal or different, by your choice."
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // The key insight is that to minimize the difference between medians,
        // we should pick two elements from the sorted array that are as close as possible.
        //
        // Let the two medians be M1 and M2.
        // M1 must be the (k1+1)-th element of its class of size 2k1+1.
        // M2 must be the (k2+1)-th element of its class of size 2k2+1.
        //
        // It can be proven that the optimal strategy is to pick the median of the first n elements
        // and the median of the last n elements.
        // This means the two medians will be a[n-1] and a[n].
        //
        // More precisely, if we sort the array a_0, ..., a_{2n-1}.
        // The smallest possible median for any class is a_0 (if class size is 1).
        // The largest possible median for any class is a_{2n-1} (if class size is 1).
        //
        // Consider the elements a_{n-1} and a_n.
        // Can a_{n-1} be the median of one class and a_n be the median of the other?
        // Yes.
        // To make a_{n-1} the median of a class, we need to pick (n-1) elements smaller than or equal to a_{n-1}
        // and (n-1) elements greater than or equal to a_{n-1}.
        // We have a_0, ..., a_{n-2} (n-1 elements) which are <= a_{n-1}.
        // We need to pick n-1 elements from a_n, ..., a_{2n-1} that are >= a_{n-1}.
        // This is always possible.
        //
        // To make a_n the median of a class, we need to pick n elements smaller than or equal to a_n
        // and n elements greater than or equal to a_n.
        // We have a_0, ..., a_{n-1} (n elements) which are <= a_n.
        // We have a_{n+1}, ..., a_{2n-1} (n-1 elements) which are >= a_n.
        //
        // The crucial observation is that the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element (0-indexed $a_n$)
        // are the "middle" two elements of the entire sorted array.
        //
        // If we form two classes, say $C_1$ and $C_2$, with medians $M_1$ and $M_2$.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $S_1+S_2 = 2n$.
        //
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        // This means there are $k$ elements less than or equal to it, and $k$ elements greater than or equal to it.
        //
        // Consider the element $a_{n-1}$.
        // We can form a class $C_1$ with $a_{n-1}$ as its median.
        // To do this, we need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $a_0, \dots, a_{k_1-1}$ (if $k_1 \le n-1$) and $a_{n-1}$ itself.
        // And we need $k_1$ elements $\ge a_{n-1}$. We can pick these from $a_n, \dots, a_{2n-1}$.
        //
        // Consider the element $a_n$.
        // We can form a class $C_2$ with $a_n$ as its median.
        // To do this, we need $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We can pick $a_0, \dots, a_{n-1}$ (which are $\le a_n$) and $a_n$ itself.
        // And we need $k_2$ elements $\ge a_n$. We can pick these from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The minimum difference is always $a_n - a_{n-1}$.
        // This is because $a_{n-1}$ is the largest possible median for a class whose elements are all $\le a_{n-1}$
        // (or rather, whose median is $a_{n-1}$ and uses elements from the lower half of the sorted array).
        // And $a_n$ is the smallest possible median for a class whose elements are all $\ge a_n$
        // (or rather, whose median is $a_n$ and uses elements from the upper half of the sorted array).
        //
        // Let's prove that $a_n - a_{n-1}$ is achievable.
        // We need to partition $2n$ students into two classes $C_1, C_2$ of odd sizes $S_1, S_2$.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $2k_1+1 + 2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        //
        // We want to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        // For $C_1$ to have median $a_{n-1}$:
        // We need to select $k_1$ elements from $a_0, \dots, a_{n-2}$ (these are $\le a_{n-1}$).
        // We need to select $k_1$ elements from $a_n, \dots, a_{2n-1}$ (these are $\ge a_{n-1}$).
        // And $a_{n-1}$ itself.
        //
        // For $C_2$ to have median $a_n$:
        // We need to select $k_2$ elements from $a_0, \dots, a_{n-1}$ (these are $\le a_n$).
        // We need to select $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (these are $\ge a_n$).
        // And $a_n$ itself.
        //
        // Let's try to construct such a partition.
        // Let $C_1$ consist of $a_0, \dots, a_{k_1-1}$, $a_{n-1}$, and $a_{n}, \dots, a_{n+k_1-1}$.
        // This uses $k_1 + 1 + k_1 = 2k_1+1$ elements.
        // The median is $a_{n-1}$ if $a_{n-1}$ is indeed the $(k_1+1)$-th element.
        // This requires $a_{k_1-1} \le a_{n-1}$ and $a_{n+k_1-1} \ge a_{n-1}$.
        // This is true by sorting.
        //
        // The remaining elements are $a_{k_1}, \dots, a_{n-2}$ and $a_{n+k_1}, \dots, a_{2n-1}$.
        // And $a_n$ is also available.
        //
        // This construction is a bit complex. A simpler argument:
        // Any class of size $2k+1$ has $k$ elements below its median and $k$ elements above its median.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // Assume $M_1 \le M_2$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the $n$ smallest elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the $n$ largest elements.
        //
        // Consider the $n$ smallest elements $a_0, \dots, a_{n-1}$.
        // At least one of these must be in $C_2$ if $M_2$ is not $a_0$.
        //
        // The crucial point is that $a_{n-1}$ is the largest element in the first half of the sorted array,
        // and $a_n$ is the smallest element in the second half.
        //
        // It is always possible to form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        // Let $k_1 = 0$, so $S_1 = 1$. Class $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // Then $S_2 = 2n-1$. So $2k_2+1 = 2n-1 \implies k_2 = n-1$.
        // Class $C_2$ needs $n-1$ elements $\le$ its median and $n-1$ elements $\ge$ its median.
        // We can pick $a_0, \dots, a_{n-2}$ (these are $n-1$ elements $\le a_n$).
        // We can pick $a_{n+1}, \dots, a_{2n-1}$ (these are $n-1$ elements $\ge a_n$).
        // And $a_n$ itself.
        // All students are assigned: $a_{n-1}$ to $C_1$, and all others to $C_2$.
        // The medians are $a_{n-1}$ and $a_n$. The difference is $a_n - a_{n-1}$.
        // This construction is always valid because $S_1=1$ is odd and $S_2=2n-1$ is odd (since $n \ge 1 \implies 2n-1 \ge 1$).
        //
        // Since $a_n - a_{n-1}$ is achievable, and any median of a class must be one of the $a_i$'s,
        // and $a_{n-1}$ and $a_n$ are adjacent in the sorted array,
        // it's impossible to get a smaller positive difference.
        // If the difference is 0, it means $a_n = a_{n-1}$.
        //
        // So the minimum absolute difference is $a_n - a_{n-1}$.
        // (Using 0-indexed array, this is a[n] - a[n-1]).
        // In the problem statement, $a_1, \dots, a_{2n}$ are 1-indexed.
        // So if sorted, $a_1, \dots, a_{2n}$. The elements are $a_n$ and $a_{n+1}$.
        // The difference is $a_{n+1} - a_n$.
        //
        // In my code, `a` is 0-indexed, so `a[n]` and `a[n-1]`.
        // The difference is `a[n] - a[n-1]`.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top triangle (from apex to cut i) should be i * (total_area / n)
        // Total area = (1/2) * base * h = (1/2) * 1 * h = h/2
        // Area of top triangle = i * (h / (2n))
        // Let x_i be the height of the top triangle.
        // By similarity, base_i / 1 = x_i / h => base_i = x_i / h
        // Area of top triangle = (1/2) * base_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h)
        // So, x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * (h^2 / n)
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used in the alternating sequence to generate k distinct differences

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            // Even index (0-based) means we take from the left (smaller) end
            std::cout << left++;
        } else {
            // Odd index (0-based) means we take from the right (larger) end
            std::cout << right--;
        }
        std::cout << " ";
    }

    // The remaining elements are from k+2 to n.
    // We can append them in increasing order to generate only difference 1.
    // This ensures no new distinct differences are introduced.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            // Try to pick an opening bracket if we still need them
            // and if picking it won't exceed the maximum possible balance for a k-length sequence
            // (which is k/2, as we need k/2 opening brackets in total)
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // Try to pick a closing bracket if we still need them
            // and if the current balance allows it (balance > 0)
            // and if picking it won't make us exceed k/2 closing brackets
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        // Optimization: if we have already formed a sequence of length k, we can stop
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

