    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of pages Polycarp writes down

        // Precompute the sum of last digits for one full cycle (10 multiples of m)
        // (1*m)%10, (2*m)%10, ..., (10*m)%10
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_first_10_last_digits;

        // Calculate the sum for the remaining multiples
        // These are (num_full_cycles * 10 + 1)*m, ..., count*m
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

