void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int k = n - 1; // Start from the rightmost element

    // Phase 1: Find the longest non-decreasing suffix
    // a[k], a[k-1], ..., a[p] such that a[k] >= a[k-1] >= ... >= a[p]
    while (k > 0 && a[k-1] >= a[k]) {
        k--;
    }

    // Phase 2: Find the longest non-increasing suffix of the remaining part
    // a[k-1], a[k-2], ..., a[p'] such that a[k-1] <= a[k-2] <= ... <= a[p']
    // This means a[p'] >= a[p'+1] >= ... >= a[k-1]
    while (k > 0 && a[k-1] <= a[k]) {
        k--;
    }

    std::cout << k << std::endl;
}

