    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // If d is between 0 (exclusive) and 4 (exclusive), there are no real solutions.
        if (d < 4.0) { // Using 4.0 for double comparison
            std::cout << "N\n";
        } else {
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant is real and non-negative.
            // d + sqrt_discriminant is positive, so a1 is positive.
            // For b1 = d - a1 to be non-negative:
            // d - (d + sqrt_discriminant) / 2 >= 0
            // (2d - d - sqrt_discriminant) / 2 >= 0
            // (d - sqrt_discriminant) / 2 >= 0
            // d >= sqrt_discriminant
            // d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a1 and b1 are guaranteed to be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1. Max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1...m]) to max(pos[1...m]).
        // We maintain current_min_idx and current_max_idx as the minimum and maximum
        // indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the segment p[current_min_idx ... current_max_idx]
        // is a permutation of 1...m.
        // This requires two conditions:
        // 1. The length of the segment must be exactly 'm'.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum value in this segment must be 'm'.
        //    (This is implicitly handled by how we expand the segment.
        //     Since we are checking for m, and we've included all numbers up to m,
        //     the maximum value in the segment [current_min_idx ... current_max_idx]
        //     will be exactly m if the length condition holds.
        //     If the length condition holds, it means all numbers from 1 to m are
        //     packed contiguously in the original permutation, and no other numbers
        //     are present in that range.)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

