int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Step 2: Ensure elements to the left of median are <= s
    // These elements are a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s. Cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Ensure elements to the right of median are >= s
    // These elements are a[median_idx+1]...a[n-1]
    // If a[i] < s, we must increase it to s. Cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of a strictly increasing prefix starting from 0
    // i.e., a_0 >= 0, a_1 >= 1, ..., a_i >= i
    int max_prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_prefix_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of a strictly decreasing suffix ending at 0
    // i.e., a_{n-1} >= 0, a_{n-2} >= 1, ..., a_{n-1-j} >= j
    int max_suffix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[n - 1 - i] >= i) {
            max_suffix_len = i + 1;
        } else {
            break;
        }
    }

    // If the sum of lengths of the longest possible prefix and suffix
    // is greater than or equal to n, it means there's an overlap or they meet.
    // This implies there's at least one 'k' where a peak can be formed.
    // The condition max_prefix_len + max_suffix_len >= n + 1 ensures that
    // there is at least one index 'k' such that it is covered by both
    // the potential increasing prefix and the potential decreasing suffix.
    // Specifically, if max_prefix_len is the length of the prefix ending at index p_idx = max_prefix_len - 1,
    // and max_suffix_len is the length of the suffix starting at index s_idx = n - max_suffix_len,
    // we need p_idx >= s_idx for an overlap.
    // p_idx >= s_idx  =>  max_prefix_len - 1 >= n - max_suffix_len
    // => max_prefix_len + max_suffix_len - 1 >= n
    // => max_prefix_len + max_suffix_len >= n + 1
    if (max_prefix_len + max_suffix_len >= n + 1) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

