    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'new' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original array positions (the 'old' array elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // If a[j] is greater than a[i], we found a match. We increment count, and use both a[i] and a[j].
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element for the 'new' array
        } else {
            // No more elements in 'a' are greater than a[i] or subsequent elements.
            // We can break early as we won't find any more matches.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let X = current_xor_sum and S = current_sum.
    // We want S' = 2 * X'.
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, b1 and b2.
    // We want (S + b1 + b2) = 2 * (X ^ b1 ^ b2).

    // Let b1 = X.
    // Then X ^ b1 = X ^ X = 0.
    // The equation becomes (S + X + b2) = 2 * (0 ^ b2) = 2 * b2.
    // S + X + b2 = 2 * b2
    // S + X = b2.
    // So, if we append b1 = X and b2 = S + X, the condition holds.
    // The new sum will be S + X + (S + X) = 2S + 2X.
    // The new XOR sum will be X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    // And indeed, (2S + 2X) = 2 * (S + X).
    // This strategy always works and uses 2 elements.
    // The values S and X can be up to 10^5 * 10^9 = 10^14 for S, and 2^30 for X.
    // S+X can be up to 10^14, which fits in long long.

    // Output 2 elements: current_xor_sum and current_sum + current_xor_sum.
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

