// Function to check if a subarray is a permutation of 1 to length
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length <= 0) {
        return false; // Permutations must have non-zero length
    }
    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > length || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // Check if all numbers from 1 to length are present
    // This is implicitly checked by `seen[val]` and `val > length`
    // and `max_val` must be equal to `length` if all are present and unique.
    // However, the `seen` array check is more robust.
    // We just need to ensure max_val is indeed length.
    // If all numbers from 1 to length are present, then max_val must be length.
    // If max_val is less than length, then some number is missing.
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0) { // Value out of bounds for any permutation up to length n
            // This case should not happen based on constraints 1 <= a_i <= n-1,
            // but good for robustness.
            // If a[i] > n, it can't be part of a permutation of length <= n.
            // If a[i] <= 0, it can't be part of a permutation.
            // However, a[i] can be up to n-1, so it can be part of a permutation of length n-1.
            // The check `a[i] > n` is technically `a[i] > i+1` for prefix_is_perm[i]
            // and `a[i] > n-i` for suffix_is_perm[i].
            // Let's stick to the logic of `is_permutation` for now.
        }

        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        prefix_max[i] = current_max;

        if (distinct_count == i + 1 && current_max == i + 1) {
            prefix_is_perm[i] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n, false);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        int len = n - i; // Length of suffix starting at index i
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;

        if (distinct_count == len && current_max == len) {
            suffix_is_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        // Check if first l1 elements form a permutation of 1 to l1
        // This corresponds to prefix_is_perm[l1-1]
        // Check if last l2 elements form a permutation of 1 to l2
        // This corresponds to suffix_is_perm[l1]
        if (prefix_is_perm[l1 - 1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

