char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') {
        return 'P';
    } else if (opponent_move == 'S') {
        return 'R';
    } else { // opponent_move == 'P'
        return 'S';
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate through R, P, S in a fixed order to ensure deterministic output
        // if counts are equal. The problem statement says "any of them" is fine.
        // R, P, S order is arbitrary but consistent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (e.g., empty string, though n >= 1),
        // or if only one type of char exists, most_frequent_bot_move will be set.
        // If multiple types have the same max count, the one appearing last in the
        // if-chain (S, then P, then R) will be chosen. This is fine.
        // For example, if R=1, P=1, S=1, then S will be chosen.
        // If R=2, P=1, S=1, then R will be chosen.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

