    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can potentially form 'ab' with any 'a' to its left.
            // Each such 'a' will eventually "pass through" this 'b'.
            // When an 'a' passes a 'b', it effectively becomes 'bba'.
            // The 'a' moves past the 'b', and a new 'b' is created.
            // The number of 'a's that are currently "active" (i.e., count_a)
            // will double when they pass this 'b'.
            // So, count_a becomes 2 * count_a.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it will form 'ab' with all 'b's to its right
            // that it hasn't "passed" yet.
            // The number of 'b's it will pass is exactly count_a.
            // Each 'ab' replacement is one step.
            // So, this 'a' contributes count_a steps.
            total_steps = (total_steps + count_a) % mod;
            // After this 'a' has passed all 'b's to its right, it itself becomes
            // a 'b' (conceptually, as it's now to the right of the original 'b's).
            // So, it adds itself to the count of 'a's that are waiting to pass
            // 'b's further to the left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern will always have 18 characters, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's on the left to make it 18 characters long
    // Since we built it from right to left, we need to reverse and then pad.
    std::reverse(pattern.begin(), pattern.end());
    while (pattern.length() < 18) {
        pattern = '0' + pattern;
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's on the left to make it 18 characters long
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Use s[i] == '0' to set corresponding w[j] to '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // Build a candidate s_prime from w and x
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        } else {
            s_prime[i] = '0';
        }
    }

    // Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

