int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (k)
    // k can range from 0 to n.
    for (int k = 0; k <= n; ++k) {
        int m = n - k; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from the right
        // The sum of weights for items w[n-m]...w[n-1] is prefix_sum[n] - prefix_sum[n-m]
        current_energy += (prefix_sum[n] - prefix_sum[n - m]) * r;

        // Add extra penalties
        if (k > m) { // More items from left than right
            current_energy += (k - m - 1) * Ql;
        } else if (m > k) { // More items from right than left
            current_energy += (m - k - 1) * Qr;
        }
        // If k == m, no extra penalty

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

