#include <numeric> // For std::accumulate in C++17, or manual OR loop

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the matrix b.
    // Using long long for matrix elements to be safe, though problem states up to 10^9,
    // which fits in int. However, bitwise OR operations might exceed int if intermediate
    // values were larger, but here the maximum value is 10^9, so int is fine.
    // Let's stick to int as per problem constraints.
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    // Read the matrix b.
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Declare a vector to store the restored sequence a.
    std::vector<int> a(n);

    // For each element a_i in the sequence:
    // a_i must be the bitwise OR of all b_ij where j != i.
    // This is because if a bit is set in b_ij, it must be set in both a_i and a_j.
    // Therefore, a_i must have all bits set that are present in any b_ij (j != i).
    // The smallest such a_i is the bitwise OR of all b_ij (j != i).
    for (int i = 0; i < n; ++i) {
        int current_a_i = 0; // Initialize with 0, as ORing with 0 doesn't change value.
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue; // Skip diagonal elements (b_ii = -1)
            }
            current_a_i |= b[i][j]; // Perform bitwise OR
        }
        a[i] = current_a_i;
    }

    // Print the restored sequence a.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

