void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool possible_split = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < split_digit + '0') {
                // Must be color 1
                if (current_digit < last1) {
                    possible_split = false;
                    break;
                }
                result[i] = '1';
                last1 = current_digit;
            } else if (current_digit > split_digit + '0') {
                // Must be color 2
                if (current_digit < last2) {
                    possible_split = false;
                    break;
                }
                result[i] = '2';
                last2 = current_digit;
            } else { // current_digit == split_digit + '0'
                // Can be either color 1 or color 2
                // Prioritize color 2 if possible, to keep last1 small
                if (current_digit >= last2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_split = false;
                    break;
                }
            }
        }

        if (possible_split) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

