#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
        // So, if f1=0, the robot cannot reach any point to its left.
        // The target X must be >= current x.
        if (f1 == 0) { // Cannot move left
            min_x = std::max(min_x, x);
        }

        // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
        // So, if f3=0, the robot cannot reach any point to its right.
        // The target X must be <= current x.
        if (f3 == 0) { // Cannot move right
            max_x = std::min(max_x, x);
        }

        // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
        // So, if f4=0, the robot cannot reach any point below it.
        // The target Y must be >= current y.
        if (f4 == 0) { // Cannot move down
            min_y = std::max(min_y, y);
        }

        // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
        // So, if f2=0, the robot cannot reach any point above it.
        // The target Y must be <= current y.
        if (f2 == 0) { // Cannot move up
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid target point exists.
        // We can pick any point within the valid range.
        // The problem guarantees that if a solution exists, one with coordinates
        // not exceeding 10^5 by absolute value exists.
        // So, we can clamp min_x and min_y to stay within this range if they
        // are outside, but since we just need *any* valid point,
        // min_x and min_y themselves are valid choices if they are within the range.
        // The problem statement implies that the coordinates of the chosen point
        // should not exceed 10^5 by absolute value.
        // The initial bounds are -10^5 to 10^5.
        // The calculated min_x, max_x, min_y, max_y can be outside this range
        // if all robots are, for example, at x=200000 and can only move right.
        // However, the problem guarantees that if a solution exists, one with
        // coordinates within [-10^5, 10^5] exists.
        // So, we can just output min_x and min_y as the target.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This means we should pick a point within [-10^5, 10^5] if possible.
        // Since min_x and min_y are valid choices, and the problem guarantees
        // a solution within [-10^5, 10^5] if any solution exists,
        // we can just output min_x and min_y.
        // The initial coordinates are within [-10^5, 10^5].
        // If min_x becomes, say, 100001, it means all robots are at x >= 100001
        // and cannot move left. In this case, the target X must be >= 100001.
        // But the problem guarantees that if a solution exists, one with |X|,|Y| <= 10^5 exists.
        // This implies that min_x and min_y will naturally fall within [-10^5, 10^5]
        // if a solution exists.
        // So, simply printing min_x and min_y is correct.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: S_r = (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    sum_r_term = (sum_r_term * modInverse(2)) % MOD;

    // Sum of k from 1 to a: S_k = a * (a+1) / 2
    long long sum_k_term = a;
    sum_k_term = (sum_k_term * (a + 1)) % MOD;
    sum_k_term = (sum_k_term * modInverse(2)) % MOD;

    // Calculate the first part: (sum_{k=1 to a} k) * b * (sum_{r=1 to b-1} r)
    long long term1 = (sum_k_term * b) % MOD;
    term1 = (term1 * sum_r_term) % MOD;

    // Calculate the second part: a * (sum_{r=1 to b-1} r)
    long long term2 = (a * sum_r_term) % MOD;

    long long total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));

    // If n is a perfect square, k*k = n.
    // We want to partition n elements into k blocks of size k.
    // The last block might be smaller if n is not a perfect square.
    // The number of full blocks will be ceil(n/k).
    // Let's use k as the block size.
    // The number of blocks will be ceil(n/k).
    // The last block will have size n % k, or k if n % k == 0.

    // Example: n=4, k=2. Blocks: [3,4], [1,2]. Output: 3 4 1 2
    // Example: n=5, k=2. Blocks: [4,5], [2,3], [1]. Output: 4 5 2 3 1
    // Example: n=6, k=2. Blocks: [5,6], [3,4], [1,2]. Output: 5 6 3 4 1 2
    // Example: n=7, k=2. Blocks: [6,7], [4,5], [2,3], [1]. Output: 6 7 4 5 2 3 1
    // Example: n=8, k=2. Blocks: [7,8], [5,6], [3,4], [1,2]. Output: 7 8 5 6 3 4 1 2
    // Example: n=9, k=3. Blocks: [7,8,9], [4,5,6], [1,2,3]. Output: 7 8 9 4 5 6 1 2 3

    // The strategy is to print numbers in blocks of size k,
    // but in decreasing order of blocks, and increasing order within each block.
    // The numbers are 1 to n.
    // The largest numbers go into the first block, then next largest, etc.
    // Each block is printed in increasing order.

    // Current number to start a block from (largest available)
    int current_val = n;

    while (current_val > 0) {
        // Determine the size of the current block
        int block_size = std::min(k, current_val);

        // Start of the current block (smallest number in this block)
        int block_start = current_val - block_size + 1;

        // Print elements of this block in increasing order
        for (int i = 0; i < block_size; ++i) {
            std::cout << block_start + i << (current_val - block_size + i == n - 1 ? "" : " ");
        }

        // Move to the next block (smaller numbers)
        current_val -= block_size;
    }
    std::cout << "\n";

    return 0;
}

