void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;
    char current_char = '\0';

    // Find a starting character for the layout chain
    // It must be a character with only one required neighbor (an endpoint of a chain)
    // Or, if all characters have two neighbors (a cycle), pick any character.
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            current_char = c;
            break;
        }
    }

    // If no character has size 1, it means all characters involved in the password
    // have size 2. This implies a cycle.
    // Or, if the password is empty or single char, no adjacencies.
    if (current_char == '\0' && !s.empty()) {
        // If s is not empty, it means there are characters involved.
        // If all involved characters have degree 2, it's a cycle.
        // Pick the first character from the password as a starting point.
        // This handles cases like "abacaba" where 'a' has degree 2, 'b' has degree 1, 'c' has degree 1.
        // The logic above should find 'b' or 'c'.
        // If s="abcde", then 'a' has 1, 'e' has 1.
        // If s="abacaba", 'a' has {'b', 'c'}, 'b' has {'a'}, 'c' has {'a'}.
        // 'b' and 'c' have degree 1.
        // The only way current_char is still '\0' is if all characters in adj have degree 0 or 2.
        // If all characters in adj have degree 0, s must be empty or single char.
        // If all characters in adj have degree 2, it's a cycle.
        // Example: s = "abcda" -> 'a' {'b','d'}, 'b' {'a','c'}, 'c' {'b','d'}, 'd' {'a','c'}
        // This is a cycle.
        // The problem statement guarantees no adjacent equal characters, but doesn't forbid cycles.
        // If it's a cycle, we can start with any character that has degree 2.
        // Let's pick the first character of the password if current_char is still '\0'.
        // This will be the case if all characters in the password have degree 2.
        // Example: s = "abcda" -> 'a' has degree 2, 'b' has degree 2, 'c' has degree 2, 'd' has degree 2.
        // In this case, current_char will be '\0'.
        // We need to check if this forms a valid chain.
        // If it's a cycle, it's impossible to lay out on a single row without breaking an adjacency.
        // A single row implies a path graph, not a cycle graph.
        // So, if all characters involved in the password have degree 2, it's impossible.
        // The only exception is if the password is empty or single character, in which case adjacencies are empty.
        // But s.length() >= 1.
        // So if current_char is still '\0' and s is not empty, it means all characters in s have degree 2.
        // This implies a cycle, which is impossible.
        // Example: s = "abcda" -> 'a' needs 'b', 'd'. 'b' needs 'a', 'c'. 'c' needs 'b', 'd'. 'd' needs 'a', 'c'.
        // This forms a cycle a-b-c-d-a. This cannot be laid out on a line.
        // So, if current_char is still '\0' and s is not empty, it's impossible.
        // The only case where current_char is '\0' and it's possible is if s is empty or single char.
        // But s.length() >= 1. So if current_char is '\0', it's impossible.
        std::cout << "NO\n";
        return;
    }

    // If s is empty or single character, current_char will be '\0'.
    // In this case, any layout is fine.
    // The loop below will not run, and we will append all unvisited chars.
    // This is fine.

    if (current_char != '\0') { // If we found a starting point for a chain
        while (current_char != '\0') {
            layout += current_char;
            visited.insert(current_char);
            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Append all unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    // Check if the constructed layout satisfies all adjacencies
    // This is implicitly handled by the construction if possible.
    // The only remaining check is if the length is 26.
    if (layout.length() != 26) {
        // This should not happen if the logic is correct, as we append all unvisited.
        // It might happen if the initial chain construction failed to cover all required chars.
        // For example, if there are multiple disjoint chains required by the password.
        // Example: s = "ab" and "cd". This would require two separate chains.
        // The problem implies all required adjacencies must be part of *one* layout.
        // If there are multiple disjoint chains, we can't connect them without breaking the "at most 2 neighbors" rule.
        // Example: "ab" and "cd". 'a'-'b' and 'c'-'d'.
        // If we start with 'a', we get "ab". Then 'c' is unvisited.
        // If we append 'c', then 'd', we get "abcd".
        // This is fine. The problem is if the password implies multiple *connected components*
        // where each component is a path.
        // The current logic builds one path. If there are other paths, they will be appended as free characters.
        // This is correct.
        // The only way layout.length() != 26 is if there's a bug or an unhandled impossible case.
        // The only impossible case is a cycle.
        // The current_char == '\0' check handles the cycle case.
        // So, if we reach here, it should be possible.
        std::cout << "NO\n"; // Should not be reached
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

