#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for each bit position (0-9)
    // For each bit j:
    // current_val0[j] = what 0 becomes after operations
    // current_val1[j] = what 1 becomes after operations
    // Initially, 0 remains 0, 1 remains 1
    std::vector<int> current_val0(10);
    std::vector<int> current_val1(10);
    for (int i = 0; i < 10; ++i) {
        current_val0[i] = 0;
        current_val1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int bit_x = (x >> j) & 1;
            if (op_char == '&') {
                current_val0[j] &= bit_x;
                current_val1[j] &= bit_x;
            } else if (op_char == '|') {
                current_val0[j] |= bit_x;
                current_val1[j] |= bit_x;
            } else { // op_char == '^'
                current_val0[j] ^= bit_x;
                current_val1[j] ^= bit_x;
            }
        }
    }

    // Now, for each bit j, we know how 0 and 1 transform:
    // (0 -> current_val0[j]) and (1 -> current_val1[j])
    // We need to find a minimal set of operations (&, |, ^) that achieve this.
    // There are 4 possible transformations for (0, 1):
    // 1. (0, 0): always 0, regardless of input bit. Achieved by & 0.
    // 2. (0, 1): identity, input bit remains unchanged. Achieved by & 1, | 0, ^ 0.
    // 3. (1, 0): negation, input bit is flipped. Achieved by ^ 1.
    // 4. (1, 1): always 1, regardless of input bit. Achieved by | 1.

    // We can combine these into at most 3 operations:
    // One & operation: to force bits to 0.
    // One | operation: to force bits to 1.
    // One ^ operation: to flip bits.

    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        if (current_val0[j] == 0 && current_val1[j] == 0) {
            // (0,0) transformation: bit must become 0.
            // This can be achieved by ANDing with 0 at this bit position.
            final_and_mask &= ~(1 << j); // Set j-th bit of final_and_mask to 0
        } else if (current_val0[j] == 1 && current_val1[j] == 1) {
            // (1,1) transformation: bit must become 1.
            // This can be achieved by ORing with 1 at this bit position.
            final_or_mask |= (1 << j); // Set j-th bit of final_or_mask to 1
        } else if (current_val0[j] == 1 && current_val1[j] == 0) {
            // (1,0) transformation: bit must be flipped.
            // This can be achieved by XORing with 1 at this bit position.
            final_xor_mask |= (1 << j); // Set j-th bit of final_xor_mask to 1
        }
        // If (0,1) transformation: bit remains unchanged.
        // This is the default behavior if no &0, |1, or ^1 is applied to this bit.
        // So, for (0,1), we leave final_and_mask bit as 1, final_or_mask bit as 0, final_xor_mask bit as 0.
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }
    if (final_and_mask != 1023) { // If any bit was forced to 0
        result_ops.push_back({'&', final_and_mask});
    }

    // The order of operations matters.
    // A common canonical form is OR, then XOR, then AND.
    // Let's verify this order.
    // Suppose input is X.
    // X' = X | final_or_mask
    // X'' = X' ^ final_xor_mask
    // X''' = X'' & final_and_mask
    //
    // Consider a bit j:
    // If (0,0): final_or_mask_j=0, final_xor_mask_j=0, final_and_mask_j=0.
    //   X_j' = X_j | 0 = X_j
    //   X_j'' = X_j ^ 0 = X_j
    //   X_j''' = X_j & 0 = 0. Correct.
    // If (1,1): final_or_mask_j=1, final_xor_mask_j=0, final_and_mask_j=1.
    //   X_j' = X_j | 1 = 1
    //   X_j'' = 1 ^ 0 = 1
    //   X_j''' = 1 & 1 = 1. Correct.
    // If (1,0): final_or_mask_j=0, final_xor_mask_j=1, final_and_mask_j=1.
    //   X_j' = X_j | 0 = X_j
    //   X_j'' = X_j ^ 1 = ~X_j
    //   X_j''' = (~X_j) & 1 = ~X_j. Correct.
    // If (0,1): final_or_mask_j=0, final_xor_mask_j=0, final_and_mask_j=1.
    //   X_j' = X_j | 0 = X_j
    //   X_j'' = X_j ^ 0 = X_j
    //   X_j''' = X_j & 1 = X_j. Correct.
    //
    // This order (OR, then XOR, then AND) works.
    // We need to output them in this specific order if they exist.

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        if (op.first == '|') {
            std::cout << op.first << " " << op.second << "\n";
        }
    }
    for (const auto& op : result_ops) {
        if (op.first == '^') {
            std::cout << op.first << " " << op.second << "\n";
        }
    }
    for (const auto& op : result_ops) {
        if (op.first == '&') {
            std::cout << op.first << " " << op.second << "\n";
        }
    }

    return 0;
}

