int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    // L[i] = 0 if a[i] = 1
    // L[i] = L[i-1] + 1 if a[i] = 0 and i > 0
    // L[0] = 1 if a[0] = 0, else 0
    if (a[0] == 0) {
        L[0] = 1;
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i
    // R[i] = 0 if a[i] = 1
    // R[i] = R[i+1] + 1 if a[i] = 0 and i < n-1
    // R[n-1] = 1 if a[n-1] = 0, else 0
    if (a[n - 1] == 0) {
        R[n - 1] = 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int current_k = std::min(L[i], R[i]);
            max_k = std::max(max_k, (current_k + 1) / 2);
        }
    }

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (L[i] <= max_k * 2 || R[i] <= max_k * 2) {
                b[i] = 1;
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

