// Using long long for y and intermediate sums to prevent overflow
// a_i can be up to 10^9, n up to 2*10^5.
// y can accumulate sums of a_i. In the worst case, if x jumps by 1 each time,
// y could be n * 10^9, which fits in long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] will be set for each query
                                     // a[2]...a[n] are read from input
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_y[i] stores the total y accumulated when starting at x=i and performing
    // the "decrease x" step (x = i - a[i]), assuming it terminates.
    // dp_next_x[i] stores the next x value after performing the "decrease x" step
    // (x = i - a[i]), assuming it terminates.
    // These are for the second part of the cycle (x_curr - a[x_curr]).
    // We need to compute these for x from n down to 1.
    // dp_y[i] = a[i] + dp_y[i - a[i]] if i - a[i] is valid and terminates
    // dp_next_x[i] = dp_next_x[i - a[i]] if i - a[i] is valid and terminates
    // If i - a[i] is <= 0, then dp_y[i] = a[i], dp_next_x[i] = i - a[i]
    // If i - a[i] is > n, then dp_y[i] = a[i], dp_next_x[i] = i - a[i]
    // If it loops, then -1.

    std::vector<long long> dp_y(n + 1);
    std::vector<int> dp_next_x(n + 1); // Stores the x value after the "decrease" step
                                       // or 0 if it terminates (x <= 0 or x > n)
                                       // or -1 if it loops.

    // Initialize dp_y and dp_next_x for base cases (terminating states)
    for (int i = 1; i <= n; ++i) {
        long long next_x_val = i - a[i];
        if (next_x_val <= 0 || next_x_val > n) {
            dp_y[i] = a[i];
            dp_next_x[i] = 0; // Sentinel for termination
        } else {
            // Will be computed later
            dp_y[i] = -1; // Mark as uncomputed or potentially looping
            dp_next_x[i] = -1;
        }
    }

    // Use a stack for DFS-like computation to detect cycles and compute values
    std::vector<int> path_stack;
    std::vector<bool> on_stack(n + 1, false); // To detect cycles

    for (int i = 1; i <= n; ++i) {
        if (dp_next_x[i] != -1) { // Already computed or base case
            continue;
        }

        path_stack.clear();
        int current_x = i;

        while (current_x >= 1 && current_x <= n && dp_next_x[current_x] == -1 && !on_stack[current_x]) {
            path_stack.push_back(current_x);
            on_stack[current_x] = true;
            current_x = current_x - a[current_x]; // Follow the "decrease x" step
        }

        // Now current_x is either out of bounds, points to an already computed state, or is part of a cycle
        if (current_x <= 0 || current_x > n) { // Terminates
            long long current_y_sum = 0;
            while (!path_stack.empty()) {
                int node = path_stack.back();
                path_stack.pop_back();
                on_stack[node] = false;
                current_y_sum += a[node];
                dp_y[node] = current_y_sum;
                dp_next_x[node] = 0; // Terminates
            }
        } else if (on_stack[current_x]) { // Cycle detected
            while (!path_stack.empty()) {
                int node = path_stack.back();
                path_stack.pop_back();
                on_stack[node] = false;
                dp_y[node] = -1; // Mark as non-terminating
                dp_next_x[node] = -1;
                if (node == current_x) break; // All nodes in the cycle are marked
            }
        } else { // current_x points to an already computed state
            long long current_y_sum = dp_y[current_x];
            int final_next_x = dp_next_x[current_x];
            while (!path_stack.empty()) {
                int node = path_stack.back();
                path_stack.pop_back();
                on_stack[node] = false;
                if (current_y_sum == -1) { // If the target state was non-terminating
                    dp_y[node] = -1;
                    dp_next_x[node] = -1;
                } else {
                    current_y_sum += a[node];
                    dp_y[node] = current_y_sum;
                    dp_next_x[node] = final_next_x;
                }
            }
        }
    }

    // Now, for each i from 1 to n-1, simulate the full program
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current query

        long long x_step1 = 1 + a[1];
        long long y_total = a[1];

        if (x_step1 <= 0 || x_step1 > n) {
            std::cout << y_total << "\n";
        } else {
            // After first step (x = 1 + a[1], y = a[1]), we are at x_step1.
            // From here, we need to apply the "decrease x" step (x = x_step1 - a[x_step1])
            // and then potentially continue.
            // This is exactly what our DP table `dp_y` and `dp_next_x` store.
            if (dp_y[x_step1] == -1) { // If the sequence starting from x_step1 - a[x_step1] loops
                std::cout << -1 << "\n";
            } else {
                y_total += dp_y[x_step1];
                std::cout << y_total << "\n";
            }
        }
    }

    return 0;
}

