// Function to count '1's in a string
int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If ones_a is odd, we can append a '1' to make it even.
    // This effectively gives us an even number of ones.
    // So, the maximum number of ones we can achieve in string 'a'
    // (before any removals) is ones_a if ones_a is even,
    // or ones_a + 1 if ones_a is odd.
    // This can be simplified to (ones_a + (ones_a % 2 != 0)).
    int max_ones_a_after_parity_op = ones_a + (ones_a % 2 != 0);

    // To transform 'a' into 'b', we must be able to:
    // 1. Have at least as many '1's in 'a' (potentially after one parity op) as in 'b'.
    // 2. Have 'a' be at least as long as 'b'.
    //    The length of 'a' can be increased by 1 (parity op) or decreased by 1 (remove first char).
    //    We can always remove characters from the front of 'a' until its length matches 'b'
    //    or until it's shorter than 'b'.
    //    If we need to make 'a' longer, we can use the parity op.
    //    The maximum length 'a' can effectively reach is |a| + 1 (by one parity op).
    //    So, if |a| < |b|, we must use the parity op at least once.
    //    If |a| + 1 < |b|, it's impossible to reach length |b|.

    // Condition 1: Number of ones
    // The number of ones in 'a' (potentially after one parity op) must be >= number of ones in 'b'.
    // If ones_a is odd, we can always make it even by appending '1'.
    // If ones_a is even, it stays even.
    // So, the effective number of ones we can work with from 'a' is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This is exactly `max_ones_a_after_parity_op`.
    if (max_ones_a_after_parity_op >= ones_b) {
        // Condition 2: Length
        // We need to be able to make 'a' at least as long as 'b'.
        // If |a| is already >= |b|, we can just remove characters from 'a' until it's |b|.
        // If |a| < |b|, we must use the parity operation to increase its length.
        // This means the maximum length 'a' can effectively reach is |a| + 1.
        // If |a| + 1 < |b|, it's impossible to reach the required length.
        if (a.length() >= b.length() || a.length() + 1 >= b.length()) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;
    std::vector<int> current_line_indices(n);
    std::iota(current_line_indices.begin(), current_line_indices.end(), 0); // Stores original indices

    int head = 0; // Index in current_line_indices

    while (head < current_line_indices.size()) {
        int current_child_original_idx = current_line_indices[head];
        cured_children_indices.push_back(children[current_child_original_idx].original_idx);
        children[current_child_original_idx].in_line = false; // Mark as left the line (to doctor)

        long long office_cry_volume = children[current_child_original_idx].v;
        long long hall_cry_sum = 0; // Accumulates d_j from children leaving due to chain reaction

        // Apply office cry and initial hall cry
        for (int i = head + 1; i < current_line_indices.size(); ++i) {
            int child_idx_in_line = current_line_indices[i];
            if (!children[child_idx_in_line].in_line) continue; // Should not happen if current_line_indices is clean

            // Apply office cry effect
            if (office_cry_volume > 0) {
                children[child_idx_in_line].p -= office_cry_volume;
                office_cry_volume = std::max(0LL, office_cry_volume - 1);
            }

            // Apply accumulated hall cry effect
            children[child_idx_in_line].p -= hall_cry_sum;

            // Check if this child now cries and leaves
            if (children[child_idx_in_line].p < 0 && children[child_idx_in_line].in_line) {
                children[child_idx_in_line].in_line = false;
                hall_cry_sum += children[child_idx_in_line].d;
            }
        }

        // Rebuild current_line_indices to remove children who left
        std::vector<int> next_line_indices;
        for (int i = head + 1; i < current_line_indices.size(); ++i) {
            int child_idx_in_line = current_line_indices[i];
            if (children[child_idx_in_line].in_line) {
                next_line_indices.push_back(child_idx_in_line);
            }
        }
        current_line_indices = next_line_indices;
        head = 0; // Reset head for the new line
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

