// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1
    // Try all possible single cuts
    // A cut at index i splits s into s[0...i-1] and s[i...N-1]
    // We can form s' = s[i...N-1] + s[0...i-1]
    // We need s' to be a palindrome and s' != s
    for (int i = 1; i < n; ++i) { // i is the length of the first part
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2
    // If k=1 didn't work, we check k=2.
    // This means we make two cuts, resulting in 3 pieces.
    // The problem statement implies that if a solution exists, k=1 or k=2 is sufficient
    // unless all characters are the same.
    //
    // If s consists of all identical characters (e.g., "aaaa"), then any reordering
    // of its substrings will result in the same string "aaaa".
    // In this case, it's impossible to get a different string.
    //
    // If s does not consist of all identical characters, and k=1 didn't work,
    // then k=2 must be the answer.
    //
    // Why k=2 is always possible if not all characters are the same?
    // Consider s = "abacaba".
    // If all characters are the same, e.g., "aaaaa", then any permutation of substrings
    // will result in "aaaaa". So it's impossible.
    //
    // If not all characters are the same, then there must be at least two distinct characters.
    // Since s is a palindrome, if s[0] != s[1], then s[N-1] != s[N-2].
    //
    // Consider the string s. If not all characters are the same, then there exists
    // at least one character s[j] such that s[j] != s[0].
    //
    // If N is odd, say N=2m+1. The middle character is s[m].
    // If all characters s[0...m-1] are the same, say 'a', and s[m] is 'b' (a!=b),
    // then s looks like "aa...ab...aa".
    // Example: "aaabaaa".
    // Cut "aaabaaa" into "aa" | "aba" | "aa". Reorder to "aa" | "aba" | "aa" -> "aaabaaa" (same).
    //
    // Let's check if all characters in the first half (excluding middle for odd N) are the same.
    // If s = "abacaba", N=7. s[0...2] = "aba". Not all same.
    // If s = "aaaaa", N=5. All same.
    // If s = "aaabaaa", N=7. s[0...2] = "aaa". All same.
    //
    // If all characters in s are the same, e.g., "aaaa", then it's impossible.
    // We can check this by comparing s[0] with s[1]. If s[0] == s[1] == ... == s[N-1],
    // then it's impossible.
    //
    // If not all characters are the same, then there must be at least two distinct characters.
    // Since s is a palindrome, if s[0] != s[1], then s[N-1] != s[N-2].
    //
    // Consider the first half of the string s, i.e., s[0 ... N/2 - 1].
    // If all characters in this first half are identical (e.g., "aaa" for "aaabaaa"),
    // then s must be of the form 'a' * (N/2) + (middle char if N odd) + 'a' * (N/2).
    // Example: "aaabaaa".
    // In this case, if we cut it into 'a' | 'aabaa' | 'a', we can't reorder to get a new palindrome.
    //
    // However, if there are at least two distinct characters in the first half,
    // e.g., s = "abacaba", first half "aba". 'a' and 'b' are distinct.
    // Then we can always find a k=2 solution.
    //
    // The condition for "Impossible" is that all characters in the string are the same.
    // Example: "qqqq".
    // If s = "aaaaa", then any cut and reorder will result in "aaaaa".
    //
    // Let's check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If k=1 didn't work, and not all characters are the same, then k=2 is always possible.
        // Example: "nolon" -> k=2.
        // "nolon" is not all same.
        // k=1 check:
        // "n" + "olon" -> "olonn" (not pal)
        // "no" + "lon" -> "lonno" (not pal)
        // "nol" + "on" -> "onnol" (not pal)
        // "nolo" + "n" -> "nnolo" (not pal)
        // So k=1 fails.
        // Since not all characters are same, output 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long good_pairs = 0;

    // min_r[l] stores the minimum r such that s[l...r] contains a bad triplet.
    // If no such r exists, it's n+1.
    // We are interested in the smallest r_min such that s[l...r_min] contains a bad triplet.
    // For any r >= r_min, s[l...r] will also contain a bad triplet.
    // So, for a fixed l, the number of pairs (l, r) that contain a bad triplet is n - r_min + 1.
    // The number of pairs (l, r) that do NOT contain a bad triplet is r_min - l.
    // We want to sum (r_min - l) for all l.

    // Let's define min_r_with_triplet[l] as the smallest r (1-indexed) such that
    // the substring s[l...r] contains at least one bad triplet.
    // If no such r exists for a given l, we can set it to n + 1.
    // The indices in the problem are 1-based. Let's convert s to 0-indexed internally.
    // So, s_idx = s[idx-1].
    // A triplet is (x, x+k, x+2k) where 1 <= x < x+2k <= n.
    // In 0-indexed: (x-1, x+k-1, x+2k-1) where 0 <= x-1 < x+2k-1 <= n-1.
    // Let x_0 = x-1, k_0 = k. Then (x_0, x_0+k_0, x_0+2k_0).
    // Condition: 0 <= x_0 < x_0+2k_0 <= n-1.
    // The substring s[l...r] (1-indexed) corresponds to s[l-1...r-1] (0-indexed).
    // A triplet (x_0, x_0+k_0, x_0+2k_0) is in s[l-1...r-1] if l-1 <= x_0 and x_0+2k_0 <= r-1.
    // So, r-1 >= x_0+2k_0, which means r >= x_0+2k_0+1.
    // The smallest r for a given l that contains a triplet starting at x_0 is x_0+2k_0+1.
    // We need to find the minimum of these over all possible triplets.

    // Let's find the smallest ending index (0-indexed) for any bad triplet.
    // This is x_0 + 2k_0.
    // Let min_end_idx[x_0] be the minimum x_0 + 2k_0 for any triplet starting at x_0.
    // Initialize min_end_idx with n (or n+1 if 1-indexed).
    std::vector<int> min_end_idx_for_start(n, n); // min_end_idx_for_start[x_0] = min(x_0+2k_0) for valid k_0

    for (int x_0 = 0; x_0 < n; ++x_0) {
        for (int k_0 = 1; x_0 + 2 * k_0 < n; ++k_0) {
            if (s[x_0] == s[x_0 + k_0] && s[x_0 + k_0] == s[x_0 + 2 * k_0]) {
                min_end_idx_for_start[x_0] = std::min(min_end_idx_for_start[x_0], x_0 + 2 * k_0);
            }
        }
    }

    // Now, min_end_idx_for_start[x_0] gives the smallest 0-indexed end of a bad triplet
    // that starts at x_0. If no such triplet exists, it's n.

    // We need to find min_r_with_triplet[l_0] (0-indexed l_0).
    // min_r_with_triplet[l_0] = min(x_0 + 2k_0) for all x_0 >= l_0 that start a bad triplet.
    // This can be computed by iterating l_0 from n-1 down to 0.
    // min_r_with_triplet[l_0] = min(min_end_idx_for_start[l_0], min_r_with_triplet[l_0+1])
    // Base case: min_r_with_triplet[n-1] = min_end_idx_for_start[n-1] (which is n, as no triplet can start at n-1)
    // Initialize min_r_with_triplet with n.
    std::vector<int> min_r_with_triplet(n + 1, n); // min_r_with_triplet[l_0] is the smallest 0-indexed r_0
                                                  // such that s[l_0...r_0] contains a bad triplet.
                                                  // If no such r_0 exists, it's n.

    for (int l_0 = n - 1; l_0 >= 0; --l_0) {
        min_r_with_triplet[l_0] = min_end_idx_for_start[l_0];
        if (l_0 + 1 < n) {
            min_r_with_triplet[l_0] = std::min(min_r_with_triplet[l_0], min_r_with_triplet[l_0 + 1]);
        }
    }

    // Now, for each l_0 (0-indexed start of substring), min_r_with_triplet[l_0] is the smallest
    // 0-indexed end of a substring that contains a bad triplet.
    // If min_r_with_triplet[l_0] is n, it means no bad triplet exists for any substring starting at l_0.
    // The number of good pairs (l_0, r_0) for a fixed l_0 is (min_r_with_triplet[l_0] - l_0).
    // This is because r_0 can range from l_0 to min_r_with_triplet[l_0] - 1.
    // The length of this range is (min_r_with_triplet[l_0] - 1) - l_0 + 1 = min_r_with_triplet[l_0] - l_0.

    for (int l_0 = 0; l_0 < n; ++l_0) {
        good_pairs += (min_r_with_triplet[l_0] - l_0);
    }

    std::cout << total_pairs - good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The smallest possible value for b_1 is 0.
                          // For subsequent b_i, prev_b is the value of b_{i-1}.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // We need to find b_i such that prev_b <= b_i and b_i can be formed from a_i
        // using at most x operations.
        // This means b_i = (a_i + k) % m for some 0 <= k <= x.

        // Case 1: a_i >= prev_b
        // If a_i is already greater than or equal to prev_b, we can potentially
        // set b_i = a_i. This requires 0 operations for a_i.
        // If a_i < prev_b, we cannot set b_i = a_i.

        // If a_i >= prev_b:
        // We can choose b_i = a_i. This is valid if a_i is reachable from a_i with 0 ops.
        // We can also choose b_i = (a_i + k) % m for 0 < k <= x.
        // The smallest possible b_i is prev_b.
        // If a_i >= prev_b, we can set b_i = a_i. This is the best choice for b_i
        // because it keeps b_i as small as possible, allowing more flexibility for b_{i+1}.
        // The number of operations needed for a_i to become a_i is 0.
        // This is valid if 0 <= x.

        // If a_i < prev_b:
        // We must increment a_i to reach at least prev_b.
        // The value (a_i + k) % m must be >= prev_b.
        // The smallest such value is prev_b itself.
        // To reach prev_b from a_i, we need to add (prev_b - a_i + m) % m.
        // Let k_needed = (prev_b - a_i + m) % m.
        // If k_needed <= x, then we can set b_i = prev_b.
        // If k_needed > x, then we cannot reach prev_b from a_i using at most x operations
        // while keeping b_i >= prev_b.
        // In this case, we must increment a_i by some k <= x.
        // The values we can reach are (a_i + 0)%m, (a_i + 1)%m, ..., (a_i + x)%m.
        // If a_i < prev_b, and we want b_i >= prev_b, then we must have
        // (a_i + k) % m >= prev_b.
        // This means we must "cross" the m-0 boundary.
        // For example, if m=7, a_i=6, prev_b=1.
        // We need to increment 6 to become 1. This is (1-6+7)%7 = 2 operations.
        // If x=1, we can't do it. If x=2, we can.
        // If a_i=0, prev_b=6. We need (6-0+7)%7 = 6 operations.
        // If x=5, we can't do it. If x=6, we can.

        // Let's analyze the conditions for b_i:
        // 1. b_i >= prev_b
        // 2. b_i = (a_i + k) % m for some 0 <= k <= x

        // If a_i >= prev_b:
        // We can choose b_i = a_i. This requires 0 operations.
        // This is valid if 0 <= x.
        // We can also choose b_i = (a_i + k) % m for k > 0.
        // The values reachable from a_i are [a_i, (a_i+x)%m] if (a_i+x)%m >= a_i,
        // or [a_i, m-1] U [0, (a_i+x)%m] if (a_i+x)%m < a_i.
        // If a_i >= prev_b, we can always pick b_i = a_i. This is the smallest possible
        // value for b_i that satisfies b_i >= prev_b and requires 0 operations.
        // So, if a_i >= prev_b, we set prev_b = a_i.

        // If a_i < prev_b:
        // We must increment a_i.
        // The values we can reach are (a_i + k) % m for 0 <= k <= x.
        // We need to find if there exists a k in [0, x] such that (a_i + k) % m >= prev_b.
        // The smallest value we can reach that is >= prev_b is prev_b itself.
        // To reach prev_b from a_i, we need to add (prev_b - a_i + m) % m operations.
        // Let k_to_reach_prev_b = (prev_b - a_i + m) % m.
        // If k_to_reach_prev_b <= x, then we can set b_i = prev_b.
        // If k_to_reach_prev_b > x, it means we cannot reach prev_b by incrementing a_i
        // by at most x operations.
        // In this scenario, we must increment a_i by some k <= x.
        // The values (a_i + k) % m will be in the range [a_i, (a_i + x) % m]
        // (potentially wrapping around m).
        // Since a_i < prev_b, and we cannot reach prev_b, it means all reachable values
        // (a_i + k) % m for k <= x are either < prev_b or they wrap around and are
        // still < prev_b.
        // More precisely, if k_to_reach_prev_b > x, it means that all values
        // (a_i + k) % m for 0 <= k <= x will be less than prev_b.
        // For example, if m=10, a_i=1, prev_b=5, x=2.
        // k_to_reach_prev_b = (5-1+10)%10 = 4. Since 4 > x=2, we can't reach 5.
        // Reachable values: (1+0)%10=1, (1+1)%10=2, (1+2)%10=3. All are < 5.
        // So, if k_to_reach_prev_b > x, it's impossible to satisfy b_i >= prev_b.
        // Therefore, we return false.

        // Combining these:
        // If a_i >= prev_b:
        //   We can choose b_i = a_i. This requires 0 operations.
        //   This is valid if 0 <= x.
        //   We can also choose b_i = (a_i + k) % m for k > 0.
        //   The values we can reach are [a_i, (a_i+x)%m] (if no wrap) or [a_i, m-1] U [0, (a_i+x)%m] (if wrap).
        //   If (a_i + x) % m < prev_b and (a_i + x) % m < a_i (meaning we wrapped around and ended up below prev_b),
        //   then we cannot satisfy b_i >= prev_b.
        //   Example: m=10, a_i=8, prev_b=7, x=3.
        //   a_i >= prev_b.
        //   (a_i+x)%m = (8+3)%10 = 1.
        //   Here, (a_i+x)%m = 1 < prev_b = 7.
        //   This means we can reach 8, 9, 0, 1.
        //   We need b_i >= prev_b = 7.
        //   We can choose b_i = 8 or b_i = 9.
        //   So, if a_i >= prev_b, we can always choose b_i = a_i. This is the smallest valid b_i.
        //   So, we update prev_b = a_i.
        //   However, there's a subtle point: if a_i + x wraps around and becomes less than prev_b,
        //   it means we *must* choose a b_i that is either a_i or some value between a_i and m-1.
        //   We cannot choose a b_i that wrapped around and became small.
        //   Example: m=10, a_i=8, prev_b=7, x=3.
        //   We can choose b_i=8 (0 ops), b_i=9 (1 op).
        //   We cannot choose b_i=0 (2 ops) or b_i=1 (3 ops) because they are < prev_b.
        //   So, if a_i >= prev_b, we can always set b_i = a_i. This is the best choice.
        //   The only exception is if a_i itself is too large such that even after incrementing by x,
        //   it still cannot be made smaller than prev_b. This is not the case here.
        //   The condition is: if a_i >= prev_b, we can set b_i = a_i.
        //   This is always valid.
        //   So, if a_i >= prev_b, we set prev_b = a_i.

        // Let's simplify. We need to find b_i such that:
        // 1. prev_b <= b_i < m
        // 2. b_i = (a_i + k) % m for some 0 <= k <= x

        // Consider the range of values [a_i, (a_i + x) % m] that can be formed.
        // This range might wrap around m.
        // Example: a_i=6, m=7, x=2. Reachable: 6, 0, 1.
        // Example: a_i=1, m=7, x=2. Reachable: 1, 2, 3.

        // If a_i >= prev_b:
        // We want to keep b_i as small as possible, so we try to set b_i = a_i.
        // This is valid if a_i >= prev_b.
