#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Case 1: Final toy in Box 1 (x <= -1)
    // This requires an odd number of negative factors and a product magnitude >= 1.
    // The magnitude condition is the tricky part.
    // If we can make the product negative, we need to check if it can be <= -1.
    // If we can make the product positive, we need to check if it can be >= 1 or < 1.

    // Let's analyze the parity of negative numbers.
    // A toy from Box 1 or Box 2 is negative.
    long long neg_count = a + b;

    // Can the final product be negative?
    // Yes, if neg_count is odd.
    // Can the final product be positive?
    // Yes, if neg_count is even.

    // Let's consider the magnitude.
    // We have three types of magnitudes:
    // Type L: |x| >= 1 (from Box 1 or Box 4)
    // Type S: |x| < 1 (from Box 2 or Box 3)

    // If there is at least one toy of Type L (a > 0 or d > 0),
    // we can potentially make the final product's magnitude >= 1.
    // If all toys are Type S (a == 0 and d == 0), then the final product's magnitude will always be < 1 (unless total_toys == 1).

    // Special case: total_toys == 1
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Box 1: x <= -1
    // Requires odd number of negative factors.
    // Requires magnitude >= 1.
    // Magnitude >= 1 is possible if (a > 0 or d > 0) OR (a == 0 and d == 0 and total_toys == 0, which is not possible here).
    // If a > 0 or d > 0, we can always pick initial values such that the product magnitude is >= 1.
    // For example, if we have one toy with value 2, and all others are 0.5, the product is 2 * 0.5^(N-1).
    // If N-1 is large, this can be < 1.
    // However, we can choose values like 2, 2, 2, ... and 0.5, 0.5, ...
    // If there is at least one toy with |x| >= 1 (from Box 1 or Box 4), we can make the final product's magnitude >= 1.
    // Example: If we have a toy with value 2, and other toys with values 0.1.
    // We can multiply 2 with 0.1 to get 0.2. Then 0.2 with 0.1 to get 0.02.
    // But we can also multiply 2 with 2 to get 4.
    // The problem states "takes two different toys randomly". This implies we can choose the order.
    // If there is at least one toy with |x| >= 1 (from Box 1 or Box 4), we can always make the final product's magnitude >= 1.
    // To do this, we can multiply all toys with |x| < 1 together first. This will result in a product with magnitude < 1.
    // Then, we multiply this small product with all toys with |x| >= 1.
    // If we have at least one toy with |x| >= 1, say `X_L`, and all other toys `X_S_i` have `|X_S_i| < 1`.
    // We can choose `X_L` to be very large (e.g., 10^9) and `X_S_i` to be very close to 1 (e.g., 0.9999).
    // Then `X_L * product(X_S_i)` can be made arbitrarily large.
    // So, if (a > 0 or d > 0), we can achieve magnitude >= 1.
    // If (a == 0 and d == 0), all initial toys have magnitude < 1. The final product will always have magnitude < 1.

    bool can_be_mag_ge_1 = (a > 0 || d > 0);

    // Box 1: x <= -1
    if (neg_count % 2 == 1 && can_be_mag_ge_1) {
        ans1 = "Ya";
    }

    // Box 2: -1 < x < 0
    // Requires odd number of negative factors.
    // Requires magnitude < 1.
    // Magnitude < 1 is always possible if total_toys > 1.
    // If (a == 0 and d == 0), magnitude < 1 is guaranteed.
    // If (a > 0 or d > 0), we can choose values such that the product is < 1.
    // E.g., if we have a toy with value 2, and all others are 0.1.
    // We can multiply 2 with 0.1 to get 0.2. Then 0.2 with 0.1 to get 0.02.
    // So, magnitude < 1 is always possible if total_toys > 1.
    if (neg_count % 2 == 1) {
        ans2 = "Ya";
    }

    // Box 3: 0 < x < 1
    // Requires even number of negative factors.
    // Requires magnitude < 1.
    // Magnitude < 1 is always possible if total_toys > 1.
    if (neg_count % 2 == 0) {
        ans3 = "Ya";
    }

    // Box 4: x >= 1
    // Requires even number of negative factors.
    // Requires magnitude >= 1.
    if (neg_count % 2 == 0 && can_be_mag_ge_1) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

