int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 1, 2, 5 form a canonical coin system.
        presses += diff / 5;
        diff %= 5;

        // Now diff can be 0, 1, 2, 3, 4
        if (diff == 4) {
            // 4 can be 2+2 (2 presses) or 5-1 (2 presses). Both are 2 presses.
            // Greedy: 4/2 = 2 presses.
            presses += 2;
        } else if (diff == 3) {
            // 3 can be 2+1 (2 presses) or 5-2 (2 presses). Both are 2 presses.
            // Greedy: 3/2 = 1 (one 2), remainder 1. Then one 1. Total 2 presses.
            presses += 2;
        } else if (diff == 2) {
            // 2 is one 2.
            presses += 1;
        } else if (diff == 1) {
            // 1 is one 1.
            presses += 1;
        }
        // If diff is 0, no more presses needed.

        std::cout << presses << "\n";
    }
    return 0;
}

