int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always produces a different permutation
        // (unless n=1, but n>=2) and results in the same set of adjacent sums.
        // For example, if p = [p1, p2, ..., pn], the sums are [p1+p2, p2+p3, ..., pn-1+pn].
        // If p' = [pn, pn-1, ..., p1], the sums are [pn+pn-1, pn-1+pn-2, ..., p2+p1].
        // These two sets of sums are identical, just in reverse order.
        // Sorting them will yield the same fingerprint.
        // Since n >= 2, p and reversed(p) are always different unless p is a palindrome,
        // but even if p is a palindrome, the problem guarantees a solution exists.
        // However, the simplest approach is to just reverse it.
        // The problem statement implies that any valid p' is acceptable.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        long long operations = 0;
        long long smallest_pile = a[0];

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we want to add smallest_pile to it
            // as many times as possible without exceeding k.
            // The number of times smallest_pile can be added to a[i] is
            // floor((k - a[i]) / smallest_pile).
            if (a[i] < k) { // Only add if a[i] itself is not already >= k
                operations += (k - a[i]) / smallest_pile;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a_items(n);
        std::vector<Item> b_items(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a_items[i].value;
            a_items[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b_items[i].value;
            b_items[i].original_index = i;
        }

        std::sort(a_items.begin(), a_items.end(), compareItems);
        std::sort(b_items.begin(), b_items.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a_items[i].original_index] = a_items[i].value;
            y[a_items[i].original_index] = b_items[i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

