                long long haybales_to_move = std::min(haybales_can_move, max_haybales_from_this_pile_given_days);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

