#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is n-1 and no p[i] is n.
    // This happens if the original permutation contained n, but it was not p[i] for any i.
    // This means the actual p[i] that was n was replaced by n-1 in our reconstruction.
    // We need to find the p[i] that should be n.
    bool found_n_minus_1 = false;
    for (int val : p) {
        if (val == n - 1) {
            found_n_minus_1 = true;
            break;
        }
    }

    if (found_n_minus_1) {
        // If there is an (n-1) in the reconstructed p, it means the true 'n' was
        // not found by max_val_in_row logic.
        // This happens if the true p_k = n, then a[k][j] = p_j for j != k.
        // The max of these p_j is n-1. So p[k] was set to n-1.
        // All other p[i] (where p_i != n) would have been correctly set to p_i.
        // So, we need to find the unique (n-1) and change it to n.
        // However, there might be multiple (n-1)s if the original permutation
        // had multiple elements equal to n-1. This is not possible for a permutation.
        // So, there must be exactly one element in the original permutation that is n.
        // And if p_k = n, then our reconstructed p[k] will be n-1.
        // All other p[i] will be correctly reconstructed.
        // So, we need to find the element that is n-1 and change it to n.
        // But what if the original permutation did not contain n-1?
        // Example: n=3, p={1,2,3}.
        // p[0]=1 -> max(a[0][j]) = 2 (from p[1]=2)
        // p[1]=2 -> max(a[1][j]) = 3 (from p[2]=3)
        // p[2]=3 -> max(a[2][j]) = 2 (from p[1]=2)
        // Reconstructed p = {2,3,2}. This is not a permutation.
        // The problem states "reconstruct any permutation".
        // The logic `p[i] = max_{j!=i} a[i][j]` correctly identifies `p[i]` if `p[i]` is not `n`.
        // If `p[i]` is `n`, then `max_{j!=i} a[i][j]` will be `n-1`.
        // So, after this step, `p` will contain `n-1` at the index where `n` was,
        // and all other values will be correct.
        // This means the set of values in `p` will be `{1, 2, ..., n-2, n-1, n-1}`.
        // We need to change one of the `n-1`s to `n`.
        // Since the problem guarantees a solution, and we know that `n` must be present,
        // we can simply find the first occurrence of `n-1` and change it to `n`.
        // This is because there will be exactly one `n-1` that corresponds to the original `n`,
        // and one `n-1` that corresponds to the original `n-1`.
        // We need to change one of them to `n`. It doesn't matter which one.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only change one instance
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

