    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle formed by the i-th cut (from apex)
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to i-th cut = i * (h / (2n)).
        // Let x_i be the distance of the i-th cut from the apex.
        // By similar triangles, the base of the triangle at height x_i is (x_i / h) * 1 = x_i / h.
        // Area of triangle at height x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * (h^2 / n).
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
