int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k distinct differences.
                       // The differences will be k, k-1, ..., 1.
                       // So we need numbers from 1 to k+1.

    // Generate the first k+1 elements to produce k distinct differences.
    // We use an alternating pattern: left, right, left+1, right-1, ...
    // This generates differences: |left - right|, |right - (left+1)|, |(left+1) - (right-1)|, ...
    // which are: right-left, right-(left+1), (right-1)-(left+1), ...
    // If left=1, right=k+1:
    // |1 - (k+1)| = k
    // |(k+1) - 2| = k-1
    // |2 - k| = k-2
    // ...
    // This sequence generates differences k, k-1, ..., 1.

    bool use_left = true;
    for (int i = 0; i <= k; ++i) { // We need k+1 elements for k differences
        if (use_left) {
            std::cout << left;
            left++;
        } else {
            std::cout << right;
            right--;
        }
        use_left = !use_left;
        std::cout << " ";
    }

    // The remaining elements are n, n-1, ..., k+2.
    // We have already printed k+1 elements.
    // The numbers used are 1, 2, ..., k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // We can just print them in increasing order.
    // This will only introduce a difference of 1 with the last element printed from the alternating sequence,
    // and then subsequent differences of 1.
    // Since 1 is already one of the k distinct differences, this does not add new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i;
        if (i < n) {
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return 0;
}

