bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the rightmost peak
    int peak_idx = m - 1;
    while (peak_idx > 0 && b[peak_idx - 1] >= b[peak_idx]) {
        peak_idx--;
    }

    // Find the rightmost valley before the peak
    int valley_idx = peak_idx;
    while (valley_idx > 0 && b[valley_idx - 1] <= b[valley_idx]) {
        valley_idx--;
    }

    // If valley_idx is 0, it means the entire suffix from 0 to m-1 is non-decreasing.
    // This implies the array is good.
    return valley_idx == 0;
}

