// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: fun value <= -1
    // This requires the final toy to be negative and its magnitude >= 1.

    // Case 1: Final toy is negative.
    // This means the total number of negative toys (A+B) must be odd.
    // If (A+B) is even, the final toy must be positive.
    if ((A + B) % 2 == 0) {
        return false; // Final toy must be positive
    }

    // Case 2: Magnitude of final toy >= 1.
    // This is the tricky part. We need to ensure that we can arrange
    // multiplications such that the magnitude doesn't drop below 1.

    // If there are any toys in Box 1 or Box 4, we can always make the magnitude >= 1.
    // A toy from Box 1 has magnitude >= 1.
    // A toy from Box 4 has magnitude >= 1.
    // If we have at least one such toy, we can always ensure the final product's magnitude is >= 1
    // by picking its value to be large enough (e.g., -100 for Box 1, 100 for Box 4)
    // and picking values in Box 2/3 to be close to 1 (e.g., -0.99, 0.99).
    // The only way the magnitude could drop below 1 is if all initial toys
    // are from Box 2 or Box 3.
    if (A > 0 || D > 0) {
        return true;
    }

    // If A=0 and D=0, all initial toys are from Box 2 or Box 3.
    // Box 2: (-1, 0) -> magnitude < 1
    // Box 3: (0, 1)  -> magnitude < 1
    // If all initial toys have magnitude < 1, then any product of these toys
    // will also have magnitude < 1.
    // For example, 0.5 * 0.5 = 0.25. -0.5 * 0.5 = -0.25. -0.5 * -0.5 = 0.25.
    // So, if A=0 and D=0, the final toy's magnitude will always be < 1.
    // Thus, it cannot be in Box 1 (or Box 4).
    return false;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: fun value in (-1, 0)
    // This requires the final toy to be negative and its magnitude < 1.

    // Case 1: Final toy is negative.
    // This means the total number of negative toys (A+B) must be odd.
    if ((A + B) % 2 == 0) {
        return false; // Final toy must be positive
    }

    // Case 2: Magnitude of final toy < 1.
    // This is always possible if there's at least one toy in Box 2 or Box 3.
    // If we have any toy in Box 2 or Box 3, we can pick its value to be very small
    // (e.g., -0.01 or 0.01) and multiply it last.
    // The product of any number of toys with magnitude < 1 will have magnitude < 1.
    // The product of toys with magnitude >= 1 and one toy with magnitude < 1
    // can be made to have magnitude < 1 by picking the <1 toy small enough.
    // For example, if we have a toy with value 100 and another with value -0.001,
    // their product is -0.1, which is in Box 2.
    // The only scenario where we *cannot* make the magnitude < 1 is if all toys
    // are from Box 1 or Box 4, and there are no toys from Box 2 or Box 3.
    // In this case, all initial toys have magnitude >= 1.
    // The product of any two toys with magnitude >= 1 will also have magnitude >= 1.
    // So, if B=0 and C=0, the final toy's magnitude will always be >= 1.
    if (B == 0 && C == 0) {
        return false; // All toys have magnitude >= 1, so final product will have magnitude >= 1
    }

    // If (A+B) is odd and (B>0 or C>0), then it's possible.
    return true;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: fun value in (0, 1)
    // This requires the final toy to be positive and its magnitude < 1.

    // Case 1: Final toy is positive.
    // This means the total number of negative toys (A+B) must be even.
    if ((A + B) % 2 != 0) {
        return false; // Final toy must be negative
    }

    // Case 2: Magnitude of final toy < 1.
    // Similar to Box 2, this is always possible if there's at least one toy in Box 2 or Box 3.
    // If B=0 and C=0, all initial toys have magnitude >= 1.
    // The product of any two toys with magnitude >= 1 will also have magnitude >= 1.
    // So, if B=0 and C=0, the final toy's magnitude will always be >= 1.
    if (B == 0 && C == 0) {
        return false; // All toys have magnitude >= 1, so final product will have magnitude >= 1
    }

    // If (A+B) is even and (B>0 or C>0), then it's possible.
    return true;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: fun value >= 1
    // This requires the final toy to be positive and its magnitude >= 1.

    // Case 1: Final toy is positive.
    // This means the total number of negative toys (A+B) must be even.
    if ((A + B) % 2 != 0) {
        return false; // Final toy must be negative
    }

    // Case 2: Magnitude of final toy >= 1.
    // Similar to Box 1, this is possible if there's at least one toy in Box 1 or Box 4.
    // If A=0 and D=0, all initial toys are from Box 2 or Box 3.
    // In this case, all initial toys have magnitude < 1.
    // The product of any number of toys with magnitude < 1 will also have magnitude < 1.
    // So, if A=0 and D=0, the final toy's magnitude will always be < 1.
    // Thus, it cannot be in Box 4 (or Box 1).
    if (A == 0 && D == 0) {
        return false;
    }

    // If (A+B) is even and (A>0 or D>0), then it's possible.
    return true;
}

