int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need to find b1, b2, ..., bs such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))
        // Let S' = current_sum + sum(b_i)
        // Let X' = current_xor_sum ^ xor_sum(b_i)
        // We need S' = 2 * X'

        // Case 1: Add 2 elements
        // Let's try to add two elements, say P and Q.
        // The new sum will be current_sum + P + Q
        // The new XOR sum will be current_xor_sum ^ P ^ Q
        // We need current_sum + P + Q = 2 * (current_xor_sum ^ P ^ Q)

        // A common strategy for these problems is to make the XOR sum equal to the sum.
        // This is not exactly what we need, but it's related.
        // We need S' = 2 * X'.
        // This implies S' must be even.
        // Also, S' - 2*X' = 0.
        // We know that for any numbers A, B: A + B = (A ^ B) + 2 * (A & B).
        // Sum of numbers = XOR sum + 2 * (sum of carries).
        // So, current_sum = current_xor_sum + 2 * K for some K.
        // The condition S' = 2 * X' can be rewritten as S' - X' = X'.
        // We know S' - X' is always even. So X' must be even.
        // This means current_xor_sum ^ xor_sum(b_i) must be even.

        // Let's try to add two elements.
        // Let the first element be current_xor_sum.
        // New XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
        // New sum becomes current_sum + current_xor_sum.
        // Now we need to add a second element, say Y, such that:
        // (current_sum + current_xor_sum + Y) = 2 * (0 ^ Y)
        // current_sum + current_xor_sum + Y = 2 * Y
        // current_sum + current_xor_sum = Y
        // So, the second element Y should be current_sum + current_xor_sum.

        // Let's verify this strategy:
        // Append b1 = current_xor_sum
        // Append b2 = current_sum + current_xor_sum
        // New sum S' = current_sum + b1 + b2
        //             = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        //             = 2 * current_sum + 2 * current_xor_sum
        // New XOR sum X' = current_xor_sum ^ b1 ^ b2
        //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        //                = 0 ^ (current_sum + current_xor_sum)
        //                = current_sum + current_xor_sum
        // Check condition: S' = 2 * X'
        // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This is always true.
        // The problem states that appended elements are non-negative.
        // current_xor_sum is always non-negative.
        // current_sum is always non-negative (since initial elements are non-negative).
        // So current_sum + current_xor_sum is also non-negative.
        // This strategy always works and adds exactly 2 elements.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

