int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute to the total steps.
            // When an 'a' moves past this 'b' (effectively 'ab' -> 'bba'),
            // it generates 2 new 'a's for future 'b's.
            // So, the current 'b' will interact with 'count_a' 'a's.
            // Each such interaction adds 'count_a' to total_steps.
            // After this 'b' is processed, the 'a's that moved past it
            // effectively double their count for the next 'b' to their left.
            // This is because 'ab' -> 'bba'. The 'a' moves past 'b', and
            // a new 'b' is inserted. The 'a' is now to the right of the 'b'.
            // The 'a's that were to the left of this 'b' effectively
            // "pass through" it.
            // The number of 'a's that will interact with the next 'b' to the left
            // will be doubled.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are currently to the right of any 'b's we've processed,
            // or are waiting to interact with 'b's to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

