// Function to convert an integer to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Reverse to get correct order (rightmost digit first)
    std::reverse(pattern_str.begin(), pattern_str.end());

    // Pad with '0's from the left to make it 18 characters long
    // This is equivalent to padding with '0's from the right after reversing,
    // which corresponds to higher-order digits being even.
    while (pattern_str.length() < 18) {
        pattern_str = '0' + pattern_str;
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern with '0's from the left to make it 18 characters long
            // This ensures it matches the format of stored patterns.
            while (s.length() < 18) {
                s = '0' + s;
            }

            // Retrieve and print the count for the padded pattern
            // If the pattern is not in the map, its count is 0 by default.
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

