    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left (i)
    // The number of items taken from the right will be (n - i)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // Sum of w[0]...w[i-1] * l
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // Sum of w[i]...w[n-1] * r
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Additional energy based on the difference in counts
        int items_left = i;
        int items_right = n - i;

        if (items_left > items_right) {
            // More items taken from left.
            // The last (items_left - items_right - 1) items taken from left
            // would have been consecutive left-hand actions after all right-hand actions finished.
            // Each of these (items_left - items_right - 1) actions incurs Ql.
            current_energy += (long long)(items_left - items_right - 1) * Ql;
        } else if (items_right > items_left) {
            // More items taken from right.
            // The last (items_right - items_left - 1) items taken from right
            // would have been consecutive right-hand actions after all left-hand actions finished.
            // Each of these (items_right - items_left - 1) actions incurs Qr.
            current_energy += (long long)(items_right - items_left - 1) * Qr;
        }
        // If items_left == items_right or |items_left - items_right| == 1, no extra cost.
        // The formula (abs(items_left - items_right) - 1) * Q_x handles this correctly
        // because if abs(diff) <= 1, then abs(diff) - 1 <= 0, so the term is 0 or negative,
        // but we only add if diff > 0.
        // The logic above is equivalent to:
        // if (items_left > items_right + 1) {
        //     current_energy += (long long)(items_left - items_right - 1) * Ql;
        // } else if (items_right > items_left + 1) {
        //     current_energy += (long long)(items_right - items_left - 1) * Qr;
        // }


        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

