            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must not be a multiple of q.
        // To make x not a multiple of q, we must remove at least one prime factor of q from p
        // such that the resulting number is no longer divisible by q.
        // We want to remove the minimum possible "factor" from p to achieve this,
        // which means we want to divide p by the smallest possible power of a prime factor of q.

        std::vector<std::pair<long long, int>> q_factors = prime_factorize(q);
        long long max_x = 0;

        for (const auto& factor_pair : q_factors) {
            long long r = factor_pair.first; // prime factor of q

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= r;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

// Using a large coordinate range for initial bounds, as per problem constraints and guarantees.
// Max coordinate value is 10^5, so min is -10^5.
// The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
// We can use slightly larger bounds to be safe, e.g., -2*10^5 to 2*10^5,
// or even -10^9 to 10^9 for initial range, then clip to -10^5 to 10^5 for output.
// Let's use -100000 and 100000 as the initial bounds for the search space.
// The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
// This implies the search space for X and Y is [-10^5, 10^5].
// So, initial bounds for min_x, max_x, min_y, max_y should be within this range.
// A robot at (x_i, y_i) with no movement restrictions can reach any (X, Y).
// If a robot cannot move left (f_1=0), it can only reach points X >= x_i.
// If a robot cannot move up (f_2=0), it can only reach points Y <= y_i.
// If a robot cannot move right (f_3=0), it can only reach points X <= x_i.
// If a robot cannot move down (f_4=0), it can only reach points Y >= y_i.

const int INF_COORD = 100000; // Max absolute coordinate value for output

void solve() {
    int n;
    std::cin >> n;

    int min_x = -INF_COORD;
    int max_x = INF_COORD;
    int min_y = -INF_COORD;
    int max_y = INF_COORD;

    for (int i = 0; i < n; ++i) {
        int x, y, f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1 means can move left (x_c - 1, y_c)
        // If f1 = 0, robot cannot move left. It can only reach points with X >= x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // f2 = 1 means can move up (x_c, y_c + 1)
        // If f2 = 0, robot cannot move up. It can only reach points with Y <= y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // f3 = 1 means can move right (x_c + 1, y_c)
        // If f3 = 0, robot cannot move right. It can only reach points with X <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4 = 1 means can move down (x_c, y_c - 1)
        // If f4 = 0, robot cannot move down. It can only reach points with Y >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point within the intersection.
        // For example, (min_x, min_y).
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_n (cannot reach target even with all diagonal/straight moves towards target)
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Parity check
        // The parity of (x+y) changes with each move.
        // (0,0) has (x+y) = 0 (even).
        // After k moves, the target (n,m) must have (n+m) with the same parity as k.
        // If (abs_n + abs_m) % 2 != k % 2, it's impossible.
        // This is equivalent to (abs_n % 2 + abs_m % 2) % 2 != k % 2.
        // Or, (abs_n % 2 != abs_m % 2) if k is even, and (abs_n % 2 == abs_m % 2) if k is odd.
        // This can be simplified: (abs_n % 2) == (abs_m % 2) means abs_n and abs_m have same parity.
        // If abs_n and abs_m have same parity, then abs_n + abs_m is even.
        // If abs_n and abs_m have different parity, then abs_n + abs_m is odd.
        // So, (abs_n + abs_m) % 2 must be equal to k % 2.
        if ((abs_n % 2) != (k % 2)) {
            // If abs_n and k have different parities, we need to make an adjustment.
            // We can always make one move that changes the parity of abs_n without changing abs_m,
            // or vice versa, by using a straight move.
            // For example, if k is even and abs_n is odd, we need to make one more move
            // that changes the parity of abs_n.
            // This means we need to use one move to go back and forth, e.g., (x,y) -> (x+1,y) -> (x,y).
            // This costs 2 moves and changes the parity of k by 2 (no net change).
            // Or, (x,y) -> (x+1,y) -> (x+1,y+1). This changes parity of x and y.
            // The simplest way to think about it is that if (abs_n % 2) != (k % 2),
            // we must use at least one "wasted" move (e.g., (x,y) -> (x+1,y) -> (x,y))
            // or a move that changes the parity of one coordinate without changing the other.
            // This effectively means we need to reduce the number of diagonal moves by 1
            // and use 2 straight moves instead, or use 1 straight move and 1 diagonal move.
            // The total number of moves k must have the same parity as abs_n.
            // If k and abs_n have different parities, we must use at least one move
            // that changes the parity of abs_n without changing the parity of abs_m.
            // This means we must use a straight move along the x-axis.
            // This costs 1 move.
            // If k and abs_n have different parities, then k - abs_n is odd.
            // The remaining k - abs_n moves must be used to adjust the parity.
            // Each pair of moves (e.g., (1,0) then (-1,0)) changes k by 2 and doesn't change position.
            // Each pair of moves (e.g., (1,1) then (-1,-1)) changes k by 2 and doesn't change position.
            // The key is that (k - abs_n) must be even.
            // If (k - abs_n) is odd, it's impossible.
            // This is equivalent to (k % 2) != (abs_n % 2).
            std::cout << -1 << "\n";
            continue;
        }

        // Maximum possible diagonal moves is k.
        // We need to reach (abs_n, abs_m).
        // We can make abs_m diagonal moves to reach (abs_m, abs_m).
        // This uses abs_m moves.
        // Remaining moves: k - abs_m.
        // Remaining distance to cover: abs_n - abs_m along x-axis.
        // We can make abs_n - abs_m straight moves along x-axis.
        // This uses abs_n - abs_m moves.
        // Total moves used so far: abs_m + (abs_n - abs_m) = abs_n.
        // Remaining moves: k - abs_n.
        // These remaining moves must be used to go back and forth without changing the final position.
        // Each such pair of moves (e.g., (1,0) then (-1,0) or (1,1) then (-1,-1))
        // uses 2 moves and can be either 2 straight moves or 2 diagonal moves.
        // To maximize diagonal moves, we prefer diagonal pairs.
        // The number of such pairs is (k - abs_n) / 2.
        // Each pair can be two diagonal moves. So, we add 2 * ((k - abs_n) / 2) diagonal moves.
        // Total diagonal moves = abs_m (to reach (abs_m, abs_m)) + 2 * ((k - abs_n) / 2).
        long long result = abs_m + 2 * ((k - abs_n) / 2);
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
