    long long chanek_coins = 0;

    while (n > 0) {
        if (n == 1) {
            chanek_coins += 1;
            n = 0;
        } else if (n == 2) {
            chanek_coins += 1; // Chanek takes 1, opponent takes 1. Chanek gets 1.
            n = 0;
        } else if (n == 3) {
            chanek_coins += 1; // Chanek takes 1, opponent takes 1, Chanek takes 1. Chanek gets 2.
            // Or Chanek takes 1, opponent takes 2/2=1, Chanek takes 1. Chanek gets 2.
            // The example says Chanek takes 1, opponent takes 2, Chanek takes 1, opponent takes 1.
            // This implies N=5 -> C:1 (N=4) -> O:2 (N=2) -> C:1 (N=1) -> O:1 (N=0). C: 1+1=2, O: 2+1=3.
            // For N=3, if C takes 1 (N=2), O takes 1 (N=1), C takes 1 (N=0). C: 1+1=2, O: 1.
            // If C takes 1 (N=2), O takes 2/2=1 (N=1), C takes 1 (N=0). C: 1+1=2, O: 1.
            // So for N=3, Chanek gets 2.
            // The current logic is for N=3, Chanek takes 1, N becomes 2.
            // Next turn is opponent. Opponent will take 1 (N=1).
            // Next turn is Chanek. Chanek will take 1 (N=0).
            // So Chanek gets 1 (from first move) + 1 (from third move) = 2.
            // The loop structure means we add 1 to chanek_coins, then n becomes 2.
            // The next iteration, n=2, chanek_coins += 1, n=0.
            // So for N=3, chanek_coins becomes 1, then 1 again. Total 2. This is correct.
            chanek_coins += 1;
            n = 0;
        } else if (n % 2 == 1) { // N is odd and N > 3
            chanek_coins += 1;
            n -= 1;
        } else { // N is even and N > 0
            // If N is even, Chanek can take N/2 or 1.
