#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) {
        used_in_s.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::set<char> visited_in_layout;
    char start_char = '\0';

    // Find a starting character for the layout.
    // It must be a character from 's' with degree 1 (an endpoint of a path).
    // Or if all characters in 's' have degree 2, pick any character from 's'.
    // Or if 's' has only one character, pick that one.
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // Degree 0 or 1
            start_char = c;
            break;
        }
    }
    if (start_char == '\0' && !used_in_s.empty()) { // All chars in 's' have degree 2 (cycle or long path)
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // To keep track of the previous character in the layout path

        while (current_char != '\0' && visited_in_layout.find(current_char) == visited_in_layout.end()) {
            keyboard_layout += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Check if all characters from 's' that were part of the graph are included in the layout.
    // This handles cases where the graph might have multiple disconnected components,
    // which would make it impossible to form a single linear layout.
    for (char c : used_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unused characters to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

