int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_first = 0; k_first < L; ++k_first) { // Iterate over all possible initial k values
        char char0 = s[k_first]; // This is t[0] for this k_first

        // Find all k' values such that s[k'] == char0
        std::vector<int> possible_k_values;
        for (int idx : char_indices[char0 - 'a']) {
            possible_k_values.push_back(idx);
        }

        if (possible_k_values.size() == 1) {
            // If only one k' matches char0, Vasya already knows k uniquely.
            // This k' must be k_first.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to maximize win probability
        // for this specific char0.
        double max_win_prob_for_char0 = 0.0;

        // Iterate over all possible positions p (1-indexed, from 2 to L)
        // Vasya chooses p, so p is fixed for all k' in possible_k_values.
        for (int p = 2; p <= L; ++p) {
            // For a fixed p, count how many k' values are uniquely determined.
            int unique_count = 0;

            // Group k' values by the character s[(k' + p - 1) % L]
            std::vector<std::vector<int>> groups_by_char_at_p(26);
            for (int k_prime : possible_k_values) {
                char char_at_p = s[(k_prime + p - 1) % L];
                groups_by_char_at_p[char_at_p - 'a'].push_back(k_prime);
            }

            for (int c_idx = 0; c_idx < 26; ++c_idx) {
                if (groups_by_char_at_p[c_idx].size() == 1) {
                    unique_count++;
                }
            }

            max_win_prob_for_char0 = std::max(max_win_prob_for_char0, (double)unique_count / possible_k_values.size());
        }
        total_win_prob += max_win_prob_for_char0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

