#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                // Check for overflow before multiplication
                // Max possible length is N = 2e5. Max value for 18 bits is 2^18 - 1 = 262143.
                // If current_val is already large, multiplying by 2 might exceed 2*N.
                // We only care about values up to N + MAX_ZERO_PREFIX_LEN.
                // MAX_ZERO_PREFIX_LEN is around 18-20. So N + 20.
                // If current_val > 2*N, then current_val * 2 will be even larger.
                // We can cap current_val at a slightly larger value than N to avoid overflow
                // and still correctly identify when it's too large.
                // A safe upper bound for current_val is N + 20 (max length + max zero prefix).
                // If current_val exceeds 2*N, it's definitely too large for any valid length.
                if (current_val > 2LL * n) { // Heuristic check to prevent overflow and early exit
                    break;
                }

                current_val = current_val * 2 + (s[j] - '0');
                long long current_len = j - i + 1;

                if (current_val == current_len) {
                    good_substrings_count++;
                }
            }
        }
        // Case 2: Substring starts with '0'
        else { // s[i] == '0'
            // Find the first '1' after s[i]
            int first_one_idx = -1;
            for (int k = i + 1; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) {
                // All remaining characters are '0's.
                // f(0...0) = 0. Length must be 0, which is impossible for non-empty substring.
                // So no good substrings starting with '0' if all subsequent are '0'.
                // The problem statement f(000) = 0. Length 3. 3 != 0.
                // So no good substrings here.
                continue;
            }

            // Iterate from first_one_idx to the end of the string
            long long current_val = 0;
            for (int j = first_one_idx; j < n; ++j) {
                if (current_val > 2LL * n) { // Heuristic check
                    break;
                }

                current_val = current_val * 2 + (s[j] - '0');
                long long current_len = j - i + 1;

                if (current_val == current_len) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

