                for (int C_i = 0; C_i <= 1; ++C_i) {
                    int res0 = (0 & A_i | B_i) ^ C_i;
                    int res1 = (1 & A_i | B_i) ^ C_i;

                    if (res0 == target_val0_bit && res1 == target_val1_bit) {
                        if (A_i == 1) final_A |= (1 << i);
                        if (B_i == 1) final_B |= (1 << i);
                        if (C_i == 1) final_C |= (1 << i);
