void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // and suffix sums for the right half (jars n+1 to 2n).
    // For type 1, add 1. For type 2, subtract 1.

    // Left half: jars 0 to n-1 (0-indexed)
    // Karlsson is between n-1 and n.
    // We are interested in the balance of jars *remaining* after eating.
    // If he eats k jars from the left, jars 0 to k-1 are eaten.
    // Jars k to n-1 remain.
    // The balance of jars 0 to n-1 is sum[n-1] - sum[k-1].
    // Let's compute the balance of jars *eaten* from the left.
    // `left_balance[k]` = balance of jars 0 to k-1.
    // `left_balance[0]` = 0 (no jars eaten)
    // `left_balance[k]` = balance of jars 0 to k-1.
    std::map<int, int> left_balance_to_k;
    left_balance_to_k[0] = 0; // 0 jars eaten from left, balance 0

    int current_balance = 0;
    for (int k = 0; k < n; ++k) { // k is 0-indexed jar index
        current_balance += (a[k] == 1 ? 1 : -1);
        // Store the minimum k for each balance.
        // If a balance is encountered again, it means we ate more jars
        // to achieve the same balance, which is not optimal for minimizing eaten jars.
        if (left_balance_to_k.find(current_balance) == left_balance_to_k.end()) {
            left_balance_to_k[current_balance] = k + 1; // k+1 jars eaten
        }
    }

    // Right half: jars n to 2n-1 (0-indexed)
    // `right_balance[k]` = balance of jars 2n-1 down to 2n-k.
    // `right_balance[0]` = 0 (no jars eaten)
    // `right_balance[k]` = balance of jars 2n-k to 2n-1.
    std::map<int, int> right_balance_to_k;
    right_balance_to_k[0] = 0; // 0 jars eaten from right, balance 0

    current_balance = 0;
    for (int k = 0; k < n; ++k) { // k is 0-indexed jar index from right end
        current_balance += (a[2 * n - 1 - k] == 1 ? 1 : -1);
        if (right_balance_to_k.find(current_balance) == right_balance_to_k.end()) {
            right_balance_to_k[current_balance] = k + 1; // k+1 jars eaten
        }
    }

    // Calculate the initial total balance of all 2n jars
    int total_initial_balance = 0;
    for (int x : a) {
        total_initial_balance += (x == 1 ? 1 : -1);
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible balances of jars eaten from the left.
    // Let `bal_L` be the balance of `k_L` jars eaten from the left.
    // The remaining jars have a balance of `total_initial_balance - bal_L - bal_R`.
    // We want this to be 0, so `bal_L + bal_R = total_initial_balance`.
    // This means `bal_R = total_initial_balance - bal_L`.
    for (auto const& [bal_L, k_L] : left_balance_to_k) {
        int target_bal_R = total_initial_balance - bal_L;
        if (right_balance_to_k.count(target_bal_R)) {
            int k_R = right_balance_to_k[target_bal_R];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

