#include <iostream>
#include <string>
#include <numeric> // For std::accumulate

// Function to calculate the parity of a 01-string
// Returns 1 if odd number of '1's, 0 otherwise.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate the parity of the initial string a
    int parity_a = calculate_parity(a);

    // If parity_a is 0, it means an even number of '1's.
    // We can append '0's indefinitely.
    // If parity_a is 1, it means an odd number of '1's.
    // We can append '1's indefinitely.
    // However, after appending a '1', the count of '1's becomes even,
    // so the next parity will be '0'.
    // After appending a '0', the count of '1's remains odd,
    // so the next parity will be '1'.
    // So, the sequence of parities appended is:
    // If initial parity is 0: 0, 0, 0, ... (count of '1's remains even)
    // If initial parity is 1: 1, 0, 1, 0, ... (count of '1's alternates odd/even)

    // The maximum number of '1's we can achieve in string 'a'
    // is its current count of '1's plus one (if we can append a '1').
    // If the initial parity of 'a' is 0, we can only append '0's,
    // so the count of '1's in 'a' never increases.
    // If the initial parity of 'a' is 1, we can append a '1',
    // increasing the count of '1's by one. After that, the parity becomes 0,
    // and we can only append '0's.
    // So, the maximum number of '1's we can ever have in 'a' (including appended parities)
    // is `calculate_parity(a) + calculate_parity(a)`.
    // This is `parity_a + (1 - parity_a)` if we consider the possibility of appending a '1'
    // which changes the parity.
    // A simpler way: if parity_a is 0, max_ones_a = count_ones(a).
    // If parity_a is 1, max_ones_a = count_ones(a) + 1.
    // This can be written as count_ones(a) + parity_a.

    int count_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            count_ones_a++;
        }
    }

    int max_ones_a_possible = count_ones_a + parity_a;

    // Calculate the number of '1's in string b
    int count_ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            count_ones_b++;
        }
    }

    // Condition 1: The number of '1's in b must be less than or equal to
    // the maximum number of '1's we can achieve in a.
    if (count_ones_b > max_ones_a_possible) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of b must be less than or equal to the length of a
    // plus the number of '0's we can append.
    // We can append as many characters as needed to match the length of b,
    // as long as the '1's count matches.
    // The only constraint on length is that we can always make 'a' longer
    // by appending parities. We can also make 'a' shorter by removing characters.
    // So, if count_ones_b <= max_ones_a_possible, we can always construct a string
    // with length |b| and count_ones_b.
    // The only edge case is if |a| < |b| and we need to append characters.
    // If |a| >= |b|, we can just remove characters from 'a' to match 'b's length,
    // then check '1's count.
    // If |a| < |b|, we must append characters.
    // The crucial part is that we can always make 'a' long enough to match 'b's length.
    // The only thing that matters is the count of '1's.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <queue>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        std::queue<int> leaving_children_q;

        // Apply v_cry from current child
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply total_d_cry_from_leaving first
            if (total_d_cry_from_leaving > 0) {
                children[j].p -= total_d_cry_from_leaving;
            }

            // Apply current_v_cry
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            if (children[j].p < 0) {
                if (children[j].in_line) { // Check if already marked to leave
                    children[j].in_line = false;
                    leaving_children_q.push(j);
                }
            }
        }

        // Process chain reactions from children leaving
        while (!leaving_children_q.empty()) {
            int leaving_idx = leaving_children_q.front();
            leaving_children_q.pop();

            total_d_cry_from_leaving += children[leaving_idx].d;

            for (int j = leaving_idx + 1; j < n; ++j) {
                if (!children[j].in_line) {
                    continue;
                }

                children[j].p -= children[leaving_idx].d;

                if (children[j].p < 0) {
                    if (children[j].in_line) {
                        children[j].in_line = false;
                        leaving_children_q.push(j);
                    }
                }
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

