// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_prefix and s_suffix.
    // We can reorder them to s_suffix + s_prefix.
    // We need s_suffix + s_prefix to be a palindrome AND not equal to s.
    // The original string s is guaranteed to be a palindrome.
    // If s_suffix + s_prefix == s, then it means s_suffix + s_prefix == s_prefix + s_suffix.
    // This implies s_prefix and s_suffix commute.
    // If s_prefix and s_suffix commute, and their concatenation is a palindrome,
    // then s_suffix + s_prefix is also a palindrome.
    // So, for k=1, we just need to find if there's any cut such that s_suffix + s_prefix != s.

    // If all characters in s are the same (e.g., "aaaa"), then any rotation will result in the same string.
    // In this case, s_suffix + s_prefix will always be equal to s.
    // We can check this by seeing if s[0] == s[n/2]. If s is a palindrome and all chars are same,
    // then s[0] == s[i] for all i.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible\n";
        return 0;
    }

    // If not all characters are the same, we can always find a k=1 solution unless n=1.
    // For n=1, s="a", all_same_chars is true, handled above.
    // For n > 1 and not all_same_chars:
    // Consider the string s. Since it's a palindrome and not all chars are same,
    // there must be at least two distinct characters.
    // For example, "otto". s_prefix="o", s_suffix="tto". s_suffix+s_prefix = "ttoo". Not a palindrome.
    // s_prefix="ot", s_suffix="to". s_suffix+s_prefix = "toot". Palindrome, != "otto". k=1.
    // For "nolon". s_prefix="n", s_suffix="olon". s_suffix+s_prefix = "olonn". Not palindrome.
    // s_prefix="no", s_suffix="lon". s_suffix+s_prefix = "lonno". Not palindrome.
    // s_prefix="nol", s_suffix="on". s_suffix+s_prefix = "onnol". Not palindrome.

    // The problem states "unite those pieces together to get a new string".
    // "Pieces couldn't be turned over, they could be shuffled."
    // For k=1, we have two pieces, s_1 and s_2. We can form s_1s_2 (original) or s_2s_1.
    // We need s_2s_1 to be a palindrome and s_2s_1 != s_1s_2.

    // Let's iterate through all possible single cuts.
    // A cut at index `i` (0-indexed) means `s_prefix = s.substr(0, i+1)` and `s_suffix = s.substr(i+1)`.
    // The cut position `i` can range from `0` to `n-2`.
    // This means `s_prefix` has length `i+1` and `s_suffix` has length `n-(i+1)`.
    // Both `s_prefix` and `s_suffix` must be non-empty.
    // So `i+1 >= 1` (i.e., `i >= 0`) and `n-(i+1) >= 1` (i.e., `i+1 <= n-1`, `i <= n-2`).

    for (int i = 0; i < n - 1; ++i) {
        std::string s_prefix = s.substr(0, i + 1);
        std::string s_suffix = s.substr(i + 1);
        std::string s_prime = s_suffix + s_prefix;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << "\n";
            return 0;
        }
    }

    // If no solution with k=1, then k=2 is always possible for n > 1 and not all_same_chars.
    // Example: s = "nolon" (n=5).
    // s_prefix="no", s_middle="l", s_suffix="on".
    // Pieces: "no", "l", "on".
    // Original order: "no" + "l" + "on" = "nolon".
    // New order: "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
    // This uses 2 cuts.
    // This strategy works for any palindrome s of length > 1 that is not all same chars.
    // Let s = P M P_rev, where P is the first half, M is the middle character/empty string, P_rev is the reverse of P.
    // If n is even, s = P P_rev.
    // If n is odd, s = P c P_rev.
    // We can cut s into three pieces: P, M (or empty), P_rev.
    // For example, if s = P P_rev (n even), cut into P and P_rev. This is k=1.
    // If s = P c P_rev (n odd), cut into P, c, P_rev. This is k=2.
    // The pieces are s.substr(0, n/2), s.substr(n/2, n%2), s.substr(n/2 + n%2).
    // Let s_1 = s.substr(0, n/2)
    // Let s_2 = s.substr(n/2, n%2) (middle char if n is odd, empty if n is even)
    // Let s_3 = s.substr(n/2 + n%2)
    // The original string is s_1 + s_2 + s_3.
    // We can rearrange to s_3 + s_2 + s_1.
    // Since s is a palindrome, s_1 is the reverse of s_3. (s_1 = reverse(s_3)).
    // So s_3 + s_2 + s_1 = reverse(s_1) + s_2 + s_1.
    // This string is a palindrome if s_2 is a palindrome (which it is, being 0 or 1 char)
    // and reverse(s_1) + s_2 + s_1 is a palindrome.
    // This is always a palindrome.
    // Example: s = "nolon". s_1="no", s_2="l", s_3="on".
    // s_3 + s_2 + s_1 = "on" + "l" + "no" = "onlno". This is a palindrome.
    // Is "onlno" != "nolon"? Yes.
    // This construction always yields a different string unless s_1 is empty (n=0 or n=1).
    // n=1 is handled by all_same_chars.
    // So for n > 1 and not all_same_chars, this construction works.
    // If n is even, s_2 is empty, so we have s_3 + s_1. This is a k=1 solution.
    // If n is odd, s_2 is a single character, so we have s_3 + s_2 + s_1. This is a k=2 solution.
    // Since we already checked for k=1, if we reach here, it means no k=1 solution was found.
    // This implies that if n is even, the k=1 solution (s_3 + s_1) must have been equal to s.
    // This would mean s_3 + s_1 == s_1 + s_3, which implies s_1 and s_3 commute.
    // If s_1 and s_3 commute, and s_1 = reverse(s_3), then s_1 must be a string of repeating characters.
    // E.g., s_1 = "aa", s_3 = "aa". Then s = "aaaa". This is covered by all_same_chars.
    // So if we reach here, it must be that n is odd.
    // And for odd n, the k=2 solution (s_3 + s_2 + s_1) is guaranteed to be different from s
    // and a palindrome, provided not all chars are the same.

    std::cout << 2 << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
