int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that s[i...r] contains no Rash triplet.
    // Initialize with n, meaning s[i...n] contains no Rash triplet.
    // This will be updated downwards.
    std::vector<int> max_r_for_l(n + 1, n); 

    // Iterate through all possible x and k to find Rash triplets.
    // Indices are 0-based in string, 1-based in problem statement.
    // s_x = s[x-1], s_{x+k} = s[x+k-1], s_{x+2k} = s[x+2k-1]
    // For a triplet (x, k), the indices are x-1, x+k-1, x+2k-1.
    // The minimum l for this triplet is x. The minimum r is x+2k.
    // The triplet spans from index x-1 to x+2k-1 in 0-based string.
    // The length of the triplet is 2k+1.
    // The maximum possible k is (n-1)/2.
    // The maximum possible x is n-2.
    // The maximum possible x+2k-1 is n-1.

    for (int x_0based = 0; x_0based < n; ++x_0based) {
        // k can be 1, 2, 3, 4, 5, 6.
        // If k >= 7, then 2k+1 >= 15.
        // The maximum length of a triplet is 2k+1.
        // If 2k+1 >= 15, then k >= 7.
        // For k=7, 2k+1 = 15.
        // If n < 15, no triplet with k >= 7 can exist.
        // If n >= 15, then for any x, the triplet s[x...x+14] would be considered.
        // The crucial observation is that if a substring s[l...r] contains a Rash triplet,
        // it must contain one where 2k+1 is small.
        // Specifically, if s[l...r] contains s_x = s_{x+k} = s_{x+2k},
        // then it also contains s_x = s_{x+k'} = s_{x+2k'} for some k' <= 6.
        // This is because if there is a triplet with k >= 7, say s_a = s_{a+k} = s_{a+2k},
        // then the string s_a s_{a+1} ... s_{a+2k} has length at least 15.
        // By pigeonhole principle, in any binary string of length 15, there must be
        // a triplet s_i = s_{i+k'} = s_{i+2k'} for some k' <= 6.
        // This is a known result from combinatorics on words (e.g., related to square-free words).
        // So we only need to check k up to 6.
        for (int k = 1; k <= 6; ++k) {
            int x_plus_k_0based = x_0based + k;
            int x_plus_2k_0based = x_0based + 2 * k;

            if (x_plus_2k_0based < n) {
                if (s[x_0based] == s[x_plus_k_0based] && s[x_0based] == s[x_plus_2k_0based]) {
                    // Found a Rash triplet starting at x_0based with step k.
                    // The 1-based indices are x = x_0based + 1, r_min = x_plus_2k_0based + 1.
                    // Any substring s[l...r] where l <= x and r >= r_min contains this triplet.
                    // We need to update max_r_for_l[l] for l from 1 to x.
                    // For each such l, the maximum r that does NOT contain this triplet
                    // must be less than r_min. So we update max_r_for_l[l] = min(max_r_for_l[l], r_min - 1).
                    // In 0-based indexing:
                    // For each l_0based from 0 to x_0based,
                    // max_r_for_l[l_0based] = min(max_r_for_l[l_0based], x_plus_2k_0based).
                    // Note: max_r_for_l stores the 0-based index of the rightmost character
                    // of a valid substring. So if a triplet ends at x_plus_2k_0based,
                    // then any valid substring must end before x_plus_2k_0based.
                    // So we update max_r_for_l[l_0based] = min(max_r_for_l[l_0based], x_plus_2k_0based - 1).
                    // The problem uses 1-based indexing for l, r.
                    // max_r_for_l[l] stores the 1-based r.
                    // So for l from 1 to x_0based + 1, update max_r_for_l[l] = min(max_r_for_l[l], x_plus_2k_0based).
                    // The value stored in max_r_for_l[l] is the maximum r (1-based) such that s[l...r] is bad.
                    // If a triplet ends at 0-based index `end_idx_0based`, then any `r` (1-based)
                    // such that `r >= end_idx_0based + 1` makes the substring `s[l...r]` good.
                    // So, for any `l` (1-based) from `1` to `x_0based + 1`,
                    // the maximum `r` (1-based) for which `s[l...r]` is bad is `end_idx_0based`.
                    // So we update `max_r_for_l[l] = min(max_r_for_l[l], end_idx_0based)`.
                    // Here, `end_idx_0based` is `x_plus_2k_0based`.
                    // The `max_r_for_l` array is 1-indexed for `l`.
                    // `max_r_for_l[l]` stores the maximum `r` (1-based) such that `s[l...r]` is a bad substring.
                    // Initially, `max_r_for_l[l] = n` for all `l`.
                    // If a triplet is found ending at `x_plus_2k_0based` (0-based),
                    // then for any `l_0based` from `0` to `x_0based`,
                    // the substring `s[l_0based ... x_plus_2k_0based]` is good.
                    // So, for `l = l_0based + 1`, the maximum `r` (1-based) for which `s[l...r]` is bad
                    // must be less than `x_plus_2k_0based + 1`.
                    // So, `max_r_for_l[l] = min(max_r_for_l[l], x_plus_2k_0based)`.
                    // This means `max_r_for_l[l]` is the largest `r` (1-based) such that `s[l...r]` is bad.
                    // If `max_r_for_l[l]` is `R`, then `s[l...R]` is bad, and `s[l...R+1]` is good (if `R+1 <= n`).
                    // The number of bad pairs for a given `l` is `max_r_for_l[l] - l + 1`.
                    // If `max_r_for_l[l] < l`, it means no bad pairs for this `l`.

                    // The triplet ends at 0-based index x_plus_2k_0based.
                    // This means any substring s[l_0based ... r_0based] where l_0based <= x_0based
                    // and r_0based >= x_plus_2k_0based is a "good" substring.
                    // We want to find the maximum r_0based for each l_0based such that s[l_0based ... r_0based] is "bad".
                    // So, for each l_0based from 0 to x_0based,
                    // the maximum r_0based for a bad substring must be less than x_plus_2k_0based.
                    // So we update max_r_for_l[l_0based + 1] = min(max_r_for_l[l_0based + 1], x_plus_2k_0based).
                    // This means for 1-based l, max_r_for_l[l] is the largest 1-based r such that s[l...r] is bad.
                    // If a triplet ends at 0-based index `end_idx_0based`, then for any `l_0based` from `0` to `x_0based`,
                    // the maximum `r_0based` for a bad substring `s[l_0based ... r_0based]` is `end_idx_0based - 1`.
                    // So, `max_r_for_l[l_0based + 1] = min(max_r_for_l[l_0based + 1], end_idx_0based)`.
                    // This is because `max_r_for_l[l]` stores the 1-based `r`.
                    // If `end_idx_0based` is the 0-based end of a triplet, then `end_idx_0based + 1` is the 1-based end.
                    // So, for any `l` (1-based) from `1` to `x_0based + 1`,
                    // the maximum `r` (1-based) for which `s[l...r]` is bad is `min(current_max_r, end_idx_0based)`.
                    // Example: triplet 010101, x=1, k=1. s[0]=s[2]=s[4]. end_idx_0based = 4.
                    // For l=1 (x_0based=0), max_r_for_l[1] = min(n, 4).
                    // For l=2 (x_0based=1), max_r_for_l[2] = min(n, 4).
                    // Example: triplet 010101, x=2, k=1. s[1]=s[3]=s[5]. end_idx_0based = 5.
                    // For l=1 (x_0based=0), max_r_for_l[1] = min(current_max_r, 5).
                    // For l=2 (x_0based=1), max_r_for_l[2] = min(current_max_r, 5).
                    // For l=3 (x_0based=2), max_r_for_l[3] = min(n, 5).

                    // The correct logic for max_r_for_l[l] (1-based l) is:
                    // max_r_for_l[l] stores the maximum 1-based r such that s[l...r] is a BAD substring.
                    // If a triplet is found ending at 0-based index `end_idx_0based`,
                    // then for any `l_0based` from `0` to `x_0based`,
                    // the substring `s[l_0based ... end_idx_0based]` is GOOD.
                    // This means that for `l = l_0based + 1`, any `r` (1-based) such that `r >= end_idx_0based + 1`
                    // makes `s[l...r]` GOOD.
                    // So, the maximum `r` (1-based) for which `s[l...r]` can be BAD is `end_idx_0based`.
                    // We update `max_r_for_l[l_0based + 1] = min(max_r_for_l[l_0based + 1], end_idx_0based)`.
                    // This is correct.

                    int end_idx_0based = x_plus_2k_0based;
                    for (int l_0based = 0; l_0based <= x_0based; ++l_0based) {
                        max_r_for_l[l_0based + 1] = std::min(max_r_for_l[l_0based + 1], end_idx_0based);
                    }
                }
            }
        }
    }

    // Calculate bad_pairs
    for (int l = 1; l <= n; ++l) {
        // max_r_for_l[l] is the maximum 1-based r such that s[l...r] is bad.
        // If max_r_for_l[l] < l, it means no bad pairs for this l.
        // Otherwise, bad pairs are (l, l), (l, l+1), ..., (l, max_r_for_l[l]).
        // The count is max_r_for_l[l] - l + 1.
        if (max_r_for_l[l] >= l) {
            bad_pairs += (max_r_for_l[l] - l + 1);
        }
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }
    std::vector<long long> p_orig(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p_orig[i];
    }

    std::set<long long> p_set(p_orig.begin(), p_orig.end());
    for (long long val : h) {
        p_set.insert(val);
    }
    std::vector<long long> p(p_set.begin(), p_set.end());

    std::vector<int> p_indices_to_read;
    for (int i = 0; i < p.size(); ++i) {
        bool is_original_p = std::binary_search(p_orig.begin(), p_orig.end(), p[i]);
        bool is_original_h = std::binary_search(h.begin(), h.end(), p[i]);
        if (is_original_p && !is_original_h) {
            p_indices_to_read.push_back(i);
        }
    }

    if (p_indices_to_read.empty()) {
        return 0;
    }

    auto check = [&](long long T) {
        std::vector<long long> dp(p.size(), -1); // dp[i] = min_h_idx to cover p[i]

        // Initialize dp for heads that can cover p[0]
        for (int j = 0; j < n; ++j) {
            if (h[j] - T <= p[0]) {
                dp[0] = j;
                break;
            }
        }

        for (int i = 1; i < p.size(); ++i) {
            // Option 1: Use a new head for p[i]
            // Find the smallest j such that h[j] - T <= p[i]
            auto it = std::upper_bound(h.begin(), h.end(), p[i] + T);
            if (it != h.begin()) {
                --it;
                if (*it - T <= p[i]) {
                    dp[i] = std::distance(h.begin(), it);
                }
            }

            // Option 2: Extend coverage from p[i-1]
            if (dp[i-1] != -1) {
                long long prev_h_idx = dp[i-1];
                if (h[prev_h_idx] + T >= p[i]) {
                    if (dp[i] == -1 || prev_h_idx < dp[i]) {
                        dp[i] = prev_h_idx;
                    }
                }
            }
        }

        std::vector<long long> dp_left(p.size(), -1); // dp_left[i] = min_h_idx to cover p[i]

        // Initialize dp_left for heads that can cover p[0]
        for (int j = 0; j < n; ++j) {
            if (h[j] - T <= p[0]) {
                dp_left[0] = j;
                break;
            }
        }

        for (int i = 1; i < p.size(); ++i) {
            // Option 1: Use a new head for p[i]
            // Find the smallest j such that h[j] - T <= p[i]
            auto it = std::upper_bound(h.begin(), h.end(), p[i] + T);
            if (it != h.begin()) {
                --it;
                if (*it - T <= p[i]) {
                    dp_left[i] = std::distance(h.begin(), it);
                }
            }

            // Option 2: Extend coverage from p[i-1]
            if (dp_left[i-1] != -1) {
                long long prev_h_idx = dp_left[i-1];
                if (h[prev_h_idx] + T >= p[i]) {
                    if (dp_left[i] == -1 || prev_h_idx < dp_left[i]) {
                        dp_left[i] = prev_h_idx;
                    }
                }
            }
        }

        std::vector<long long> dp_right(p.size(), -1); // dp_right[i] = max_h_idx to cover p[i]

        // Initialize dp_right for heads that can cover p[p.size()-1]
        for (int j = n - 1; j >= 0; --j) {
            if (h[j] + T >= p[p.size()-1]) {
                dp_right[p.size()-1] = j;
                break;
            }
        }

        for (int i = p.size() - 2; i >= 0; --i) {
            // Option 1: Use a new head for p[i]
            // Find the largest j such that h[j] + T >= p[i]
            auto it = std::lower_bound(h.begin(), h.end(), p[i] - T);
            if (it != h.end()) {
                if (*it + T >= p[i]) {
                    dp_right[i] = std::distance(h.begin(), it);
                }
            }

            // Option 2: Extend coverage from p[i+1]
            if (dp_right[i+1] != -1) {
                long long next_h_idx = dp_right[i+1];
                if (h[next_h_idx] - T <= p[i]) {
                    if (dp_right[i] == -1 || next_h_idx > dp_right[i]) {
                        dp_right[i] = next_h_idx;
                    }
                }
            }
        }

        std::vector<long long> dp_min_h_idx_to_cover_prefix(p.size(), -1);
        for (int i = 0; i < p.size(); ++i) {
            if (dp_left[i] != -1) {
                dp_min_h_idx_to_cover_prefix[i] = dp_left[i];
            }
            if (i > 0 && dp_min_h_idx_to_cover_prefix[i-1] != -1) {
                if (dp_min_h_idx_to_cover_prefix[i] == -1 || dp_min_h_idx_to_cover_prefix[i-1] < dp_min_h_idx_to_cover_prefix[i]) {
                    dp_min_h_idx_to_cover_prefix[i] = dp_min_h_idx_to_cover_prefix[i-1];
                }
            }
        }

        std::vector<long long> dp_max_h_idx_to_cover_suffix(p.size(), -1);
        for (int i = p.size() - 1; i >= 0; --i) {
            if (dp_right[i] != -1) {
                dp_max_h_idx_to_cover_suffix[i] = dp_right[i];
            }
            if (i < p.size() - 1 && dp_max_h_idx_to_cover_suffix[i+1] != -1) {
                if (dp_max_h_idx_to_cover_suffix[i] == -1 || dp_max_h_idx_to_cover_suffix[i+1] > dp_max_h_idx_to_cover_suffix[i]) {
                    dp_max_h_idx_to_cover_suffix[i] = dp_max_h_idx_to_cover_suffix[i+1];
                }
            }
        }

        for (int p_idx : p_indices_to_read) {
            bool covered = false;
            // Case 1: Covered by a single head
            // Find a head j such that h[j] - T <= p[p_idx] <= h[j] + T
            auto it_low = std::upper_bound(h.begin(), h.end(), p[p_idx] + T);
            if (it_low != h.begin()) {
                --it_low;
                if (*it_low - T <= p[p_idx]) {
                    covered = true;
                }
            }
            if (covered) continue;

            // Case 2: Covered by two heads
            // Find a split point k such that p[p_idx] is covered by a head covering prefix up to k,
            // and another head covering suffix from k+1.
            // This is not quite right. We need to cover p[p_idx] itself.
            // The logic should be: is p[p_idx] covered by a head that also covers some prefix,
            // OR by a head that also covers some suffix.
            // The DP states `dp_min_h_idx_to_cover_prefix` and `dp_max_h_idx_to_cover_suffix`
            // are for covering *all* points up to `i` or *all* points from `i`.
            // We need to check if `p[p_idx]` is covered by *any* head.
            // The `dp_left` and `dp_right` arrays are for this.

            // Check if p[p_idx] is covered by a head that covers some prefix ending at p[p_idx]
            if (dp_left[p_idx] != -1) {
                covered = true;
            }
            if (covered) continue;

            // Check if p[p_idx] is covered by a head that covers some suffix starting at p[p_idx]
            if (dp_right[p_idx] != -1) {
                covered = true;
            }
            if (covered) continue;

            // If p[p_idx] is not covered by any single head, or by a head that covers a prefix/suffix
            // then it's impossible to cover all points.
            // This means we need to find a head `j` such that `h[j] - T <= p[p_idx]` and `h[j] + T >= p[p_idx]`.
            // This is exactly what `covered` variable checks.
            // If `covered` is false here, it means `p[p_idx]` cannot be covered by any head.
            return false;
        }
        return true;
    };

    long long low = 0, high = 20000000000LL, ans = high; // Max possible diff is 10^10, so 2*10^10 is safe upper bound

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::cout << solve() << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a_0 into S1, and a_1, ..., a_{n-1} into S2.
    // This ensures that a_0 is in a different subsequence from all other elements.
    // The smallest sum a_i + a_j is a_0 + a_1.
    // If a_0 and a_1 are in different subsequences, f(a_0, a_1) = a_0 + a_1 + h.
    // If a_0 and a_1 are in the same subsequence, f(a_0, a_1) = a_0 + a_1.
    //
    // Consider the partition where elements[0] is in S1, and elements[1...n-1] are in S2.
    // min_f:
    //   - If n=2: S1={a_0}, S2={a_1}. Only f(a_0, a_1) = a_0 + a_1 + h. min_f = max_f = a_0 + a_1 + h. Goodness = 0.
    //   - If n > 2:
    //     - Pairs within S1: None.
    //     - Pairs within S2: Smallest is elements[1].value + elements[2].value.
    //     - Pairs across S1 and S2: Smallest is elements[0].value + elements[1].value.
    //     So, min_f = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h).
    //     This is incorrect. The minimum f value is always elements[0].value + elements[1].value (if they are in the same group)
    //     or elements[0].value + elements[1].value + h (if they are in different groups).
    //
    // Let's re-evaluate the min/max f values for a general partition.
    // min_f = min(a_i + a_j, a_k + a_l + h)
    // max_f = max(a_i + a_j, a_k + a_l + h)
    //
    // The smallest possible sum of two elements is elements[0].value + elements[1].value.
    // The largest possible sum of two elements is elements[n-2].value + elements[n-1].value.
    //
    // Let's consider the partition where elements[0] is in group 1, and all other elements are in group 2.
    // This is a common strategy for minimizing the range when h is large.
    //
    // Values of f:
    // 1. For pairs (a_i, a_j) where a_i, a_j are both in group 2 (i.e., i, j >= 1):
    //    Range: [elements[1].value + elements[2].value, elements[n-2].value + elements[n-1].value]
    // 2. For pairs (a_0, a_j) where a_j is in group 2 (i.e., j >= 1):
    //    Range: [elements[0].value + elements[1].value + h, elements[0].value + elements[n-1].value + h]
    //
    // So, for this partition:
    // min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) (if n > 2)
    //         If n=2, min_f = elements[0].value + elements[1].value + h.
    // max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    //
    // Let's simplify.
    // The minimum possible value of `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible value of `a_i + a_j` is `elements[n-2].value + elements[n-1].value`.
    //
    // Consider two main candidates for optimal partition:
    // 1. All elements in one group.
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-2].value + elements[n-1].value
    //    Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    //
    // 2. elements[0] in group 1, elements[1...n-1] in group 2.
    //    min_f:
    //      - If n=2: only f(a_0, a_1) = a_0 + a_1 + h. min_f = a_0 + a_1 + h.
    //      - If n > 2:
    //        - Pairs within group 2: min sum is elements[1].value + elements[2].value.
    //        - Pairs across groups: min sum is elements[0].value + elements[1].value + h.
    //        So, min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h).
    //    max_f:
    //      - If n=2: max_f = a_0 + a_1 + h.
    //      - If n > 2:
    //        - Pairs within group 2: max sum is elements[n-2].value + elements[n-1].value.
    //        - Pairs across groups: max sum is elements[0].value + elements[n-1].value + h.
    //        So, max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h).
    //    Goodness = max_f - min_f.

    long long goodness2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (n == 2) {
        goodness2 = 0; // Only one pair (a_0, a_1), they are in different groups. f(a_0, a_1) = a_0 + a_1 + h. min_f = max_f.
    } else {
        long long min_f_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_case2 = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
        goodness2 = max_f_case2 - min_f_case2;
    }

    // Case 3: elements[0], elements[1] in group 1, elements[2...n-1] in group 2.
    // This is relevant if h is small.
    // This partition ensures that elements[0] and elements[1] are in the same group.
    // This makes f(a_0, a_1) = a_0 + a_1.
    //
    // Values of f:
    // 1. Pairs within group 1 (S1 = {a_0, a_1}): Only (a_0, a_1). Value: elements[0].value + elements[1].value.
    // 2. Pairs within group 2 (S2 = {a_2, ..., a_{n-1}}):
    //    Range: [elements[2].value + elements[3].value, elements[n-2].value + elements[n-1].value] (if n > 3)
    //    If n=3, S2={a_2}, no pairs.
    // 3. Pairs across groups (a_i in S1, a_j in S2):
    //    Smallest: elements[0].value + elements[2].value + h.
    //    Largest: elements[1].value + elements[n-1].value + h.
    //    Range: [elements[0].value + elements[2].value + h, elements[1].value + elements[n-1].value + h] (if n > 2)
    //
    // For this partition:
    // min_f:
    //   - If n=2: S1={a_0, a_1}, S2={}. Only f(a_0, a_1) = a_0 + a_1. min_f = a_0 + a_1.
    //   - If n=3: S1={a_0, a_1}, S2={a_2}.
    //     Pairs: (a_0, a_1) -> a_0+a_1
    //            (a_0, a_2) -> a_0+a_2+h
    //            (a_1, a_2) -> a_1+a_2+h
    //     min_f = a_0+a_1
    //   - If n > 3:
    //     min_f = std::min({elements[0].value + elements[1].value,
    //                       elements[2].value + elements[3].value,
    //                       elements[0].value + elements[2].value + h})
    // max_f:
    //   - If n=2: max_f = a_0 + a_1.
    //   - If n=3: max_f = std::max({a_0+a_1, a_0+a_2+h, a_1+a_2+h}) = a_1+a_2+h.
    //   - If n > 3:
    //     max_f = std::max({elements[0].value + elements[1].value,
    //                       elements[n-2].value + elements[n-1].value,
    //                       elements[1].value + elements[n-1].value + h})
    //
    // This is getting complicated. Let's simplify the logic.
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-2].value + elements[n-1].value + h` (if there's any cross-group pair).
    // Or `elements[n-2].value + elements[n-1].value` (if all are in one group).
    //
    // The key observation is that the minimum possible `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible `a_i + a_j` is `elements[n-2].value + elements[n-1].value`.
    //
    // Let `min_base = elements[0].value + elements[1].value`.
    // Let `max_base = elements[n-2].value + elements[n-1].value`.
    //
    // The values of f are either `X` or `X + h`.
    // The range of `X` is `[min_base, max_base]`.
    //
    // If all elements are in one group:
    //   min_f = min_base
    //   max_f = max_base
    //   Goodness = max_base - min_base.
    //
    // If there are elements in both groups:
    //   min_f = min(min_base, min_base + h) = min_base (if a_0, a_1 are in same group)
    //   min_f = min_base + h (if a_0, a_1 are in different groups)
    //   max_f = max(max_base, max_base + h) = max_base + h (if a_{n-2}, a_{n-1} are in different groups)
    //   max_f = max_base (if a_{n-2}, a_{n-1} are in same group)
    //
    // The minimum possible value of f is either `elements[0].value + elements[1].value` (if `elements[0]` and `elements[1]` are in the same group)
    // or `elements[0].value + elements[1].value + h` (if `elements[0]` and `elements[1]` are in different groups).
    //
    // The maximum possible value of f is either `elements[n-2].value + elements[n-1].value` (if `elements[n-2]` and `elements[n-1]` are in the same group)
    // or `elements[n-2].value + elements[n-1].value + h` (if `elements[n-2]` and `elements[n-1]` are in different groups).
    //
    // Let's consider the two main scenarios:
    // Scenario A: All elements are in the same group.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-2].value + elements[n-1].value
    //   Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    //   This is `goodness1`.
    //
    // Scenario B: There are elements in both groups.
    //   This means there is at least one pair (a_i, a_j) such that a_i is in S1 and a_j is in S2.
    //   So, `h` will be added to at least one pair.
    //   The smallest possible `f` value is `elements[0].value + elements[1].value`.
    //   The largest possible `f` value is `elements[n-2].value + elements[n-1].value + h`.
    //   This is because we can always construct a partition where `elements[0]` and `elements[1]` are in the same group (e.g., both in S1),
    //   and `elements[n-2]` and `elements[n-1]` are in different groups (e.g., `elements[n-2]` in S1, `elements[n-1]` in S2).
    //   For example, put `elements[0], ..., elements[n-2]` in S1, and `elements[n-1]` in S2.
    //   Then `f(elements[0], elements[1]) = elements[0].value + elements[1].value`.
    //   And `f(elements[n-2], elements[n-1]) = elements[n-2].value + elements[n-1].value + h`.
    //   In this partition:
    //     min_f = elements[0].value + elements[1].value
    //     max_f = elements[n-2].value + elements[n-1].value + h
    //     Goodness = (elements[n-2].value + elements[n-1].value + h) - (elements[0].value + elements[1].value)
    //
    // This is a candidate for minimal goodness. Let's call it `goodness_candidate_B`.
    //
    // What if `elements[0]` and `elements[1]` are in different groups?
    // Then `min_f` would be at least `elements[0].value + elements[1].value + h`.
    // This would increase the minimum `f` value, potentially reducing the goodness if `max_f` doesn't increase as much.
    //
    // Let's consider the partition where `elements[0]` is in group 1, and all other `n-1` elements are in group 2.
    // This is `partition2`.
    // For this partition:
    //   min_f_val:
    //     - If n=2: `elements[0].value + elements[1].value + h` (only one pair, different groups)
    //     - If n > 2: `std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)`
    //   max_f_val:
    //     - If n=2: `elements[0].value + elements[1].value + h`
    //     - If n > 2: `std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)`
    //   Goodness = max_f_val - min_f_val. This is `goodness2`.
    //
    // The optimal solution is either `goodness1` or `goodness2`.
    // Why?
    // The minimum possible value of `f` is `elements[0].value + elements[1].value`.
    // The maximum possible value of `f` is `elements[n-2].value + elements[n-1].value + h`.
    //
    // Let `min_f_actual` be the minimum `f` value in an optimal partition.
    // Let `max_f_actual` be the maximum `f` value in an optimal partition.
    //
    // `min_f_actual` can be `elements[0].value + elements[1].value` (if `elements[0]` and `elements[1]` are in the same group).
    // `min_f_actual` can be `elements[0].value + elements[1].value + h` (if `elements[0]` and `elements[1]` are in different groups).
    //
    // `max_f_actual` can be `elements[n-2].value + elements[n-1].value` (if `elements[n-2]` and `elements[n-1]` are in the same group).
    // `max_f_actual` can be `elements[n-2].value + elements[n-1].value + h` (if `elements[n-2]` and `elements[n-1]` are in different groups).
    //
    // Consider the case where `h` is very large.
    // Then we want to avoid `+h` terms as much as possible.
    // If we put all elements in one group, goodness is `max_base - min_base`. No `+h` terms.
    // If we put `elements[0]` in S1 and `elements[1...n-1]` in S2:
    //   `min_f` will be `elements[1].value + elements[2].value` (if n > 2) or `elements[0].value + elements[1].value + h` (if n=2).
    //   `max_f` will be `elements[0].value + elements[n-1].value + h`.
    //   The goodness will be dominated by `h`.
    //   Specifically, `max_f - min_f` will be roughly `(elements[0].value + elements[n-1].value + h) - (elements[1].value + elements[2].value)`.
    //   This is large if `h` is large.
    //
    // However, if `h` is small, `goodness1` might be large, and `goodness2` might be small.
    //
    // Let's check the example:
    // 3 2
    // 1 2 3
    // Sorted: (1,0), (2,1), (3,2)
    // n=3, h=2
    //
    // Case 1 (all 1s):
    // goodness1 = (elements[1].value + elements[2].value) - (elements[0].value + elements[1].value)
    //           = (2 + 3) - (1 + 2) = 5 - 3 = 2.
    // Partition: 1 1 1
    // f values:
    // f(1,2) = 1+2 = 3
    // f(1,3) = 1+3 = 4
    // f(2,3) = 2+3 = 5
    // max-min = 5-3 = 2.
    //
    // Case 2 (elements[0] in S1, others in S2):
    // elements[0]=(1,0), elements[1]=(2,1), elements[2]=(3,2)
    // Partition: (1,0) in S1, (2,1), (3,2) in S2.
    // Original indices: a_0=1, a_1=2, a_2=3.
    // Partition: a_0 in S1, a_1 in S2, a_2 in S2.
    // Output: 1 2 2
    //
    // min_f_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //             = std::min(2 + 3, 1 + 2 + 2) = std::min(5, 5) = 5.
    // max_f_case2 = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    //             = std::max(elements[1].value + elements[2].value, elements[0].value + elements[2].value + h)
    //             = std::max(2 + 3, 1 + 3 + 2) = std::max(5, 6) = 6.
    // goodness2 = 6 - 5 = 1.
    //
    // This matches the example output. So `goodness2` is better than `goodness1` here.
    //
    // The logic seems to be:
    // The minimum possible goodness is either:
    // 1. All elements in one group. Goodness = (a_{n-1} + a_{n-2}) - (a_0 + a_1).
    // 2. `a_0` in one group, `a_1, ..., a_{n-1}` in the other group.
    //    Goodness = `max(a_{n-1} + a_0 + h, a_{n-1} + a_{n-2}) - min(a_0 + a_1 + h, a_1 + a_2)`.
    //    (Special handling for n=2).
    //
    // Let's verify the `min_f_case2` and `max_f_case2` for n=2.
    // If n=2, elements[0] in S1, elements[1] in S2.
    // Only one pair (elements[0], elements[1]). They are in different groups.
    // f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h.
    // Goodness = 0.
    // My code handles this with `if (n == 2) goodness2 = 0;`. This is correct.
    //
    // What if `n=3`?
    // `elements[0]` in S1, `elements[1], elements[2]` in S2.
    // Pairs:
    //   - (elements[1], elements[2]) in S2: `elements[1].value + elements[2].value`
    //   - (elements[0], elements[1]) across groups: `elements[0].value + elements[1].value + h`
    //   - (elements[0], elements[2]) across groups: `elements[0].value + elements[2].value + h`
    //
    // min_f_case2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f_case2 = std::max(elements[1].value + elements[2].value, elements[0].value + elements[2].value + h)
    // This is correct for n=3.
    //
    // The logic seems sound. The two candidate partitions cover the extreme cases of `h` being very small (all same group)
    // and `h` being very large (isolate the smallest element to minimize cross-group sums).
    //
    // The problem asks for minimal goodness.
    // If `goodness1 <= goodness2`, then `goodness1` is the answer, and `partition1` is the output.
    // Else, `goodness2` is the answer, and `partition2` is the output.

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
    } else {
        std::cout << goodness2 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

