#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation p always yields a different permutation p'
    // with the same fingerprint.
    //
    // Let p = [p_1, p_2, ..., p_n].
    // The sums of adjacent elements are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    //
    // Let p' be the reversed permutation: p' = [p_n, p_{n-1}, ..., p_1].
    // The sums of adjacent elements in p' are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    //
    // Notice that this set of sums is exactly the same as the set of sums for p,
    // just in reverse order.
    // For example, p_n+p_{n-1} is the same sum as p_{n-1}+p_n.
    // p_{n-1}+p_{n-2} is the same sum as p_{n-2}+p_{n-1}.
    // ...
    // p_2+p_1 is the same sum as p_1+p_2.
    //
    // Since the fingerprint F(p) is defined as the *sorted* array of these sums,
    // if the sets of sums are identical, their sorted versions will also be identical.
    // Thus, F(p) = F(p').
    //
    // A reversed permutation p' is different from p unless p is a palindrome.
    // However, for n >= 2, a permutation [p_1, ..., p_n] cannot be a palindrome
    // if it contains distinct integers from 1 to n.
    // For example, if p_1 = 1, then p_n must be 1 for it to be a palindrome,
    // but elements must be distinct.
    // The only exception is n=1, where [1] is a palindrome, but n >= 2 is given.
    // For n=2, p=[1,2], p'=[2,1]. They are different.
    // For n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    //
    // Therefore, reversing the permutation always works.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

