void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048. Any excess count for a given power of two
        // will be carried over to the next higher power of two.
        // For example, if we have three 512s, two combine to 1024,
        // one 512 remains. The 1024 contributes to the sum.
        // The remaining 512 is effectively added to the sum of 512s.
        // This is equivalent to summing up all values less than or equal to 2048.
        current_sum += (long long)val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

