int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, a_i up to 100. n up to 100.
                     // Max cost is 99 days. Max haybales 100 * 100 = 10000.
                     // d can be 100, so long long for d is not strictly necessary
                     // but good practice for sums involving d.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            int pile_idx = i; // 0-indexed pile index
            int haybales_in_pile = a[pile_idx];
            long long cost_per_haybale = pile_idx; // Cost to move one haybale from pile_idx+1 to pile 1

            if (d >= cost_per_haybale) { // If we have enough days to move at least one haybale from this pile
                long long haybales_to_move = std::min((long long)haybales_in_pile, d / cost_per_haybale);
                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            }
            if (d == 0) { // If we run out of days, no more moves are possible
                break;
            }
        }
        std::cout << current_a1 << std::endl;
    }
