void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // The strategy is to use '2' as the first digit, and '3' for all subsequent digits,
        // except for the last digit which is '9'.
        // This forms a number like 233...39.
        //
        // Let's check divisibility:
        // 1. Divisibility by 2: The number ends in 9, which is odd. So, it's not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + (n-2)*3 + 9.
        //    Sum = 2 + 3n - 6 + 9 = 3n + 5.
        //    For the number to be divisible by 3, 3n + 5 must be divisible by 3.
        //    This means 5 must be divisible by 3, which is false.
        //    So, the number is not divisible by 3.
        // 3. Divisibility by 9: For the number to be divisible by 9, the sum of digits (3n + 5)
        //    must be divisible by 9.
        //    Since 3n + 5 is not divisible by 3, it cannot be divisible by 9 either.
        //    (If a number is divisible by 9, it must be divisible by 3).
        //    So, the number is not divisible by 9.
        //
        // The digits used are 2, 3, 9.
        // Since it's not divisible by 2, 3, or 9, it's not divisible by any of its digits.
        // All digits are non-zero. The number has n digits.
        // This construction works for all n >= 2.

        std::cout << '2'; // First digit
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '3'; // Middle digits
        }
        std::cout << '9'; // Last digit
        std::cout << "\n";
    }
}

