void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int color_for_T_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Smaller than T/2, assign to white (0)
        } else if (a[i] > T_half) {
            p[i] = 1; // Larger than T/2, assign to black (1)
        } else { // a[i] == T_half
            if (T_is_even) {
                // For elements equal to T/2, alternate colors
                p[i] = color_for_T_half;
                color_for_T_half = 1 - color_for_T_half; // Flip color for next T/2 element
            } else {
                // If T is odd, T/2 is not an integer, so a[i] cannot be T/2.
                // This branch should ideally not be reached if a[i] == T_half is true.
                // However, if T_half is integer division, then a[i] == T_half means a[i] < T/2 + 1.
                // But the problem states a_i are non-negative integers.
                // If T is odd, then T/2 is not an integer, so no a_i can be exactly T/2.
                // So this else branch only applies if T is even.
                // For safety, if T is odd and a[i] == T_half (which means T_half is integer division and a[i] is T/2 rounded down),
                // then a[i] + a[i] != T. In this case, a[i] is just a regular number not equal to T/2.
                // The logic for a[i] < T_half and a[i] > T_half already covers this.
                // So this else branch is only for T_is_even and a[i] == T_half.
                // The current logic is correct.
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

