#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_price_suffix with the last element, as it's the minimum
    // for the suffix starting at n-1.
    int min_price_suffix = a[n - 1];

    // Iterate from the second to last element backwards to the first element.
    // For each element a[i], we compare it with the minimum price found
    // in the suffix a[i+1...n-1].
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_price_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_suffix, it means a[i]
            // is a new minimum for the suffix a[i...n-1].
            min_price_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

