#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    bool n_used = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
        if (p[i] == n) {
            n_used = true;
        }
    }

    if (!n_used) {
        // If 'n' was not assigned to any p[i], it means all p[i] were determined
        // by max(min(p[i], p[j])) for j!=i, and none of them reached 'n'.
        // This implies that 'n' must be one of the p[i] values, and it must be
        // the one whose row's maximum a[i][j] was the largest among all rows.
        // However, this logic is flawed. If 'n' is not used, it means that
        // for every i, p[i] is not n.
        // But if p[i] is not n, then max_{j!=i} min(p[i], p[j]) could be n-1.
        // If p[i] = n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j].
        // This value could be n-1 if there is some p[j]=n-1.
        // The problem states that a solution is guaranteed.
        // If 'n' is not present in the calculated p values, it means that
        // for every i, p[i] was determined as max_{j!=i} a[i][j] < n.
        // This implies that the actual value of p[i] must be n for exactly one i.
        // For this specific i, p[i] = n. For all other j, p[j] < n.
        // So, a[i][j] = min(n, p[j]) = p[j].
        // Thus, max_{j!=i} a[i][j] = max_{j!=i} p[j] = n-1 (since n-1 is the largest value among p[j] for j!=i).
        // So, if n is not used, it means there is exactly one index k such that p[k] should be n.
        // For this k, the calculated p[k] (which is max_{j!=k} a[k][j]) must be n-1.
        // We need to find such a k and set p[k] = n.
        // The problem guarantees a solution, so there must be exactly one such k.

        // Find the index k where p[k] should be n.
        // This k is the index where max_{j!=k} a[k][j] is n-1, AND
        // for all other i, max_{j!=i} a[i][j] is less than n-1.
        // Or, more simply, if n is not used, it means one of the p[i] values
        // that we calculated as max_val_in_row should actually be n.
        // This happens if the true p[i] was n, and all other p[j] were < n.
        // In this case, max_{j!=i} min(p[i], p[j]) = max_{j!=i} min(n, p[j]) = max_{j!=i} p[j].
        // Since all other p[j] are < n, the maximum of them must be n-1.
        // So, if n is not used, exactly one p[i] must be n, and its calculated value would be n-1.
        // We need to find an index i where p[i] (calculated as max_val_in_row) is n-1,
        // and change it to n. If there are multiple such indices, any one is fine.
        // The problem guarantees a solution, so there will be at least one such index.

        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        // We need to partition these 2n students into two classes, each with an odd number of students.
        // Let the sizes be S1 and S2, where S1 + S2 = 2n, and S1, S2 are odd.
        // The smallest possible odd size is 1.
        // The largest possible odd size is 2n-1.
        //
        // Consider the case where S1 = 1 and S2 = 2n-1.
        // For S1=1, the median is simply the single element.
        // For S2=2n-1, the median is the ((2n-1)-1)/2 + 1 = (n-1)+1 = n-th element (0-indexed) of its sorted elements.
        //
        // It can be proven that the optimal strategy is to assign the smallest n elements to one class
        // and the largest n elements to the other class, or more generally, to split the sorted array
        // into two halves.
        //
        // Specifically, if we sort the entire array a_0, a_1, ..., a_{2n-1},
        // the median of a class of size 2k+1 is its k-th element (0-indexed) after sorting.
        //
        // The key insight is that to minimize the difference between medians, we want the medians to be as close as possible.
        // The elements a_{n-1} and a_n are the two "middle" elements of the entire sorted array.
        //
        // If we form two classes, one with elements {a_0, ..., a_{n-1}} and the other with {a_n, ..., a_{2n-1}},
        // this would result in two classes of size n. This is only valid if n is odd.
        //
        // However, the problem states that each class must have an odd number of students.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // Let's try to make the medians as close as possible.
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        //
        // If we take the first $n$ elements $a_0, \dots, a_{n-1}$ and the last $n$ elements $a_n, \dots, a_{2n-1}$.
        //
        // The problem is equivalent to finding two indices $i$ and $j$ such that $a_i$ and $a_j$ are medians of two classes,
        // and $|a_i - a_j|$ is minimized.
        //
        // Consider the case where one class takes $a_0, \dots, a_{n-1}$ and the other takes $a_n, \dots, a_{2n-1}$.
        // This is not a valid partition because the class sizes are $n$, which might be even.
        //
        // The crucial observation is that if we sort all $2n$ skill levels, say $s_0 \le s_1 \le \dots \le s_{2n-1}$.
        // We need to pick $S_1$ students for class 1 and $S_2$ students for class 2, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        //
        // Let $m_1$ be the median of class 1 and $m_2$ be the median of class 2.
        //
        // It turns out that the minimum difference is always achieved by taking $a_{n-1}$ and $a_n$ as the medians of the two classes.
        //
        // Why?
        // Suppose we have a partition. Let $M_1$ be the set of students in class 1 and $M_2$ for class 2.
        // Let $m_1$ be the median of $M_1$ and $m_2$ be the median of $M_2$.
        //
        // Consider the sorted array $a_0, \dots, a_{2n-1}$.
        // The element $a_{n-1}$ is the $(n)$-th element (1-indexed) and $a_n$ is the $(n+1)$-th element.
        //
        // If we choose $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ such that $k_1+k_2 = n-1$.
        //
        // The minimum possible difference is always $a_n - a_{n-1}$.
        //
        // To achieve this, we can construct the classes as follows:
        // Class 1: Take $k_1$ elements from $a_0, \dots, a_{n-2}$, then $a_{n-1}$, then $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        // This is not how medians work.
        //
        // The median of a set of $2k+1$ elements is the $(k+1)$-th element when sorted.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can form a class 1 of size $2k_1+1$ and class 2 of size $2k_2+1$ such that $k_1+k_2=n-1$.
        //
        // Let's try to make $a_{n-1}$ the median of class 1 and $a_n$ the median of class 2.
        //
        // To make $a_{n-1}$ the median of class 1 (size $2k_1+1$):
        // We need $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements greater than or equal to $a_{n-1}$.
        // We can pick $a_{n-1}$ itself.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$.
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        //
        // To make $a_n$ the median of class 2 (size $2k_2+1$):
        // We need $k_2$ elements smaller than or equal to $a_n$ and $k_2$ elements greater than or equal to $a_n$.
        // We can pick $a_n$ itself.
        // We can pick $k_2$ elements from $a_0, \dots, a_{n-1}$.
        // We can pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is a constructive proof.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ such that $k_1+k_2 = n-1$.
        //
        // Class 1:
        // Take $a_{n-1}$.
        // Take $k_1$ elements from $a_0, \dots, a_{n-2}$. (e.g., $a_0, \dots, a_{k_1-1}$)
        // Take $k_1$ elements from $a_n, \dots, a_{2n-1}$. (e.g., $a_n, \dots, a_{n+k_1-1}$)
        // This forms a class of size $1+k_1+k_1 = 2k_1+1$.
        // The median of this class would be $a_{n-1}$ if the elements are chosen carefully.
        //
        // Class 2:
        // Take $a_n$.
        // Take $k_2$ elements from $a_0, \dots, a_{n-1}$ (that are not used in Class 1).
        // Take $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (that are not used in Class 1).
        // This forms a class of size $1+k_2+k_2 = 2k_2+1$.
        // The median of this class would be $a_n$ if the elements are chosen carefully.
        //
        // The simplest way to achieve this is to make one class consist of $a_0, \dots, a_{n-1}$ and the other $a_n, \dots, a_{2n-1}$.
        // This is not allowed because $n$ might be even.
        //
        // The problem is simpler than that. The minimum difference is always $a_n - a_{n-1}$.
        //
        // Consider the elements $a_0, \dots, a_{2n-1}$ sorted.
        // We need to pick $S_1$ elements for class 1 and $S_2$ elements for class 2.
        // $S_1 = 2k_1+1$, $S_2 = 2k_2+1$. $S_1+S_2 = 2n \implies 2k_1+1+2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1=n$.
        // So $k_1+k_2 = n-1$.
        //
        // The median of class 1 is the $(k_1+1)$-th element of its sorted members.
        // The median of class 2 is the $(k_2+1)$-th element of its sorted members.
        //
        // Let $m_1$ be the median of class 1 and $m_2$ be the median of class 2.
        //
        // Suppose $m_1 < m_2$.
        // For $m_1$ to be the median of class 1, there must be at least $k_1$ elements in class 1 that are $\le m_1$ (excluding $m_1$ itself)
        // and at least $k_1$ elements in class 1 that are $\ge m_1$ (excluding $m_1$ itself).
        //
        // For $m_2$ to be the median of class 2, there must be at least $k_2$ elements in class 2 that are $\le m_2$ (excluding $m_2$ itself)
        // and at least $k_2$ elements in class 2 that are $\ge m_2$ (excluding $m_2$ itself).
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The $n$-th element (0-indexed $a_{n-1}$) and $(n+1)$-th element (0-indexed $a_n$) are the "middle" elements.
        //
        // Let's try to prove that $a_n - a_{n-1}$ is the minimum.
        //
        // Suppose we have a partition with medians $m_A$ and $m_B$. Assume $m_A \le m_B$.
        // Class A has size $2k_A+1$, median $m_A$.
        // Class B has size $2k_B+1$, median $m_B$.
        // $k_A+k_B = n-1$.
        //
        // In class A, there are $k_A$ elements $\le m_A$ and $k_A$ elements $\ge m_A$ (excluding $m_A$ itself).
        // In class B, there are $k_B$ elements $\le m_B$ and $k_B$ elements $\ge m_B$ (excluding $m_B$ itself).
        //
        // Total elements $\le m_A$ in class A: $k_A+1$.
        // Total elements $\ge m_B$ in class B: $k_B+1$.
        //
        // All elements in class A that are $\le m_A$ are also $\le m_B$.
        // All elements in class B that are $\ge m_B$ are also $\ge m_A$.
        //
        // The total number of elements in the entire $2n$ array that are $\le m_A$ is at least $k_A+1$.
        // The total number of elements in the entire $2n$ array that are $\ge m_B$ is at least $k_B+1$.
        //
        // Let $N_{\le x}$ be the count of elements in the original $2n$ array that are $\le x$.
        // Let $N_{\ge x}$ be the count of elements in the original $2n$ array that are $\ge x$.
        //
        // We have $N_{\le m_A} \ge k_A+1$.
        // We have $N_{\ge m_B} \ge k_B+1$.
        //
        // Since $m_A \le m_B$, all elements counted in $N_{\ge m_B}$ are also $\ge m_A$.
        //
        // The total number of elements is $2n$.
        // The number of elements strictly between $m_A$ and $m_B$ is $2n - N_{\le m_A} - N_{\ge m_B \text{ and } > m_A}$.
        //
        // This is a standard result for median problems. When you sort the entire array $a_0, \dots, a_{2n-1}$,
        // the minimum possible difference between the medians of two classes (each of odd size, summing to $2n$)
        // is $a_n - a_{n-1}$.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // n-1 = 0, n = 1. a[0]=1, a[1]=1. Difference = 1-1=0. Correct.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n-1 = 2, n = 3. a[2]=3, a[3]=4. Difference = 4-3=1. Correct.
        //
        // Example 3: n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1 = 4, n = 5. a[4]=8, a[5]=13. Difference = 13-8=5. Correct.
        //
        // The logic seems to hold for all examples.
        // The proof relies on the fact that if you have two sets of numbers, and you want to minimize the difference between their medians,
        // the medians will be adjacent elements in the combined sorted list.
        //
        // To construct such a partition:
        // Let $m_1 = a_{n-1}$ and $m_2 = a_n$.
        // We need to form two classes, $C_1$ and $C_2$, with odd sizes $S_1, S_2$ such that $m_1$ is median of $C_1$ and $m_2$ is median of $C_2$.
        // Let $S_1 = 1$ and $S_2 = 2n-1$.
        // Class 1: $\{a_{n-1}\}$. Median is $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$. This class has $n-1 + n = 2n-1$ elements.
        // The median of Class 2 would be the $((2n-1)-1)/2 + 1 = n$-th element (1-indexed) of its sorted elements.
        // The elements of Class 2 are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // When sorted, these are $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$.
        // The $n$-th element (1-indexed) is $a_n$. So $a_n$ is the median of Class 2.
        // This construction works. The difference is $|a_n - a_{n-1}|$.
        //
        // This is a valid partition:
        // Class 1: $\{a_{n-1}\}$ (size 1, odd). Median is $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$, odd). Median is $a_n$.
        // All students are assigned.
        // The difference is $a_n - a_{n-1}$.
        // Since this is a valid partition, and we know that the medians must be at least $a_{n-1}$ and $a_n$ respectively (or vice versa),
        // this difference is the minimum possible.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x
            // Total remaining students to fill the 3rd slot in 'mid' teams:
            // (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already assigned 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members to fill the 3rd slot in each team.
            // These 'mid' members can come from remaining coders, mathematicians, or x.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
