int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos is -1, it means the effective last 'R' was at cell 0.
                             // If last_R_pos is 0, it means the 'R' at index 0 of string s.
                             // To align with problem's 0-indexed string and 1-indexed cells:
                             // Cell 0 is before s[0].
                             // Cell i corresponds to s[i-1].
                             // Cell n+1 is after s[n-1].

        // The frog starts at cell 0.
        // The first segment is from cell 0 to the first 'R' cell.
        // If s[i] is 'R', it means the frog can jump right from cell i+1.
        // The problem states: "if the frog is staying at the i-th cell and the i-th character is 'R'".
        // This means s[0] corresponds to cell 1, s[1] to cell 2, ..., s[n-1] to cell n.
        // So, if s[k] is 'R', the frog can jump right from cell k+1.

        // Let's re-evaluate the positions.
        // Frog is at cell 0.
        // String s has length n. s_1 ... s_n.
        // s_i is char at cell i.
        // If frog at cell i, s_i is 'L' or 'R'.
        // This means s[0] in string corresponds to s_1 (cell 1), s[1] to s_2 (cell 2), ..., s[n-1] to s_n (cell n).

        // The frog must be able to jump from cell 0 to some cell j.
        // Then from cell j to some cell k, and so on, until cell n+1.
        // The crucial observation is that 'L' cells are obstacles for moving right.
        // The frog can only move right from cell 0.
        // If the frog is at cell `i` and `s_i` is 'R', it can jump right.
        // If the frog is at cell `i` and `s_i` is 'L', it can jump left.
        // To reach `n+1`, the frog must always make progress to the right, or at least not get stuck.
        // The 'L' cells are problematic because they force jumps to the left.
        // To overcome an 'L' cell at position `i`, the frog must jump over it.
        // This means the frog must jump from some cell `j < i` to some cell `k > i`.
        // This implies that `s_j` must be 'R'.

        // The strategy is to find the maximum distance between consecutive 'R' cells (or cell 0 and first 'R', or last 'R' and cell n+1).
        // Let's consider the positions where the frog can jump right.
        // These are cell 0, and any cell `i` where `s_i` is 'R'.
        // In 0-indexed string `s`, `s[k]` corresponds to cell `k+1`.
        // So, the frog can jump right from cell 0.
        // And from cell `k+1` if `s[k]` is 'R'.

        // Let's list all "right-jump-enabling" positions:
        // Cell 0.
        // Cell `k+1` for all `k` such that `s[k] == 'R'`.
        // And finally, the target cell `n+1` can be considered a "right-jump-enabling" position for calculation purposes,
        // as we need to reach it from the last 'R' cell.

        // Let `P` be the list of indices `p` such that `s[p-1] == 'R'` (meaning cell `p` allows right jumps),
        // plus `0` at the beginning and `n+1` at the end.
        // Example: s = LRLRRLL, n=7
        // Cells: 0  1  2  3  4  5  6  7  8
        // s_i:    L  R  L  R  R  L  L
        // s[k]:   s[0] s[1] s[2] s[3] s[4] s[5] s[6]
        // 'R' cells are: cell 2 (s[1]), cell 4 (s[3]), cell 5 (s[4]).
        // P = [0, 2, 4, 5, 8]
        // Gaps:
        // 2 - 0 = 2
        // 4 - 2 = 2
        // 5 - 4 = 1
        // 8 - 5 = 3
        // Max gap = 3. So d=3.

        // Example: s = L, n=1
        // Cells: 0  1  2
        // s_i:    L
        // s[k]:   s[0]
        // 'R' cells: none.
        // P = [0, 2]
        // Gaps: 2 - 0 = 2
        // Max gap = 2. So d=2.

        // Example: s = LLR, n=3
        // Cells: 0  1  2  3  4
        // s_i:    L  L  R
        // s[k]:   s[0] s[1] s[2]
        // 'R' cells: cell 3 (s[2])
        // P = [0, 3, 4]
        // Gaps: 3 - 0 = 3
        // 4 - 3 = 1
        // Max gap = 3. So d=3.

        // This logic seems correct.
        // We need to find the maximum distance between:
        // 1. Cell 0 and the first cell `i` where `s_i` is 'R'.
        // 2. Two consecutive cells `i` and `j` where `s_i` is 'R' and `s_j` is 'R'.
        // 3. The last cell `i` where `s_i` is 'R' and cell `n+1`.

        // Let `current_pos` be the last cell from which the frog could jump right. Initially, `current_pos = 0`.
        // Iterate through the string `s` (0-indexed). `s[k]` corresponds to cell `k+1`.
        // If `s[k] == 'R'`, then cell `k+1` allows right jumps.
        // The distance from `current_pos` to `k+1` is `(k+1) - current_pos`.
        // We need `d` to be at least this distance. Update `max_gap`.
        // Then update `current_pos = k+1`.

        // After iterating through the string, `current_pos` will be the last cell `i` where `s_i` was 'R'.
        // The final jump is from `current_pos` to `n+1`.
        // The distance is `(n+1) - current_pos`. Update `max_gap` one last time.

        int current_right_jump_pos = 0; // This is the cell number. Initially 0.
        for (int k = 0; k < n; ++k) {
            if (s[k] == 'R') {
                // Cell k+1 allows right jumps.
                // The gap is from current_right_jump_pos to k+1.
                max_gap = std::max(max_gap, (k + 1) - current_right_jump_pos);
                current_right_jump_pos = k + 1;
            }
        }
        // After the loop, current_right_jump_pos is the last cell that allowed a right jump.
        // Now calculate the gap from this last right-jump-enabling cell to the target n+1.
        max_gap = std::max(max_gap, (n + 1) - current_right_jump_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // We want to divide this into n equal pieces, so each piece has area A_piece = A_total / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // By similar triangles, the base of the smaller triangle formed by this cut is b_x = x / h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // The i-th cut (x_i) should be such that the area of the triangle from the apex to x_i
    // is equal to i times the area of one piece.
    // A_{x_i} = i * A_piece
    // x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

