    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost of a 1-stair staircase
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            // Calculate cost for the next staircase.
            // If current staircase has k stairs, its cost is (2^k - 1) * (2^k) / 2.
            // The next staircase will have 2k+1 stairs.
            // Its cost is (2^(k+1) - 1) * (2^(k+1)) / 2.
            // The difference in number of stairs is 2^(k+1) - 1 - (2^k - 1) = 2^k.
            // The cost of a staircase with N stairs is N*(N+1)/2.
            // The sequence of N for nice staircases is 1, 3, 7, 15, ... which is 2^k - 1.
            // So, for k=1, N=1. Cost = 1*(2)/2 = 1.
            // For k=2, N=3. Cost = 3*(4)/2 = 6.
            // For k=3, N=7. Cost = 7*(8)/2 = 28.
            // The cost of the (k+1)-th nice staircase (which has 2^(k+1)-1 stairs)
            // is (2^(k+1)-1) * (2^(k+1))/2.
            // Let N_k = 2^k - 1. The cost is N_k * (N_k+1) / 2.
            // The next N is N_{k+1} = 2^(k+1) - 1.
            // The cost of the next staircase is N_{k+1} * (N_{k+1}+1) / 2.
            // The problem asks for the cost of the *next* staircase in the sequence of nice staircases.
            // The sequence of costs is 1, 6, 28, 120, ...
            // The current_cost is the cost of the staircase we just built.
            // The next staircase will have N_next = 2 * N_current + 1 stairs.
            // Its cost will be N_next * (N_next + 1) / 2.
            // Let's re-evaluate the sequence of costs.
            // N=1: cost = 1.
            // N=3: cost = 6.
            // N=7: cost = 28.
            // N=15: cost = 120.
            // The cost of the (k+1)-th staircase in the sequence of nice staircases
            // is (2^(k+1)-1) * (2^(k+1))/2.
            // The current_cost is (2^k-1) * (2^k)/2.
            // The next cost is (2^(k+1)-1) * (2^(k+1))/2.
            // This can be written as (2 * (2^k) - 1) * (2 * (2^k)) / 2.
            // Let P = 2^k. Then current_cost = (P-1)*P/2.
            // Next cost = (2P-1)*2P/2 = (2P-1)*P.
            // So, if current_cost = (P-1)*P/2, then P = (sqrt(8*current_cost + 1) + 1) / 2.
            // This is too complex.
            // Let's use the observation that the number of stairs for nice staircases are 1, 3, 7, 15, ...
            // which are of the form 2^k - 1.
            // Let N_k = 2^k - 1. The cost is C_k = N_k * (N_k + 1) / 2.
            // C_1 = 1 * 2 / 2 = 1.
            // C_2 = 3 * 4 / 2 = 6.
            // C_3 = 7 * 8 / 2 = 28.
            // C_4 = 15 * 16 / 2 = 120.
            // The current_cost variable holds C_k. We need to calculate C_{k+1}.
            // N_{k+1} = 2 * N_k + 1.
            // C_{k+1} = N_{k+1} * (N_{k+1} + 1) / 2.
            // Let's track N_k directly.
            // Initial N_k = 1. current_cost = 1.
            // Next N_k = 2 * 1 + 1 = 3. Next cost = 3 * 4 / 2 = 6.
            // Next N_k = 2 * 3 + 1 = 7. Next cost = 7 * 8 / 2 = 28.
            // This is the correct sequence.
            // The current_cost variable is the cost of the staircase we just "built".
            // We need to calculate the cost of the *next* staircase.
            // The number of stairs for the staircase we just built is N_current.
            // The number of stairs for the next staircase is N_next = 2 * N_current + 1.
            // The cost of the next staircase is N_next * (N_next + 1) / 2.
            // Let's track N_current.
            // Initially, N_current = 1.
            // After building the first staircase (cost 1), N_current becomes 3.
            // After building the second staircase (cost 6), N_current becomes 7.
            // And so on.
            // So, if current_cost is the cost of the staircase with N_current stairs,
            // then the next staircase will have N_next = 2 * N_current + 1 stairs.
            // Its cost will be N_next * (N_next + 1) / 2.
            // We can derive N_current from current_cost:
            // current_cost = N_current * (N_current + 1) / 2
            // 2 * current_cost = N_current^2 + N_current
            // N_current^2 + N_current - 2 * current_cost = 0
            // N_current = (-1 + sqrt(1 - 4 * 1 * (-2 * current_cost))) / 2
            // N_current = (-1 + sqrt(1 + 8 * current_cost)) / 2
            // This is too slow due to sqrt.
            // Let's track N_current directly.
            // Let N_stairs be the number of stairs for the staircase we are *currently considering* to build.
            // Initially, N_stairs = 1.
            // Cost = N_stairs * (N_stairs + 1) / 2 = 1 * 2 / 2 = 1.
            // If x >= 1, build it. x -= 1. count = 1.
            // Next N_stairs = 2 * 1 + 1 = 3.
            // Cost = 3 * 4 / 2 = 6.
            // If x >= 6, build it. x -= 6. count = 2.
            // Next N_stairs = 2 * 3 + 1 = 7.
            // Cost = 7 * 8 / 2 = 28.
            // This is the correct logic.

            // Let's use `num_stairs` to track N_k.
            // Initially, `num_stairs` is 1.
            // `current_cost` is `num_stairs * (num_stairs + 1) / 2`.
            // After building, update `num_stairs` for the *next* staircase.
            long long num_stairs = (-1 + static_cast<long long>(std::sqrt(1 + 8 * current_cost))) / 2;
            num_stairs = 2 * num_stairs + 1;
            current_cost = num_stairs * (num_stairs + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0 && open_needed < close_needed) {
            // Only add ')' if it can be matched by a preceding '('
            // and we still need closing brackets.
            // The condition open_needed < close_needed ensures that
            // the number of '(' already added to result is greater than
            // the number of ')' already added to result.
            // Specifically, if we have added `k/2 - open_needed` '(' and
            // `k/2 - close_needed` ')', then we need
            // `k/2 - open_needed > k/2 - close_needed`
            // which simplifies to `open_needed < close_needed`.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This `i` is the start of the first non-increasing segment from the right.
    int i = n - 1;
    while (i > 0 && a[i - 1] >= a[i]) {
        i--;
    }
    // Now `i` is the first index from the right where a[i-1] < a[i] (if such exists)
    // or `i` is 0 if the whole array is non-decreasing from the right.
    // The segment a[i...n-1] is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j-1]
    // This `j` is the start of the first non-decreasing segment from the right,
    // after the non-increasing segment.
    int j = i;
    while (j > 0 && a[j - 1] <= a[j]) {
        j--;
    }
    // Now `j` is the first index from the right where a[j-1] > a[j] (if such exists)
    // or `j` is 0 if the whole array is non-increasing from the right.
    // The segment a[j...i-1] is non-increasing.

    std::cout << j << std::endl;
}

