    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest difference we want to generate is k.
                       // This means we use numbers from 1 to k+1 to generate differences 1 to k.

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences using numbers 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order.
    // The differences generated by these appended numbers will be 1.
    // For example, if p[k] is `x`, then p[k+1] = `x+1`, p[k+2] = `x+2`, etc.
    // The differences will be `| (x+1) - x | = 1`, `| (x+2) - (x+1) | = 1`, etc.
    // Since 1 is already among the k distinct differences (unless k=0, but k>=1),
    // this does not introduce new distinct differences.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be the next available number in sequence
                      // if we consider numbers 1 to n.
                      // The numbers used so far are 1 to k+1.
                      // So the next available number is k+2.
                      // p[k+1] = k+2, p[k+2] = k+3, ..., p[n-1] = n.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

