int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            // Discriminant D = d^2 - 4d
            // a = (d + sqrt(D)) / 2
            // b = (d - sqrt(D)) / 2
            // Or vice versa. Since a and b are symmetric, the order doesn't matter.
            // We need a, b >= 0.
            // d >= 4 ensures d^2 - 4d >= 0, so sqrt(D) is real.
            // d + sqrt(D) is clearly >= 0.
            // d - sqrt(D) >= 0 needs to be checked.
            // d - sqrt(d^2 - 4d) >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, we can square both sides)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So both a and b will be non-negative.

            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the segment is just [1]. This is always beautiful.
    // The segment is p[pos[1]...pos[1]], min=1, max=1, length=1.
    result[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the current segment to include 'm'
        // 'm' is at pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx ... current_max_idx]
        // is a permutation of 1, 2, ..., m.
        // This requires its length to be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

