    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, ensure the median element itself is s.
    // This is a mandatory cost.
    operations += std::abs(a[median_idx] - s);

    // Then, ensure elements to the left of the median are <= s.
    // If a[i] > s for i < median_idx, we must decrease it to s.
    // This is because if we decrease it to something < s, it might still be > a[median_idx] (which is now s)
    // or it might become < s but then we'd need to increase it to s to satisfy the condition.
    // The minimum cost to make a[i] <= s is to change it to s if a[i] > s.
    // If a[i] <= s, no change is needed for this condition.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Finally, ensure elements to the right of the median are >= s.
    // If a[i] < s for i > median_idx, we must increase it to s.
    // Similar logic: minimum cost to make a[i] >= s is to change it to s if a[i] < s.
    // If a[i] >= s, no change is needed for this condition.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

