    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original array elements (the 'a' array elements)
        // We are trying to find an element a[j] from the sorted array
        // that is strictly greater than a[i].
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j
        // will also be > a[i] (or equal if a[k] == a[j]).
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // to save larger elements for larger a[i] values later.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element in 'b' array for the next match
        } else {
            // No more elements in 'b' array are greater than a[i]
            // Since 'a' is sorted, no subsequent a[k] (k > i) will find a match either.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (seen_prefix[a[i]]) {
            distinct_prefix = false;
            break;
        }
        seen_prefix[a[i]] = true;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_prefix && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (seen_suffix[a[i]]) {
            distinct_suffix = false;
            break;
        }
        seen_suffix[a[i]] = true;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_suffix && max_val_suffix == (n - i)) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

