#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_val[i] = maximum possible value for a[i]
    // such that a[0] < a[1] < ... < a[i] can be formed.
    // This means a[j] >= j for j <= i.
    // So, a[i] must be at least i.
    // And a[i] must be at least a[i-1]+1.
    // The actual value of a[i] can be at most the original a[i].
    // So, max_left_val[i] = min(original_a[i], max_left_val[i-1]+1)
    // with base case max_left_val[0] = original_a[0].
    // However, we are interested in the minimum possible value for a[i]
    // to satisfy the increasing condition.
    // Let's define `left_min_req[i]` as the minimum value `a[i]` must take
    // to satisfy `a[0] < a[1] < ... < a[i]`.
    // `left_min_req[0] = 0` (since `a[0]` can be `0`)
    // `left_min_req[i] = left_min_req[i-1] + 1`.
    // If `a[i]` (original) is less than `left_min_req[i]`, then it's impossible
    // to make `a[0] < ... < a[i]` without increasing `a[i]`, which is not allowed.
    // So, we need `a[i] >= i` for all `i` in the increasing part.
    // This means `a[i]` must be at least `i`.
    // We can find the longest prefix `a[0], ..., a[L-1]` such that `a[i] >= i` for all `i < L`.
    int L = 0;
    while (L < n && a[L] >= L) {
        L++;
    }
    // L is now the first index where a[L] < L, or L == n.
    // So, a[0], ..., a[L-1] can potentially form the increasing part.

    // Similarly, for the decreasing part: `a[k] > a[k+1] > ... > a[n-1]`.
    // This means `a[j]` must be at least `n-1-j` for `j >= k`.
    // We can find the longest suffix `a[R], ..., a[n-1]` such that `a[j] >= n-1-j` for all `j >= R`.
    int R = n - 1;
    while (R >= 0 && a[R] >= (n - 1 - R)) {
        R--;
    }
    // R is now the last index where a[R] < n-1-R, or R == -1.
    // So, a[R+1], ..., a[n-1] can potentially form the decreasing part.

    // If there is a peak `k`, then `k` must be in the range `[0, L-1]` (from increasing part)
    // and `k` must be in the range `[R+1, n-1]` (from decreasing part).
    // This means there must be at least one index `k` such that `a[k] >= k` AND `a[k] >= n-1-k`.
    // The indices that satisfy `a[i] >= i` are `0, ..., L-1`.
    // The indices that satisfy `a[i] >= n-1-i` are `R+1, ..., n-1`.
    // We need to find if there's an overlap between these two ranges.
    // The overlap exists if `L-1 >= R+1`.
    // Or, more simply, if `L > R`.
    // If `L > R`, it means there is at least one index `i` such that `i < L` and `i > R`.
    // For such an `i`, `a[i] >= i` and `a[i] >= n-1-i`.
    // This `i` can be our peak `k`.
    // For example, if `L=3` and `R=0`, then `L > R`.
    // Indices `0,1,2` satisfy `a[i] >= i`.
    // Indices `1,2,...,n-1` satisfy `a[i] >= n-1-i`.
    // Index `1` and `2` are in both. We can pick `k=1` or `k=2`.
    // If `L=3` and `R=2`, then `L > R`.
    // Indices `0,1,2` satisfy `a[i] >= i`.
    // Indices `3,...,n-1` satisfy `a[i] >= n-1-i`.
    // No overlap. This is `L-1 < R+1`.
    // The condition `L > R` means that the range `[0, L-1]` and `[R+1, n-1]` have at least one common index.
    // The common indices are `max(0, R+1)` to `min(n-1, L-1)`.
    // This range is non-empty if `max(0, R+1) <= min(n-1, L-1)`.
    // Since `0 <= R+1` and `L-1 <= n-1` (assuming `n >= 1`), this simplifies to `R+1 <= L-1`.
    // Which is `R+2 <= L`.
    // Wait, `L` is the first index where `a[L] < L`. So `a[0]...a[L-1]` satisfy `a[i] >= i`.
    // `R` is the last index where `a[R] < n-1-R`. So `a[R+1]...a[n-1]` satisfy `a[i] >= n-1-i`.
    // We need to find an index `k` such that `k` is in `[0, L-1]` AND `k` is in `[R+1, n-1]`.
    // This means `R+1 <= k <= L-1`.
    // Such a `k` exists if and only if `R+1 <= L-1`.
    // Which is `R+2 <= L`.

    // Let's re-evaluate the ranges.
    // `L` is the count of elements from the left that satisfy the condition.
    // So, `a[0], ..., a[L-1]` satisfy `a[i] >= i`.
    // `R` is the count of elements from the right that satisfy the condition.
    // So, `a[n-R], ..., a[n-1]` satisfy `a[j] >= n-1-j`.
    // Example: n=6, a=[100, 11, 15, 9, 7, 8]
    // Left scan:
    // a[0]=100 >= 0
    // a[1]=11 >= 1
    // a[2]=15 >= 2
    // a[3]=9 >= 3
    // a[4]=7 >= 4
    // a[5]=8 >= 5
    // L=6. All elements satisfy a[i] >= i.
    // Right scan:
    // a[5]=8 >= 6-1-5=0
    // a[4]=7 >= 6-1-4=1
    // a[3]=9 >= 6-1-3=2
    // a[2]=15 >= 6-1-2=3
    // a[1]=11 >= 6-1-1=4
    // a[0]=100 >= 6-1-0=5
    // R=6. All elements satisfy a[i] >= n-1-i.
    // In this case, L=6, R=6.
    // The indices that can be a peak are `0, ..., L-1` and `n-R, ..., n-1`.
    // So, `0, ..., 5` and `0, ..., 5`.
    // The intersection is `[0, 5]`. Any `k` in this range works.
    // The condition for existence of such `k` is `L + R > n`.
    // If `L=6, R=6, n=6`, then `6+6 > 6` is true. So "Yes".

    // Let's re-check the definition of L and R.
    // L: number of elements from the left that satisfy `a[i] >= i`.
    // `a[0] >= 0, a[1] >= 1, ..., a[L-1] >= L-1`.
    // R: number of elements from the right that satisfy `a[i] >= n-1-i`.
    // `a[n-1] >= 0, a[n-2] >= 1, ..., a[n-R] >= R-1`.
    // We need to find an index `k` such that `a[k] >= k` AND `a[k] >= n-1-k`.
    // The indices `i` for which `a[i] >= i` are `0, 1, ..., L-1`.
    // The indices `j` for which `a[j] >= n-1-j` are `n-R, n-R+1, ..., n-1`.
    // We need to find if there is an overlap between `[0, L-1]` and `[n-R, n-1]`.
    // An overlap exists if `L-1 >= n-R`.
    // This simplifies to `L + R >= n + 1`.

    // Let's test with examples:
    // n=1, a=[248618]
    // L=1 (a[0]=248618 >= 0)
    // R=1 (a[0]=248618 >= 0)
    // L+R >= n+1 => 1+1 >= 1+1 => 2 >= 2. True. Output: Yes. Correct.

    // n=3, a=[12, 10, 8]
    // L: a[0]=12>=0, a[1]=10>=1, a[2]=8>=2. L=3.
    // R: a[2]=8>=0, a[1]=10>=1, a[0]=12>=2. R=3.
    // L+R >= n+1 => 3+3 >= 3+1 => 6 >= 4. True. Output: Yes. Correct.

    // n=6, a=[100, 11, 15, 9, 7, 8]
    // L: a[0]=100>=0, a[1]=11>=1, a[2]=15>=2, a[3]=9>=3, a[4]=7>=4, a[5]=8>=5. L=6.
    // R: a[5]=8>=0, a[4]=7>=1, a[3]=9>=2, a[2]=15>=3, a[1]=11>=4, a[0]=100>=5. R=6.
    // L+R >= n+1 => 6+6 >= 6+1 => 12 >= 7. True. Output: Yes. Correct.

    // n=4, a=[0, 1, 1, 0]
    // L: a[0]=0>=0, a[1]=1>=1. a[2]=1 < 2. So L=2.
    // R: a[3]=0>=0. a[2]=1>=1. a[1]=1 < 2. So R=2. (a[3], a[2] satisfy)
    // L+R >= n+1 => 2+2 >= 4+1 => 4 >= 5. False. Output: No. Correct.

    // n=2, a=[0, 0]
    // L: a[0]=0>=0. a[1]=0 < 1. So L=1.
    // R: a[1]=0>=0. a[0]=0 < 1. So R=1.
    // L+R >= n+1 => 1+1 >= 2+1 => 2 >= 3. False. Output: No. Correct.

    // n=2, a=[0, 1]
    // L: a[0]=0>=0, a[1]=1>=1. L=2.
    // R: a[1]=1>=0, a[0]=0 < 1. So R=1.
    // L+R >= n+1 => 2+1 >= 2+1 => 3 >= 3. True. Output: Yes. Correct.

    // n=2, a=[1, 0]
    // L: a[0]=1>=0. a[1]=0 < 1. So L=1.
    // R: a[1]=0>=0, a[0]=1>=1. L=2.
    // L+R >= n+1 => 1+2 >= 2+1 => 3 >= 3. True. Output: Yes. Correct.

    // n=2, a=[1, 1]
    // L: a[0]=1>=0, a[1]=1>=1. L=2.
    // R: a[1]=1>=0, a[0]=1>=1. R=2.
    // L+R >= n+1 => 2+2 >= 2+1 => 4 >= 3. True. Output: Yes. Correct.

    // n=3, a=[0, 1, 0]
    // L: a[0]=0>=0, a[1]=1>=1. a[2]=0 < 2. So L=2.
    // R: a[2]=0>=0, a[1]=1>=1. a[0]=0 < 2. So R=2.
    // L+R >= n+1 => 2+2 >= 3+1 => 4 >= 4. True. Output: Yes. Correct.

    // n=3, a=[1, 0, 1]
    // L: a[0]=1>=0. a[1]=0 < 1. So L=1.
    // R: a[2]=1>=0, a[1]=0 < 1. So R=1.
    // L+R >= n+1 => 1+1 >= 3+1 => 2 >= 4. False. Output: No. Correct.

    // The logic seems solid.

    int current_L = 0;
    while (current_L < n && a[current_L] >= current_L) {
        current_L++;
    }

    int current_R = 0;
    while (current_R < n && a[n - 1 - current_R] >= current_R) {
        current_R++;
    }

    if (current_L + current_R >= n + 1) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

