char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking
        // R, P, S is one such order.
        // The problem statement implies any optimal answer is fine.
        // Let's use R, P, S for iteration.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_move = 'R';
        }
        if (counts['P'] > max_count) { // P vs R tie-break: P wins
            max_count = counts['P'];
            most_frequent_move = 'P';
        }
        if (counts['S'] > max_count) { // S vs P tie-break: S wins
            max_count = counts['S'];
            most_frequent_move = 'S';
        }

        // If all counts are 0 (empty string, not possible by constraints n>=1),
        // or if there's only one type of character, this logic still works.
        // If multiple characters have the same max_count, any of them is fine.
        // The current logic picks 'S' if 'S' has max_count and 'P' has same max_count, etc.
        // Example: R=1, P=1, S=1 -> most_frequent_move = 'S'
        // Example: R=2, P=1, S=1 -> most_frequent_move = 'R'
        // Example: R=1, P=2, S=1 -> most_frequent_move = 'P'

        char optimal_player_move = get_winning_move(most_frequent_move);

        for (size_t i = 0; i < s.length(); ++i) {
            std::cout << optimal_player_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Mr. Chanek's turn
            if (n % 2 == 1) {
                // N is odd. Only option is to take 1.
                chanek_coins += 1;
                n -= 1;
            } else {
                // N is even. Two options: take 1 or take N/2.
                // If N is 2, taking 1 leaves 1 for opponent, opponent takes 1. Chanek gets 1.
                // If N is 2, taking N/2 leaves 1 for opponent, opponent takes 1. Chanek gets 1.
                // So for N=2, both moves yield 1 for Chanek.
                if (n == 2) {
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) {
                    // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // This seems good for Chanek.
                    // Example: N=6. Take 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If N=6. Take 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // In this case, taking N/2 is better or equal.
                    // The only case where taking N/2 is bad is if N/2 is a power of 2, and N/2 is even.
                    // E.g., N=8. Take 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 4+1=5. Opponent: 2+1=3.
                    // If N=8. Take 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    // It seems taking N/2 is always optimal if N/2 is odd.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // (n / 2) % 2 == 0, i.e., N is a multiple of 4.
                    // If N/2 is even, taking N/2 leaves an even number for opponent.
                    // Opponent might take N/4, which is good for opponent.
                    // Example: N=4. Take 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 2+1=3. Opponent: 1.
                    // If N=4. Take 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+1=2. Opponent: 1+1=2.
                    // Here, taking N/2 is better.
                    //
                    // The only time taking 1 is better is if N is a power of 2, and N > 2.
                    // For N = 2^k (k > 1):
                    // If Chanek takes N/2 = 2^(k-1):
                    //   Chanek gets 2^(k-1). Remaining N=2^(k-1). Opponent's turn.
                    //   Opponent will take 2^(k-2). Remaining N=2^(k-2). Chanek's turn.
                    //   ... This continues until N=2.
                    //   Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1 (if k is even) or 2^0 (if k is odd).
                    //   Opponent gets 2^(k-2) + 2^(k-4) + ... + 2^0 (if k is even) or 2^1 (if k is odd).
                    // If Chanek takes 1:
                    //   Chanek gets 1. Remaining N=2^k-1 (odd). Opponent's turn.
                    //   Opponent takes 1. Remaining N=2^k-2 (even). Chanek's turn.
                    //   Chanek takes (2^k-2)/2 = 2^(k-1)-1. Remaining N=2^(k-1)-1 (odd). Opponent's turn.
                    //   ... This seems complicated.
                    //
                    // Let's re-evaluate the greedy strategy:
                    // If N is odd, take 1.
                    // If N is even:
                    //   If N is a power of 2 (N = 2^k, k >= 1):
                    //     If N=2, take 1. Chanek gets 1. Opponent gets 1.
                    //     If N=4, take 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2. Opponent: 1+1=2.
                    //     If N=4, take 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                    //     So for N=4, take N/2.
                    //     If N=8, take 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //     Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    //     If N=8, take 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //     Chanek: 4+1=5. Opponent: 2+1=3.
                    //     It seems for powers of 2, both moves give the same result for Chanek.
                    //     The problem is that taking 1 makes N odd, which forces opponent to take 1.
                    //     Taking N/2 makes N even, which allows opponent to take N/4.
                    //
                    // The optimal strategy for Chanek when N is even:
                    // If N is a power of 2 (N = 2^k, k >= 1):
                    //   Take 1. This leaves N-1 (odd). Opponent must take 1. Then N-2 (even).
                    //   This forces opponent to take 1, which is good for Chanek.
                    //   Example N=8. Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //   Chanek: 1+3+1=5. Opponent: 1+1+1=3.
                    //   If Chanek takes N/2=4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //   Chanek: 4+1=5. Opponent: 2+1=3.
                    //   It seems for powers of 2, both moves yield the same result for Chanek.
                    //   So, if N is a power of 2, taking 1 is simpler.
                    //
                    // If N is even but not a power of 2:
                    //   N = 2^k * M, where M is odd and M > 1.
                    //   Take N/2. This leaves N/2 = 2^(k-1) * M.
                    //   This is generally better because Chanek gets more coins upfront.
                    //   Example N=6. Take 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    //   Chanek: 3+1=4. Opponent: 1+1=2.
                    //   If N=6. Take 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    //   Chanek: 1+2+1=4. Opponent: 1+1=2.
                    //   Both yield same result.
                    //
                    // The strategy seems to be:
                    // If N is odd, take 1.
                    // If N is even:
                    //   If N is a power of 2 (N = 2^k, k >= 1): take 1.
                    //   If N is even but not a power of 2: take N/2.
                    //
                    // Let's check if N is a power of 2.
                    // A number x is a power of 2 if (x > 0) and ((x & (x - 1)) == 0).
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    } else { // N is even but not a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    }
                }
            }
        } else {
            // Opponent's turn
            if (n % 2 == 1) {
                // N is odd. Only option is to take 1.
                opponent_coins += 1;
                n -= 1;
            } else {
                // N is even. Two options: take 1 or take N/2.
                // Opponent also plays optimally to maximize their own coins.
                // So opponent uses the same logic as Chanek.
                if (n == 2) {
                    opponent_coins += 1;
                    n -= 1;
                } else if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += 1;
                    n -= 1;
                } else { // N is even but not a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

