int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually need to pass this 'b'.
            // Each 'a' to its left will contribute to the total steps.
            // The number of 'a's that need to pass this 'b' is `count_a`.
            // When an 'a' passes a 'b', it effectively doubles the number of 'a's
            // that need to pass the *next* 'b' to its left.
            // So, `count_a` doubles for the next 'b' encountered.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to pass all 'b's to its right.
            // It adds 1 to the current count of 'a's that are waiting
            // to pass 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

