int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert an integer to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding with '0's (even digits) from the left in the number's decimal representation
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Map to store counts of each 18-digit parity pattern
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern with '0's to make it 18 characters long
            // This corresponds to padding with '0's (even digits) from the left in the number's decimal representation
            while (s.length() < 18) {
                s = '0' + s;
            }

            // The map key is the pattern string where digits are from right to left.
            // So, the query pattern needs to be reversed to match the map key format.
            std::reverse(s.begin(), s.end());

            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
