int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        int m = n - k; // m is the number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - m]) * r;

        // Extra energy based on counts
        if (k > m) { // More items from left than right
            current_energy += (k - m - 1) * Ql;
        } else if (m > k) { // More items from right than left
            current_energy += (m - k - 1) * Qr;
        }
        // If k == m, no extra cost

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

