void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        int last1 = -1;
        int last2 = -1;
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            int current_digit = s[i] - '0';

            bool can_be_1 = (current_digit >= last1);
            bool can_be_2 = (current_digit >= last2);

            if (current_digit < pivot_digit) { // Must be color 1
                if (can_be_1) {
                    result[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            } else if (current_digit > pivot_digit) { // Must be color 2
                if (can_be_2) {
                    result[i] = '2';
                    last2 = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            } else { // current_digit == pivot_digit
                // Try to put it in color 1 if possible and it maintains sorted order for color 1
                // and it's less than or equal to the first element of color 2 (which is pivot_digit)
                // This is equivalent to checking if it can be color 1 and last1 <= pivot_digit
                if (can_be_1 && current_digit <= pivot_digit) { // current_digit == pivot_digit, so current_digit <= pivot_digit is always true
                    result[i] = '1';
                    last1 = current_digit;
                } else if (can_be_2) { // Otherwise, try color 2
                    result[i] = '2';
                    last2 = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            // Final check: last1 must be <= first element of S2.
            // The first element of S2 will be >= pivot_digit.
            // If last1 is <= pivot_digit, then it's fine.
            // If last1 > pivot_digit, then it's not fine.
            // Our logic for assigning pivot_digit to color 1 ensures last1 <= pivot_digit if assigned to 1.
            // Our logic for assigning pivot_digit to color 2 ensures last2 >= pivot_digit if assigned to 2.
            // So, if a solution is found, it should be valid.
            std::cout << result << "\n";
            found_solution = true;
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

