// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be divisible by q.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then for every fi, the exponent of fi in x must be >= ai.
        // So, x % q != 0 means there is at least one fi such that the exponent of fi in x is < ai.

        // We want to maximize x.
        // Consider p = P * q.
        // We are looking for x = p / (f_j^k) for some prime factor f_j of q,
        // such that p / (f_j^k) is not divisible by q, and this x is maximized.
        // To maximize x, we need to divide p by the smallest possible factor that makes it not divisible by q.
        // This factor will be some power of a prime factor of q.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : prime_factors_q) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // Or, more precisely, divide current_p by f until the power of f in current_p
            // is less than the power of f in q.

            // Calculate the power of f in q
            long long q_val = q;
            int count_f_in_q = 0;
            while (q_val > 0 && q_val % f == 0) {
                count_f_in_q++;
                q_val /= f;
            }

            // Calculate the power of f in p
            long long p_val = p;
            int count_f_in_p = 0;
            while (p_val > 0 && p_val % f == 0) {
                count_f_in_p++;
                p_val /= f;
            }

            // We need to reduce the power of f in p such that it becomes less than count_f_in_q.
            // The smallest power of f to divide p by is f^(count_f_in_p - count_f_in_q + 1).
            // This ensures that the resulting number has power of f equal to count_f_in_q - 1,
            // which is less than count_f_in_q.

            long long divisor_power = 1;
            for(int i = 0; i < count_f_in_p - count_f_in_q + 1; ++i) {
                divisor_power *= f;
            }

            max_x = std::max(max_x, p / divisor_power);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r: S_r = sum_{r=1}^{b-1} r
    // S_r = (b-1) * b / 2
    long long sum_r = (b - 1);
    sum_r = (sum_r * b) % MOD;
    sum_r = (sum_r * modInverse(2)) % MOD;

    // Sum of k: S_k = sum_{k=1}^{a} k
    // S_k = a * (a+1) / 2
    long long sum_k = a;
    sum_k = (sum_k * (a + 1)) % MOD;
    sum_k = (sum_k * modInverse(2)) % MOD;

    // The total sum is sum_{k=1}^{a} sum_{r=1}^{b-1} r * (k*b + 1)
    // = sum_{k=1}^{a} sum_{r=1}^{b-1} (r*k*b + r)
    // = sum_{k=1}^{a} (k*b * sum_{r=1}^{b-1} r + sum_{r=1}^{b-1} r)
    // = sum_{k=1}^{a} (k*b + 1) * sum_{r=1}^{b-1} r
    // = (sum_{k=1}^{a} (k*b + 1)) * sum_{r=1}^{b-1} r
    //
    // Let's calculate sum_{k=1}^{a} (k*b + 1)
    // = sum_{k=1}^{a} (k*b) + sum_{k=1}^{a} 1
    // = b * sum_{k=1}^{a} k + a
    // = b * S_k + a

    long long term_kb_plus_1_sum = (b * sum_k) % MOD;
    term_kb_plus_1_sum = (term_kb_plus_1_sum + a) % MOD;

    long long total_sum = (term_kb_plus_1_sum * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_val = current_val;
        int block_end_idx = std::min(i + k, n);
        for (int j = block_end_idx - 1; j >= i; --j) {
            p[j] = block_start_val - (block_end_idx - 1 - j);
        }
        current_val -= (block_end_idx - i);
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> next_char_indices(L, std::vector<int>(26, -1));
    for (int i = 0; i < L; ++i) {
        for (int j = 0; j < 26; ++j) {
            for (int k = 1; k < L; ++k) {
                if (s[(i + k) % L] == 'a' + j) {
                    next_char_indices[i][j] = k;
                    break;
                }
            }
        }
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char t0_char = s[k_actual]; // t[0] = s[k_actual]

        // Vasya's strategy: choose p to maximize win probability for this t0_char
        double max_win_prob_for_t0 = 0.0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            char tp_char = s[(k_actual + p) % L]; // t[p] = s[(k_actual + p) % L]

            int count_matching_k = 0;
            for (int k_candidate = 0; k_candidate < L; ++k_candidate) {
                if (s[k_candidate] == t0_char && s[(k_candidate + p) % L] == tp_char) {
                    count_matching_k++;
                }
            }

            if (count_matching_k == 1) {
                max_win_prob_for_t0 = std::max(max_win_prob_for_t0, 1.0);
            } else {
                // If multiple k_candidates match, Vasya needs to distinguish them.
                // He can only win if for *all* other k_candidates, there's a position
                // where they differ from k_actual.
                // This is equivalent to checking if k_actual is the *only* k_candidate
                // that matches t0_char and tp_char.
                // If count_matching_k > 1, Vasya loses for this (t0_char, tp_char) pair.
                // So, the probability of winning for this (t0_char, tp_char) is 0.
                // The max_win_prob_for_t0 will be updated if a p leads to count_matching_k == 1.
            }
        }
        total_win_prob += max_win_prob_for_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false); // 'a' -> 0, 'b' -> 1, ...

    // Find a starting point: a character with only one required neighbor (an endpoint of a segment)
    // Or if all characters in password have two neighbors, pick the first char of password.
    // Or if password is empty/single char, pick 'a'.
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in password have 0 or 2 neighbors.
    // If all have 0 neighbors, password is empty or single char.
    // If all have 2 neighbors, it means it forms a cycle or multiple disjoint cycles.
    // A cycle is impossible on a linear keyboard.
    // However, the problem statement implies we are building a path.
    // If all chars in password have 2 neighbors, and it's not a cycle, it means it's a path
    // where the endpoints are not part of the password, or the password itself is a cycle.
    // The only way for all chars in password to have 2 neighbors and be valid is if the password
    // forms a single path, and we pick one of its endpoints as start_char.
    // If start_char is still '\0', it means all chars in password have 0 or 2 neighbors.
    // If there are any chars in the password, pick the first one as a potential start.
    if (start_char == '\0' && !s.empty()) {
        start_char = s[0];
    } else if (start_char == '\0' && s.empty()) { // Empty password case, though constraints say |s| >= 1
        start_char = 'a'; // Just pick 'a'
    }

    // Build the main path segment
    if (start_char != '\0') {
        char current_char = start_char;
        while (current_char != '\0' && !visited[current_char - 'a']) {
            layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (!visited[neighbor - 'a']) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check for cycles or disconnected components within the password-defined graph
    // If any character from the password is not in the layout, it means it's part of a disconnected component
    // or a cycle.
    for (char c : s) {
        if (!visited[c - 'a']) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unvisited characters to the layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited[c - 'a']) {
            layout += c;
        }
    }

    if (layout.length() != 26) {
        // This case should ideally not be reached if logic is correct,
        // but as a safeguard for unexpected graph structures.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_balance = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n).
    // We want to find a state where the remaining balance is 0.
    // Let L be the number of jars emptied from the left (0 to n-1 jars from index n down to 1)
    // Let R be the number of jars emptied from the right (0 to n-1 jars from index n+1 up to 2n)
    // The jars remaining are a[0...n-L-1] and a[n+R...2n-1].
    // The balance of jars a[0...n-L-1] is prefix_balance[n-L-1] (if n-L > 0)
    // The balance of jars a[n+R...2n-1] is suffix_balance[n+R] (if 2n-R > n)
    //
    // Let's define balance_left[k] as the balance of jars a[0...k-1] (i.e., k jars from the left).
    // Let's define balance_right[k] as the balance of jars a[2n-k...2n-1] (i.e., k jars from the right).
    //
    // The jars Karlsson keeps are a[0...n-L-1] and a[n+R...2n-1].
    // The total balance of remaining jars is (balance of a[0...n-L-1]) + (balance of a[n+R...2n-1]).
    //
    // Let's re-evaluate the balance calculation.
    // We want the final balance of remaining jars to be 0.
    // The initial total balance is `initial_balance`.
    // If Karlsson empties `L` jars from the left (jars `n`, `n-1`, ..., `n-L+1`)
    // and `R` jars from the right (jars `n+1`, `n+2`, ..., `n+R`),
    // the remaining jars are `a[0...n-L-1]` and `a[n+R...2n-1]`.
    //
    // Let `bal_left_prefix[k]` be the balance of jars `a[0...k-1]`.
    // Let `bal_right_suffix[k]` be the balance of jars `a[2n-k...2n-1]`.
    //
    // The balance of jars `a[0...n-L-1]` is `bal_left_prefix[n-L]`.
    // The balance of jars `a[n+R...2n-1]` is `bal_right_suffix[n-R]`.
    //
    // The total balance of remaining jars is `bal_left_prefix[n-L] + bal_right_suffix[n-R]`.
    // We want this to be 0.
    //
    // Let's define `bal_left_removed[k]` as the balance of jars `a[n-k...n-1]` (k jars removed from left side).
    // Let `bal_right_removed[k]` as the balance of jars `a[n...n+k-1]` (k jars removed from right side).
    //
    // The total balance of all jars is `initial_balance`.
    // If we remove `L` jars from the left and `R` jars from the right,
    // the balance of removed jars is `bal_left_removed[L] + bal_right_removed[R]`.
    // The balance of remaining jars is `initial_balance - (bal_left_removed[L] + bal_right_removed[R])`.
    // We want `initial_balance - (bal_left_removed[L] + bal_right_removed[R]) = 0`.
    // This means `bal_left_removed[L] + bal_right_removed[R] = initial_balance`.
    //
    // Let's compute `bal_left_removed[k]` for `k` from `0` to `n`.
    // `bal_left_removed[0] = 0`.
    // For `k > 0`, `bal_left_removed[k]` is `bal_left_removed[k-1]` plus the balance of jar `a[n-k]`.
    //
    // Let's compute `bal_right_removed[k]` for `k` from `0` to `n`.
    // `bal_right_removed[0] = 0`.
    // For `k > 0`, `bal_right_removed[k]` is `bal_right_removed[k-1]` plus the balance of jar `a[n+k-1]`.

    std::vector<int> bal_left_removed(n + 1, 0);
    for (int k = 1; k <= n; ++k) {
        bal_left_removed[k] = bal_left_removed[k - 1];
        if (a[n - k] == 1) {
            bal_left_removed[k]++;
        } else {
            bal_left_removed[k]--;
        }
    }

    std::vector<int> bal_right_removed(n + 1, 0);
    for (int k = 1; k <= n; ++k) {
        bal_right_removed[k] = bal_right_removed[k - 1];
        if (a[n + k - 1] == 1) {
            bal_right_removed[k]++;
        } else {
            bal_right_removed[k]--;
        }
    }

    // We need to find minimum L+R such that bal_left_removed[L] + bal_right_removed[R] = initial_balance.
    // Iterate over all possible L (0 to n).
    // For each L, we need to find an R such that bal_right_removed[R] = initial_balance - bal_left_removed[L].
    // To do this efficiently, we can precompute a map for bal_right_removed values.

    std::map<int, int> min_R_for_balance; // map: balance_value -> minimum R to achieve this balance
    for (int R = 0; R <= n; ++R) {
        int current_balance = bal_right_removed[R];
        if (min_R_for_balance.find(current_balance) == min_R_for_balance.end()) {
            min_R_for_balance[current_balance] = R;
        } else {
            // We want minimum R, so if we find a smaller R for the same balance, update it.
            // But we are iterating R from 0 to n, so the first R encountered for a balance is already the minimum.
            // No need to update.
        }
    }

    int min_total_removed = 2 * n; // Max possible jars to remove

    for (int L = 0; L <= n; ++L) {
        int target_right_balance = initial_balance - bal_left_removed[L];
        if (min_R_for_balance.count(target_right_balance)) {
            int R = min_R_for_balance[target_right_balance];
            min_total_removed = std::min(min_total_removed, L + R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and = 1023; // Represents the value that `x` is ANDed with
    int current_or = 0;    // Represents the value that `x` is ORed with
    int current_xor = 0;   // Represents the value that `x` is XORed with

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and &= val;
            current_or &= val;
            current_xor &= val;
        } else if (op_char == '|') {
            current_and |= val;
            current_or |= val;
            current_xor |= val;
        } else if (op_char == '^') {
            current_and ^= val;
            current_or ^= val;
            current_xor ^= val;
        }
    }

    // Now we have the final state for an input of 0, 1023, and 0 (for XOR)
    // Let's call the final state for input 0 as `f(0)`
    // Let's call the final state for input 1023 as `f(1023)`
    // Let's call the final state for input `x` as `f(x)`
    // We know that `f(0) = current_or` (because `0 & A = 0`, `0 | A = A`, `0 ^ A = A`)
    // We know that `f(1023) = current_and` (because `1023 & A = A`, `1023 | A = 1023`, `1023 ^ A = ~A` (within 10 bits))
    // The `current_xor` variable actually stores `f(0) ^ f(1023)` if we consider the effect on `0` and `1023` separately.
    // More precisely, `current_or` is `f(0)` and `current_and` is `f(1023)`.
    // The `current_xor` variable is `f(0) ^ f(1023)` if we consider the effect on `0` and `1023` separately.
    // No, `current_xor` is the value that `x` is XORed with *after* all AND/OR operations.
    // Let's re-evaluate.
    // `f(x) = (((x & A_1) | O_1) ^ X_1) ...`
    // The final transformation can be represented as `(x & A) | O ^ X`.
    // Let's find A, O, X.
    // `f(0) = (0 & A) | O ^ X = O ^ X`
    // `f(1023) = (1023 & A) | O ^ X = A | O ^ X`

    // The `current_or` variable stores `f(0)`.
    // The `current_and` variable stores `f(1023)`.
    // The `current_xor` variable stores `f(0) ^ f(1023)` if we consider the effect on `0` and `1023` separately.
    // No, this is not correct. The `current_xor` variable is the value that `x` is XORed with *after* all AND/OR operations.
    // Let's track the state of each bit.
    // For each bit `j` from 0 to 9:
    // Let `x_j` be the j-th bit of the input.
    // Let `a_j` be the j-th bit of `current_and`.
    // Let `o_j` be the j-th bit of `current_or`.
    // Let `c_j` be the j-th bit of `current_xor`.
    // The final j-th bit `res_j` is `((x_j & a_j) | o_j) ^ c_j`.
    // This is the form we want to achieve.
    // We need to find `A_final`, `O_final`, `X_final` such that `(x & A_final) | O_final ^ X_final` is equivalent.

    // Let's find the final `A`, `O`, `X` values.
    // `f(0)` is the result when input is 0.
    // `f(1023)` is the result when input is 1023.
    // `f(0)` is `current_or` (from the simulation).
    // `f(1023)` is `current_and` (from the simulation).

    // Let `res_0 = current_or`.
    // Let `res_1023 = current_and`.

    // For each bit `j`:
    // Let `x_j` be the input bit.
    // Let `r_j` be the output bit.
    // `r_j` can be one of four functions of `x_j`:
    // 1. `r_j = 0` (always 0)
    // 2. `r_j = 1` (always 1)
    // 3. `r_j = x_j` (identity)
    // 4. `r_j = ~x_j` (negation)

    // We can determine which function `r_j` is by looking at `res_0_j` and `res_1023_j`.
    // `res_0_j` is the j-th bit of `f(0)`.
    // `res_1023_j` is the j-th bit of `f(1023)`.

    // If `res_0_j = 0` and `res_1023_j = 0`, then `r_j = 0`.
    // If `res_0_j = 1` and `res_1023_j = 1`, then `r_j = 1`.
    // If `res_0_j = 0` and `res_1023_j = 1`, then `r_j = x_j`.
    // If `res_0_j = 1` and `res_1023_j = 0`, then `r_j = ~x_j`.

    // We want to represent this as `(x & A) | O ^ X`.
    // Let's find `A`, `O`, `X` bit by bit.
    int final_A = 0;
    int final_O = 0;
    int final_X = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_0 = (current_or >> j) & 1;
        int bit_1023 = (current_and >> j) & 1;

        if (bit_0 == 0 && bit_1023 == 0) { // r_j = 0
            // (x_j & 0) | 0 ^ 0 = 0
            // (x_j & 1) | 0 ^ 1 = x_j ^ 1 = ~x_j (not 0)
            // (x_j & 0) | 1 ^ 1 = 0
            // (x_j & 1) | 1 ^ 0 = 1 (not 0)
            // So, A_j=0, O_j=0, X_j=0 works.
            // Or A_j=0, O_j=1, X_j=1 works.
            // Let's pick A_j=0, O_j=0, X_j=0.
            // This means `final_A` has 0 at bit `j`, `final_O` has 0 at bit `j`, `final_X` has 0 at bit `j`.
        } else if (bit_0 == 1 && bit_1023 == 1) { // r_j = 1
            // (x_j & 0) | 1 ^ 0 = 1
            // (x_j & 1) | 1 ^ 0 = 1
            // So, A_j=0, O_j=1, X_j=0 works.
            // This means `final_A` has 0 at bit `j`, `final_O` has 1 at bit `j`, `final_X` has 0 at bit `j`.
            final_O |= (1 << j);
        } else if (bit_0 == 0 && bit_1023 == 1) { // r_j = x_j
            // (x_j & 1) | 0 ^ 0 = x_j
            // So, A_j=1, O_j=0, X_j=0 works.
            // This means `final_A` has 1 at bit `j`, `final_O` has 0 at bit `j`, `final_X` has 0 at bit `j`.
            final_A |= (1 << j);
        } else { // bit_0 == 1 && bit_1023 == 0, r_j = ~x_j
            // (x_j & 1) | 0 ^ 1 = ~x_j
            // So, A_j=1, O_j=0, X_j=1 works.
            // This means `final_A` has 1 at bit `j`, `final_O` has 0 at bit `j`, `final_X` has 1 at bit `j`.
            final_A |= (1 << j);
            final_X |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If final_A is not all ones, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) { // If final_O is not all zeros, we need an OR operation
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) { // If final_X is not all zeros, we need an XOR operation
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can assume the target is in the first quadrant
        // and n is the larger coordinate. The problem statement implies n, m are positive.
        // If they were negative, we'd take absolute values. Given constraints 1 <= n, m, k,
        // they are always positive.
        if (n < m) {
            std::swap(n, m);
        }

        // The minimum number of moves to reach (n, m) is n (if n >= m).
        // This is achieved by making m diagonal moves and n-m horizontal moves.
        // If k < n, it's impossible to reach (n, m) in k moves.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Let's analyze the parity of coordinates and moves.
        // Each move changes the sum of coordinates (x+y) by -2, 0, or 2 (diagonal)
        // or -1, 1 (horizontal/vertical).
        // More simply, each move changes the parity of x or y or both.
        // A diagonal move changes both x and y parities.
        // A non-diagonal move changes exactly one of x or y parities.
        //
        // Consider the parity of (n + m) and k.
        // Starting at (0,0), after k moves, the point (x_k, y_k) is reached.
        // The parity of (x_k + y_k) must be the same as the parity of k.
        // This is because each move changes x by $\Delta x \in \{-1, 0, 1\}$ and y by $\Delta y \in \{-1, 0, 1\}$,
        // with $\max(|\Delta x|, |\Delta y|) = 1$.
        // So, $\Delta x + \Delta y$ can be $\{-2, -1, 0, 1, 2\}$.
        // The parity of $(\Delta x + \Delta y)$ is always the same as the parity of $\max(|\Delta x|, |\Delta y|)$.
        // Since $\max(|\Delta x|, |\Delta y|) = 1$ for any move, each move changes the parity of $(x+y)$ by an odd amount.
        // Thus, after $k$ moves, the parity of $(x_k + y_k)$ must be the same as the parity of $k$.
        //
        // So, if $(n + m)$ and $k$ have different parities, it's impossible.
        // (n + m) % 2 != k % 2
        if (((n % 2) + (m % 2)) % 2 != (k % 2)) {
            // If n and m have different parities, n+m is odd.
            // If n and m have same parities, n+m is even.
            // This is equivalent to (n % 2 != m % 2) != (k % 2).
            // Or simply (n + m) % 2 != k % 2.

            // However, there's a special case. If k is greater than n, we can always make
            // "wasted" moves. A wasted move is moving to an adjacent cell and then immediately
            // back to the original cell. E.g., (0,0) -> (1,0) -> (0,0). This takes 2 moves
            // and changes the parity of (x+y) by 0.
            // Or (0,0) -> (1,1) -> (0,0). This also takes 2 moves and changes parity of (x+y) by 0.
            //
            // The parity condition (n+m)%2 == k%2 is necessary if we only consider moves that
            // bring us closer to the target or maintain distance.
