                                           // This logic is flawed.
                                           // Let's use the definition: b_i = (a_i + k) % m, where 0 <= k <= mid.
                                           // We want to find the smallest b_i >= prev_b.
                                           // If a_i >= prev_b:
                                           //   We can choose k=0, so b_i = a_i. This is valid.
                                           //   So prev_b for next element is a_i.
                                           // If a_i < prev_b:
                                           //   We need to increase a_i.
                                           //   If a_i + mid >= prev_b:
                                           //     We can achieve prev_b. So we set b_i = prev_b.
                                           //   If a_i + mid < prev_b:
                                           //     We cannot achieve prev_b by just adding up to mid.
                                           //     We must wrap around.
                                           //     The values we can get are [a_i, (a_i + mid) % m].
                                           //     If a_i + mid < m, then the range is [a_i, a_i + mid].
                                           //     If a_i + mid >= m, then the range is [0, (a_i + mid) % m] U [a_i, m-1].
                                           //     In this case (a_i < prev_b and a_i + mid < prev_b), it means we cannot reach prev_b.
                                           //     So it's impossible.
                                           // This is the correct logic.

                // If current_a <= prev_b:
                // We need to make current_b >= prev_b.
                // The minimum value current_a can take is current_a (by applying 0 operations).
                // The maximum value current_a can take without wrapping is current_a + mid.
                // If current_a + mid < prev_b, it means even with 'mid' operations, we cannot reach 'prev_b'
                // without wrapping around. If we wrap around, the value becomes smaller than current_a.
                // So, if current_a + mid < prev_b, it's impossible to satisfy current_b >= prev_b.
                // Example: a_i=0, prev_b=2, mid=1. a_i+mid=1 < prev_b=2. Impossible.
                // Example: a_i=0, prev_b=2, mid=2. a_i+mid=2 >= prev_b=2. Possible, current_b=2.
                if (current_a + mid < prev_b) {
                    possible = false;
                    break;
                }
                // Otherwise, current_a + mid >= prev_b. We can achieve prev_b.
                current_b = prev_b;
            } else { // current_a > prev_b
                // We need to make current_b >= prev_b.
                // We can choose current_b = current_a (by applying 0 operations). This satisfies current_b >= prev_b.
                // However, we also need to consider if we can achieve a smaller value by wrapping around.
                // If current_a + mid >= m + prev_b, it means we can wrap around and still be >= prev_b.
                // Example: m=7, a_i=6, prev_b=0, mid=1. a_i+mid=7. (7%7)=0. This is >= prev_b.
                // So we can choose current_b = prev_b.
                // If current_a + mid < m + prev_b, it means we cannot wrap around and still be >= prev_b.
                // So we must choose current_b = current_a.
                if (current_a + mid >= m + prev_b) {
                    current_b = prev_b;
                } else {
                    current_b = current_a;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
