struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> current_delta(n, 0);

    // Initialize initial_a based on type 2 operations
    // For each type 2 operation (l, r, m), we know that for any j in [l, r],
    // A_j + delta_j <= m.
    // So, A_j <= m - delta_j.
    // We want to maximize A_j to satisfy constraints, so we take the minimum of these upper bounds.
    // Initialize A_j to a very large value (effectively infinity)
    for (int i = 0; i < n; ++i) {
        initial_a[i] = std::numeric_limits<long long>::max();
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If initial_a[j] is still max_long_long, it means it was never constrained by a type 2 operation.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Check if the constructed initial_a satisfies all type 2 operations
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for verification
    std::vector<long long> current_a(n);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (std::abs(initial_a[i]) > 1000000000LL) {
            // This case should ideally not be reached if the logic for initial_a is correct
            // and if a solution exists within the 10^9 bounds.
            // The problem statement guarantees that if a solution exists, it has |a_i| <= 10^9.
            // Our construction finds the largest possible A_i values.
            // If these largest values exceed 10^9, it implies no solution exists within bounds.
            // However, the problem constraints on m_i (-5e7 to 5e7) and d_i (-1e4 to 1e4)
            // combined with m (5000) mean that initial_a[j] will likely stay within bounds.
            // Max possible delta_j is 5000 * 1e4 = 5e7.
            // Max possible m_i is 5e7.
            // So A_j = m_i - delta_j could be 5e7 - (-5e7) = 1e8, which is within 10^9.
            // Min possible A_j could be -5e7 - 5e7 = -1e8, also within 10^9.
            // So this check is mostly for robustness, but should not fail given problem constraints.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

