// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2); // Median of 0s and 1s: 1 if sum >= 2, else 0
    }
    return b;
}

