#include <numeric>
#include <queue>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i goes to the dentist

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_runaways = 0;

        std::queue<int> runaway_queue;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from previous runaways
            children[j].p -= total_d_cry_from_runaways;

            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure we only add to queue once
                    runaway_queue.push(j);
                    children[j].in_line = false;
                }
            }
        }

        // Process chain reaction of runaways
        while (!runaway_queue.empty()) {
            int runaway_idx = runaway_queue.front();
            runaway_queue.pop();

            total_d_cry_from_runaways += children[runaway_idx].d;

            for (int j = runaway_idx + 1; j < n; ++j) {
                if (!children[j].in_line) {
                    continue;
                }

                children[j].p -= children[runaway_idx].d;

                if (children[j].p < 0) {
                    if (children[j].in_line) { // Ensure we only add to queue once
                        runaway_queue.push(j);
                        children[j].in_line = false;
                    }
                }
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
