int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> next_bad_idx(n + 1, n); // next_bad_idx[i] stores the smallest j >= i such that s[j], s[j+1], s[j+2] are all same.
                                            // Or s[j], s[j+2], s[j+4] are all same.
                                            // Or s[j], s[j+1], s[j+2], s[j+3], s[j+4], s[j+5] are all same.
                                            // More precisely, next_bad_idx[i] is the smallest index `p` such that `p` is the first element of a 3-AP `s[p]=s[p+k]=s[p+2k]`
                                            // and `p >= i`.
                                            // The problem states `l <= x < x+2k <= r`.
                                            // So `x` is the first element of the 3-AP.
                                            // We are looking for `x` such that `s[x]=s[x+k]=s[x+2k]`.
                                            // The smallest `r` for a given `l` that satisfies the condition is `max(l, x+2k)` for some `x, k` where `x >= l`.
                                            // This is equivalent to finding the smallest `x+2k` for some `x, k` where `x >= l`.
                                            // Let `min_r_for_l[l]` be the minimum `r` such that `(l, r)` is a "good" pair.
                                            // This `min_r_for_l[l]` is `min_{x >= l} (x+2k)` over all valid `x, k`.
                                            // Let `min_end_idx[i]` be the minimum `j` such that `s[i]=s[i+k]=s[j]` for some `k` and `j=i+2k`.
                                            // We need to find `min_end_idx[i]` for all `i`.
                                            // The `next_bad_idx` array will store `min_end_idx[i]` for the smallest `i` that starts a 3-AP.
                                            // Let `min_r_val[i]` be the minimum `x+2k` such that `x >= i` and `s[x]=s[x+k]=s[x+2k]`.
                                            // If no such `x, k` exists for `x >= i`, then `min_r_val[i] = n`.

    // Initialize min_r_val for each starting index i
    std::vector<int> min_r_val(n, n); // min_r_val[i] stores the minimum r-1 (0-indexed) such that there exists x, k with x=i, s[x]=s[x+k]=s[x+2k]=s[r-1]
                                      // and r-1 = x+2k.
                                      // If no such k exists for x=i, then min_r_val[i] = n.

    for (int i = 0; i < n; ++i) {
        // Check k=1
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            min_r_val[i] = std::min(min_r_val[i], i + 2);
        }
        // Check k=2
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            min_r_val[i] = std::min(min_r_val[i], i + 4);
        }
        // Check k=3
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            min_r_val[i] = std::min(min_r_val[i], i + 6);
        }
    }

    // Now, compute `min_r_for_l[l]` (1-indexed `l`) which is `min_{x >= l-1} (min_r_val[x])`.
    // Let `min_r_suffix[i]` be the minimum `x+2k` (0-indexed) for any `x >= i` (0-indexed).
    std::vector<int> min_r_suffix(n + 1, n); // min_r_suffix[i] stores min(min_r_val[i], min_r_val[i+1], ..., min_r_val[n-1])
                                            // or rather, min(min_r_val[i], min_r_suffix[i+1])
    for (int i = n - 1; i >= 0; --i) {
        min_r_suffix[i] = std::min(min_r_val[i], min_r_suffix[i+1]);
    }

    long long total_good_pairs = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) { // l_idx is 0-indexed l-1
        int min_r_end_idx = min_r_suffix[l_idx]; // This is the minimum 0-indexed r-1 for this l_idx
        if (min_r_end_idx < n) { // If there is at least one such pattern starting at or after l_idx
            // All r from min_r_end_idx to n-1 (inclusive) will form a good pair (l_idx, r_idx)
            // Number of such r_idx values is (n-1) - min_r_end_idx + 1 = n - min_r_end_idx
            total_good_pairs += (n - min_r_end_idx);
        }
    }

    std::cout << total_good_pairs << std::endl;

    return 0;
}

