    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness_all_one = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);

    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }
    long long min_goodness = goodness_all_one;

