bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1
    // Try all possible single cuts
    // s = P1 P2
    // New string = P2 P1
    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string new_s = p2 + p1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2
    // If n is odd, and all characters are the same, e.g., "aaaaa"
    // Then any permutation of substrings will result in "aaaaa".
    // For example, "a|a|aaa" -> "a" + "a" + "aaa" = "aaaaa"
    // "a|aa|aa" -> "a" + "aa" + "aa" = "aaaaa"
    // If all characters are the same, no matter how you cut and reorder,
    // the string will remain the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Consider s = "nolon" (n=5)
    // Cut: no | l | on
    // Reorder: on | l | no -> "onlno" (palindrome, different from "nolon")
    // This strategy works for any palindrome that is not all same characters.
    // Take s = A B A, where A is s[0...n/2-1] and B is s[n/2] (if n is odd)
    // Cut s into s[0...n/2-1] | s[n/2] | s[n/2+1...n-1]
    // Let P1 = s[0...n/2-1], P2 = s[n/2] (middle char), P3 = s[n/2+1...n-1]
    // Since s is a palindrome, P1 is the reverse of P3.
    // So P3 = reverse(P1).
    // The original string is P1 + P2 + P3.
    // Reorder to P3 + P2 + P1.
    // This new string is reverse(P1) + P2 + P1.
