        // This is still not quite right. The heads are not consumed. They can be used to cover multiple points.
        // The problem states "A track is considered read if at least one head has visited this track."
        // "During the operation each head's movement does not affect the movement of the other heads:
        // the heads can change their relative order; there can be multiple reading heads above any of the tracks."

#include <iostream>
#include <vector>
#include <numeric>

// Using 1-based indexing for a_val and x to match problem statement
// a_val[0] is unused. a_val[1] corresponds to a_1, a_val[2] to a_2, etc.
// The input gives a_2, ..., a_n. So a_val[2]...a_val[n] are read.
// For each query i, a_val[1] is set to i.

std::vector<long long> a_val;
std::vector<long long> dp_y; // dp_y[x] stores the total y accumulated when starting from (x, 0) and performing step 2 then step 3.
std::vector<int> dp_x;   // dp_x[x] stores the final x value when starting from (x, 0) and performing step 2 then step 3.
std::vector<bool> visited; // For cycle detection during DFS

int N;

// DFS function to compute dp_x and dp_y for a given starting x
// Returns true if computation finishes (terminates or reaches a known state), false if a cycle is detected.
bool dfs(int current_x) {
    if (current_x <= 0 || current_x > N) {
        // Base case: x is out of bounds, program terminates.
        // dp_x[current_x] and dp_y[current_x] are not directly used for out-of-bounds x,
        // but we can mark them as terminal states if needed.
        // For simplicity, we just return true as this path terminates.
        return true;
    }

    if (dp_x[current_x] != 0) { // Already computed or part of a cycle
        return true; // Already computed, or we've hit a node that's part of the current DFS path (cycle)
    }

    if (visited[current_x]) {
        // Cycle detected. Mark this state as non-terminating.
        // We use a special value like -1 for dp_x and dp_y to indicate non-termination.
        dp_x[current_x] = -1;
        dp_y[current_x] = -1;
        return false;
    }

    visited[current_x] = true;

    long long val_ax = a_val[current_x];

    // Simulate step 2: x = x + a_x, y = y + a_x
    int next_x_after_step2 = current_x + val_ax;
    long long y_after_step2 = val_ax;

    // Simulate step 3: x = x - a_x, y = y + a_x (using the new x from step 2, but old a_x for value)
    // The problem states "increases y by a_x while decreasing x by a_x"
    // This implies a_x is the value from the *original* x.
    // So, the x for the second operation is next_x_after_step2, and the value a_x is val_ax.
    int final_x_for_this_pair = next_x_after_step2 - val_ax;
    long long total_y_for_this_pair = y_after_step2 + val_ax;

    // Now, we need to find the result of the next pair of steps starting from final_x_for_this_pair
    if (final_x_for_this_pair <= 0 || final_x_for_this_pair > N) {
        // Program terminates after this pair of steps
        dp_x[current_x] = final_x_for_this_pair;
        dp_y[current_x] = total_y_for_this_pair;
    } else {
        // Recursively call dfs for the next state
        if (!dfs(final_x_for_this_pair)) {
            // If the recursive call detected a cycle, this path also leads to non-termination
            dp_x[current_x] = -1;
            dp_y[current_x] = -1;
        } else {
            // If the recursive call terminated or found a known state
            if (dp_x[final_x_for_this_pair] == -1) { // Next state leads to non-termination
                dp_x[current_x] = -1;
                dp_y[current_x] = -1;
            } else {
                dp_x[current_x] = dp_x[final_x_for_this_pair];
                dp_y[current_x] = total_y_for_this_pair + dp_y[final_x_for_this_pair];
            }
        }
    }

    visited[current_x] = false; // Backtrack: remove from current path
    return dp_x[current_x] != -1; // Return true if this path terminates, false if it leads to a cycle
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_val.resize(N + 1);
    // a_val[1] will be set for each query.
    // a_val[2] through a_val[N] are read from input.
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_val[i];
    }

    // Initialize DP tables. 0 indicates uncomputed. -1 indicates non-terminating.
    dp_x.resize(N + 1, 0);
    dp_y.resize(N + 1, 0);
    visited.resize(N + 1, false);

    // Precompute results for all possible starting x values (1 to N)
    // This is done by calling DFS for each x that hasn't been computed yet.
    // The DFS will fill dp_x and dp_y for all reachable states.
    for (int i = 1; i <= N; ++i) {
        if (dp_x[i] == 0) { // If not yet computed
            dfs(i);
        }
    }

    // For each query i (1 to N-1), set a_val[1] = i and run the program.
    for (int i = 1; i < N; ++i) {
        a_val[1] = i; // Set a_1 for this query

        // The program starts with x=1, y=0.
        // It performs step 2 then step 3.
        // Let's denote the initial a_x (which is a_1) as current_a_val.
        long long current_a_val = a_val[1];

        // First pair of operations:
        // Step 2: x = 1 + current_a_val, y = 0 + current_a_val
        int x_after_step2 = 1 + current_a_val;
        long long y_after_step2 = current_a_val;

        // Step 3: x = x_after_step2 - current_a_val, y = y_after_step2 + current_a_val
        int final_x_after_first_pair = x_after_step2 - current_a_val;
        long long total_y_after_first_pair = y_after_step2 + current_a_val;

        // Now, we need to find the result of subsequent pairs of steps starting from final_x_after_first_pair
        if (final_x_after_first_pair <= 0 || final_x_after_first_pair > N) {
            // Program terminates after the first pair of steps
            std::cout << total_y_after_first_pair << "\n";
        } else {
            // Use the precomputed DP values
            if (dp_x[final_x_after_first_pair] == -1) { // Subsequent steps lead to non-termination
                std::cout << -1 << "\n";
            } else {
                std::cout << total_y_after_first_pair + dp_y[final_x_after_first_pair] << "\n";
            }
        }
    }

    return 0;
}

