        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same fingerprint.
        // We need to output a different permutation.
        // If p is already its own reverse (e.g., n=1 or n=2 and p=[1,2] or p=[2,1]),
        // then reversing it would give the same permutation.
        // However, for n >= 2, a permutation p and its reverse p_rev are different
        // unless p is a palindrome. A permutation cannot be a palindrome unless n=1.
        // For n=2, p=[1,2], p_rev=[2,1]. They are different.
        // For n=2, p=[2,1], p_rev=[1,2]. They are different.
        // So, reversing the permutation always gives a different permutation for n >= 2.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

