void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        // Distance from pile i+1 (0-indexed i) to pile 1 (0-indexed 0) is i.
        long long distance = i; 

        if (d >= distance) {
            // Calculate how many haybales can be moved from pile i to pile 1.
            // Each haybale costs 'distance' days.
            // We have 'a[i]' haybales in pile i.
            // We have 'd' days remaining.
            long long haybales_to_move = std::min(a[i], d / distance);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * distance;
        } else {
            // Not enough days to move even one haybale from this pile.
            // Since piles further away cost more days, we can stop.
            break;
        }
    }

    std::cout << current_a1 << std::endl;
}

