#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // After sorting the array a, the optimal strategy is to pick
        // the n-th element (0-indexed: a[n-1]) as the median for one class
        // and the (n+1)-th element (0-indexed: a[n]) as the median for the other class.
        // This is because if we pick a[n-1] as the median for a class of size 2k+1,
        // we need k elements smaller than or equal to a[n-1] and k elements larger than or equal to a[n-1].
        // Similarly for a[n].
        // The smallest possible difference is achieved by taking adjacent elements in the sorted array.
        // Specifically, a[n-1] and a[n] are the two "middle" elements of the entire sorted array.
        // If we form one class with elements up to a[n-1] and another with elements from a[n],
        // we can always construct valid odd-sized classes such that a[n-1] and a[n] are their medians.
        // For example, Class 1: [a_0, ..., a_{n-1}] and Class 2: [a_n, ..., a_{2n-1}].
        // Both classes would have size n. If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition.
        // However, the key insight is that the minimum difference will always be between a[n-1] and a[n].
        // This is because any other pair of medians would be further apart.
        // For example, if we pick a[i] and a[j] as medians, and i < n-1 or j > n,
        // then |a[i] - a[j]| >= |a[n-1] - a[n]|.
        // The problem guarantees that such a partition is always possible.
        // The minimum difference is simply the difference between the two middle elements.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

