int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // a[i][i] is 0, skip it
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there must be some p[j] > p[i], and min(p[i], p[j]) = p[i].
        // So max_val_in_row would be p[i].
        // If p[i] is n, then for all j, min(n, p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j != i), which is n-1.
        // In this case, p[i] should be n.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

