        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The previous 'R' or start was at last_R_pos
                // The current 'R' is at i+1
                // The gap is (i+1) - last_R_pos
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }

        // After iterating through the string, consider the jump from the last 'R' to n+1
        // Or if no 'R's, from 0 to n+1
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
