#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and prevents flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices for each day
        }

        if (n <= 1) {
            std::cout << 0 << "\n"; // If 0 or 1 day, no price can be bad
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the price of the last day.
        // The last day's price can never be bad because there are no later days.
        int min_suffix = a[n - 1]; 

        // Iterate from the second-to-last day backwards to the first day.
        // For each day i, we compare a[i] with the minimum price found
        // in days i+1, i+2, ..., n-1 (which is min_suffix).
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                bad_prices_count++; // If a[i] is greater than min_suffix, it's a bad price
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is
                // either equal to or less than the current minimum.
                // In this case, a[i] becomes the new minimum for subsequent days
                // (days before i).
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students divided by 3.
        // 2. The number of coders (each team needs at least one).
        // 3. The number of mathematicians (each team needs at least one).
        // So, an upper bound for the number of teams is min((c+m+x)/3, c, m).
        // Let's call this upper bound 'max_possible_teams'.
        // We are looking for the largest 'k' such that k <= max_possible_teams
        // and k teams can actually be formed.

        // The minimum number of students required for k teams is k coders and k mathematicians.
        // The remaining k students must come from the remaining c-k coders, m-k mathematicians,
        // and all x unspecalized students.
        // So, (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3

        // Also, we need at least k coders and k mathematicians.
        // So, k <= c and k <= m.

        // Combining these, the maximum number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3

        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // This condition is also sufficient. If we can form k teams, we use k coders and k mathematicians.
        // The remaining students are (c-k) coders, (m-k) mathematicians, and x unspecalized.
        // The total count of these remaining students is (c-k) + (m-k) + x.
        // We need to pick k more students from this pool to complete the 3 members per team.
        // Since k <= (c+m+x)/3 implies 3k <= c+m+x, which means k <= (c+m+x) - 2k.
        // So, k <= (c-k) + (m-k) + x.
        // This means there are enough remaining students to fill the third slot in each of the k teams.

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

