int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // Example: k=2, range [1,3]. Output: 1 3 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, range [1,4]. Output: 1 4 2 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    // Example: k=4, range [1,5]. Output: 1 5 2 4 3. Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, pick from left (smallest available)
            std::cout << left++;
        } else { // Odd index, pick from right (largest available)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This will only generate a difference of 1, which is already among the k distinct differences
    // (specifically, it's the smallest one generated by the alternating pattern).
    // So, no new distinct differences are introduced.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

