#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just p[pos[1]], which is [1].
        // min_idx and max_idx are already initialized to pos[1].
        // The length is 1, max is 1, min is 1. So m=1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' must be at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from min(pos[1], ..., pos[m]) to max(pos[1], ..., pos[m]).

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for being a permutation of 1...m.
        // 1. Length must be m: (current_max_idx - current_min_idx + 1) == m
        // 2. Min element must be 1 (guaranteed by construction, as we always include pos[1])
        // 3. Max element must be m (guaranteed by construction, as we expand to include pos[m])
        // If these hold, and all numbers 1..m are distinct (which they are in a permutation),
        // then it's a permutation of 1..m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we need d - 4 >= 0, which means d >= 4.
        // If d is 0, it's a special case handled above.
        // If d is 1, 2, or 3, then d - 4 is negative, so no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly positive, so a1 is positive.
            // For b1, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So, both a1 and b1 are guaranteed to be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

