void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0, but good for robustness
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Determine if the final product can be positive or negative
    // The parity of negative numbers determines the sign of the final product.
    // B toys are negative, A toys are negative.
    // Total negative toys = A + B.
    // If (A + B) is even, final product can be positive.
    // If (A + B) is odd, final product can be negative.

    bool can_be_positive = ((A + B) % 2 == 0);
    bool can_be_negative = ((A + B) % 2 != 0);

    // Determine if the final product can have magnitude > 1, < 1, or = 1
    // Let N_gt1 = A + D (toys with |val| >= 1)
    // Let N_lt1 = B + C (toys with |val| < 1)

    // If there are any toys with |val| >= 1 (A or D > 0), then it's possible to make |product| >= 1.
    // If there are any toys with |val| < 1 (B or C > 0), then it's possible to make |product| < 1.

    // If all toys are from B and C (A=0, D=0), then the final product will have magnitude < 1.
    // If all toys are from A and D (B=0, C=0), then the final product will have magnitude >= 1.
    // If there's a mix, it's more complex.

    // Let's analyze the conditions for each box:

    // Box 1: $(-\infty, -1]$ (Negative, magnitude >= 1)
    // Requires: can_be_negative AND can_be_magnitude_ge1
    // can_be_magnitude_ge1:
    //   If A+D > 0 (at least one toy with |val| >= 1), then it's possible to make magnitude >= 1.
    //   If A+D = 0 (all toys from B and C), then magnitude will always be < 1.
    if (can_be_negative && (A + D > 0)) {
        ans1 = "Ya";
    }

    // Box 2: $(-1, 0)$ (Negative, magnitude < 1)
    // Requires: can_be_negative AND can_be_magnitude_lt1
    // can_be_magnitude_lt1:
    //   If B+C > 0 (at least one toy with |val| < 1), then it's possible to make magnitude < 1.
    //   If B+C = 0 (all toys from A and D), then magnitude will always be >= 1.
    //   Special case: If A+D > 0 and B+C > 0, we can always make magnitude < 1.
    //   If A+D = 0, then B+C = total_toys > 0, so magnitude < 1 is guaranteed.
    //   If B+C = 0, then A+D = total_toys > 0, so magnitude >= 1 is guaranteed.
    //   So, if B+C > 0, it's possible to make magnitude < 1.
    //   What if B+C = 0? Then all toys are from A and D. The product will be >= 1.
    //   So, if B+C > 0, can_be_magnitude_lt1 is true.
    //   If B+C = 0, can_be_magnitude_lt1 is false.
    if (can_be_negative && (B + C > 0)) {
        ans2 = "Ya";
    }

    // Box 3: $(0, 1)$ (Positive, magnitude < 1)
    // Requires: can_be_positive AND can_be_magnitude_lt1
    if (can_be_positive && (B + C > 0)) {
        ans3 = "Ya";
    }

    // Box 4: $[1, \infty)$ (Positive, magnitude >= 1)
    // Requires: can_be_positive AND can_be_magnitude_ge1
    if (can_be_positive && (A + D > 0)) {
        ans4 = "Ya";
    }

    // Edge cases for magnitude:
    // If all toys are from B and C (A=0, D=0), then the final product will always have magnitude < 1.
    // In this case, ans1 and ans4 must be "Tidak".
    if (A == 0 && D == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }
    // If all toys are from A and D (B=0, C=0), then the final product will always have magnitude >= 1.
    // In this case, ans2 and ans3 must be "Tidak".
    if (B == 0 && C == 0) {
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    // One final check for the "magnitude < 1" possibility.
    // If there are no toys in B or C (B+C=0), then all toys are from A and D.
    // In this scenario, the product of any two toys from A and D will have magnitude >= 1.
    // So, the final product will always have magnitude >= 1.
    // Thus, boxes 2 and 3 are impossible.
    if (B == 0 && C == 0) {
        ans2 = "Tidak";
        ans3 = "Tidak";
    }

    // One final check for the "magnitude >= 1" possibility.
    // If there are no toys in A or D (A+D=0), then all toys are from B and C.
    // In this scenario, the product of any two toys from B and C will have magnitude < 1.
    // So, the final product will always have magnitude < 1.
    // Thus, boxes 1 and 4 are impossible.
    if (A == 0 && D == 0) {
        ans1 = "Tidak";
        ans4 = "Tidak";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

