void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_req: minimum value a[i] must be to satisfy a[0] < ... < a[i]
    // a[0] must be at least 0
    // a[1] must be at least 1
    // a[i] must be at least i
    // So, a[i] must be >= i.
    // We can decrease a[i] to satisfy this.
    // If original a[i] < i, then it's impossible to make a[i] >= i.
    // So, we need a[i] >= i for all i in the increasing part.
    // This means a[i] must be at least i.
    // The actual value we can achieve for a[i] is min(original a[i], some_upper_bound).
    // For the increasing part, we need a[i] >= i.
    // If a[i] < i, it's impossible.
    // So, we need a[i] >= i for all i in the increasing part.
    // Let's find the first index `i` from the left where `a[i] < i`.
    // All elements `a[0]` to `a[i-1]` can potentially form the increasing part.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate suffix_min_req: minimum value a[i] must be to satisfy a[i] > ... > a[n-1]
    // a[n-1] must be at least 0
    // a[n-2] must be at least 1
    // a[i] must be at least (n-1-i)
    // So, a[i] must be >= (n-1-i).
    // If original a[i] < (n-1-i), then it's impossible.
    // Let's find the first index `i` from the right where `a[i] < (n-1-i)`.
    // All elements `a[i+1]` to `a[n-1]` can potentially form the decreasing part.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i;
            break;
        }
    }

    // If left_limit > right_limit, it means there is at least one index `k`
    // such that `a[k] >= k` AND `a[k] >= (n-1-k)`.
    // This `k` can be our peak.
    // For such a `k`, we can make `a[0] < ... < a[k]` by setting `a[i] = i` for `i < k`.
    // This is possible because `a[i] >= i` for `i < k` (due to `left_limit > k`).
    // And we can make `a[k] > ... > a[n-1]` by setting `a[i] = n-1-i` for `i > k`.
    // This is possible because `a[i] >= n-1-i` for `i > k` (due to `right_limit < k`).
    // The peak `a[k]` can be set to `max(k, n-1-k) + 1` (or more, up to original `a[k]`).
    // Since `a[k] >= k` and `a[k] >= n-1-k`, we can always find a value for `a[k]`
    // that is greater than `a[k-1]` (which is `k-1`) and greater than `a[k+1]` (which is `n-1-(k+1)`).
    // For example, we can set `a[k]` to `max(k, n-1-k)`.
    // If `k=0`, `a[0]` must be `> a[1]`. `a[0] >= 0`. `a[1]` must be `n-1-1`.
    // If `k=n-1`, `a[n-1]` must be `> a[n-2]`. `a[n-1] >= 0`. `a[n-2]` must be `n-1-2`.
    // The condition `left_limit > right_limit` means there is an overlap of valid indices.
    // Any index `k` in the range `[right_limit + 1, left_limit - 1]` can be a peak.
    // For such a `k`:
    // For `i < k`, `i < left_limit`, so `a[i] >= i`. We can set `a[i] = i`.
    // For `i > k`, `i > right_limit`, so `a[i] >= n-1-i`. We can set `a[i] = n-1-i`.
    // For `i = k`: `a[k] >= k` and `a[k] >= n-1-k`.
    // We need `a[k] > a[k-1]` (if `k>0`) and `a[k] > a[k+1]` (if `k<n-1`).
    // If `k=0`, we need `a[0] > a[1]`. We can set `a[0]` to `max(0, n-1-1+1) = n-1`. Original `a[0]` must be `>= n-1`.
    // If `k=n-1`, we need `a[n-1] > a[n-2]`. We can set `a[n-1]` to `max(n-1-1+1, 0) = n-1`. Original `a[n-1]` must be `>= n-1`.
    // In general, we can set `a[k-1]` to `k-1` and `a[k+1]` to `n-1-(k+1)`.
    // We need `a[k]` to be at least `k` and at least `n-1-k`.
    // And `a[k]` must be strictly greater than `k-1` (if `k>0`) and strictly greater than `n-1-(k+1)` (if `k<n-1`).
    // Since `a[k] >= k` and `a[k] >= n-1-k`, `a[k]` is already greater than or equal to `k-1` and `n-1-(k+1)`.
    // If `a[k]` is `k`, it's `> k-1`. If `a[k]` is `n-1-k`, it's `> n-1-(k+1)`.
    // The only edge case is if `k=0` and `n=1`. `left_limit=1`, `right_limit=-1`. `1 > -1` is true.
    // The logic holds.

    if (left_limit > right_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

