    // Sort B in ascending order of values
    std::sort(B.begin(), B.end(), compareB);

    // Create the result array A'
    std::vector<long long> A_prime(m);

    // The strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means A[i] (sorted) should be paired with B[i] (sorted).
    // However, we need to reconstruct the A' array based on the original indices of B.
    // So, if B[i] (sorted) was originally at index B[i].original_index,
    // then A_prime[B[i].original_index] should be A[i].value (sorted).
    for (int i = 0; i < m; ++i) {
