bool is_good(const std::vector<int>& a, int start_idx) {
    if (start_idx >= a.size()) { // Empty array or single element array (handled by loop condition)
        return true;
    }

    int n = a.size();
    int current_val = 0; // Represents the last element added to 'c'

    // Find the first decreasing sequence from the right
    // This identifies the rightmost non-increasing suffix
    int right_ptr = n - 1;
    while (right_ptr > start_idx && a[right_ptr - 1] <= a[right_ptr]) {
        right_ptr--;
    }
    // After this loop, a[right_ptr...n-1] is non-decreasing.
    // If right_ptr == start_idx, the whole suffix a[start_idx...n-1] is non-decreasing.

    // Find the first increasing sequence from the left
    // This identifies the leftmost non-decreasing prefix
    int left_ptr = start_idx;
    while (left_ptr < right_ptr && a[left_ptr] <= a[left_ptr + 1]) {
        left_ptr++;
    }
    // After this loop, a[start_idx...left_ptr] is non-decreasing.
    // If left_ptr == right_ptr, it means the entire segment a[start_idx...right_ptr] is non-decreasing.

    // The "valley" or "peak" is between left_ptr and right_ptr.
    // If left_ptr >= right_ptr, the array is already non-decreasing or has a single peak/valley.
    // The condition for a good array is that it must be of the form:
    // non-decreasing prefix, then non-increasing sequence, then non-decreasing suffix.
    // Or more precisely, it must be possible to pick elements to form a non-decreasing sequence.
    // The strategy is to pick elements from the ends.
    // The elements that are "left over" in the middle must form a non-decreasing sequence.
    // This means the array must look like:
    // [increasing part] [decreasing part] [increasing part]
    // Example: [1, 2, 3, 4, 4, 2, 1]
    // left_ptr will go up to 3 (value 4).
    // right_ptr will go down to 5 (value 2).
    // The middle part is [4, 2]. This is not good.
    // The example given: b = [1, 2, 3, 4, 4, 2, 1] is good.
    // The strategy is: take 1 (left), take 1 (right), take 2 (right), take 2 (left), take 3 (left), take 4 (right), take 4 (left).
    // This means the elements are picked in a specific order.
    // The elements remaining in the middle must be picked last.
    // The elements picked from the left form a non-decreasing sequence.
    // The elements picked from the right form a non-decreasing sequence.
    // The elements picked from the middle must be non-decreasing.

    // Let's re-evaluate the structure of a good array.
    // A good array `b` can be split into three parts:
    // `b_L = [b_1, ..., b_i]` (elements picked from left)
    // `b_M = [b_{i+1}, ..., b_j]` (elements picked from middle, if any)
    // `b_R = [b_{j+1}, ..., b_m]` (elements picked from right)
    // The elements `b_L` and `b_R` are picked first, then `b_M`.
    // This means `b_L` must be non-decreasing, `b_R` must be non-decreasing (when read from right to left),
    // and `b_M` must be non-decreasing.
    // This is equivalent to saying that the array `b` must be of the form:
    // `[X_1, X_2, ..., X_k, Y_p, Y_{p-1}, ..., Y_1]` where `X_1 <= ... <= X_k` and `Y_1 <= ... <= Y_p`.
    // The elements `X_i` are picked from the left, `Y_j` are picked from the right.
    // The remaining elements `b_{k+1}, ..., b_{m-p}` must form a non-decreasing sequence.
    // This means the array must look like:
    // `[inc_prefix] [dec_middle] [inc_suffix]`
    // The `dec_middle` part is the part that is "bad".
    // We need to find the longest suffix `a[k...n-1]` such that `a[k...n-1]` is good.

    // The condition for a good array is that it must be possible to find a split point `k`
    // such that `a[start_idx...k]` is non-decreasing and `a[k...n-1]` is non-increasing.
    // No, this is not correct. The example [1,2,3,4,4,2,1] is good.
    // It's more like: find the first element from the right that breaks non-decreasing order.
    // And find the first element from the left that breaks non-decreasing order.
    // The elements between these two points must be "removable".

    // Let's use the definition from the problem statement:
    // "select either the first or the last element of b, remove it from b, and append it to the end of the array c."
    // This implies that the elements are picked from the ends.
    // The elements picked from the left form a sequence `L = [b_1, b_2, ..., b_k]`.
    // The elements picked from the right form a sequence `R = [b_m, b_{m-1}, ..., b_j]`.
    // The remaining elements `M = [b_{k+1}, ..., b_{j-1}]` are picked last.
    // For `c` to be non-decreasing, we must have:
    // 1. `L` is non-decreasing.
    // 2. `R` is non-decreasing (when read from right to left).
    // 3. `M` is non-decreasing.
    // 4. The elements must be picked in such a way that `c` is non-decreasing.
    // This means `max(L_i)` must be <= `min(M_j)` and `max(R_i)` must be <= `min(M_j)`.
    // This is equivalent to saying that the array `b` must be of the form:
    // `[inc_prefix] [dec_part] [inc_suffix]`
    // The `inc_prefix` is `a[start_idx ... left_peak_idx]`.
    // The `inc_suffix` is `a[right_peak_idx ... n-1]`.
    // The `dec_part` is `a[left_peak_idx ... right_peak_idx]`.
    // The elements in `dec_part` must be picked from the ends of `dec_part` to form a non-decreasing sequence.
    // This means `dec_part` itself must be of the form `[inc_prefix'] [dec_suffix']`.
    // This is the "mountain" or "valley" structure.

    // The actual condition for a good array is simpler:
    // The array `b` is good if it can be partitioned into three (possibly empty) contiguous subarrays `P`, `M`, `S`
    // such that `b = P + M + S`, where:
    // 1. `P` is non-decreasing.
    // 2. `S` is non-decreasing (when read from right to left).
    // 3. `M` is non-decreasing.
    // 4. All elements of `P` are less than or equal to all elements of `M`.
    // 5. All elements of `S` are less than or equal to all elements of `M`.
    // This is equivalent to saying that the array `b` must be of the form:
    // `[x_1, ..., x_k, y_1, ..., y_p, z_1, ..., z_q]`
    // where `x_1 <= ... <= x_k`, `y_1 <= ... <= y_p`, `z_q <= ... <= z_1`.
    // And `x_k <= y_1` and `z_q <= y_1`.
    // This means the array must look like `/\` or `\/` or `_` or `/\_` or `_/\` etc.
    // The example `[1, 2, 3, 4, 4, 2, 1]` is good.
    // Here `P = [1, 2, 3]`, `M = [4, 4]`, `S = [1, 2]` (read from right to left).
    // `x_k = 3`, `y_1 = 4`, `z_q = 1`.
    // `3 <= 4` and `1 <= 4`. This fits.

    // So, we need to find the longest suffix `a[start_idx ... n-1]` that satisfies this property.
    // Let `b = a[start_idx ... n-1]`.
    // Find the rightmost index `i` such that `b[i] > b[i+1]`. If no such `i`, `b` is non-decreasing.
    // Find the leftmost index `j` such that `b[j] < b[j-1]`. If no such `j`, `b` is non-increasing.

    // The strategy to check if `b` is good:
    // 1. Find the longest non-decreasing suffix from the right.
    //    `right_idx` is the first index from the right such that `a[right_idx-1] > a[right_idx]`.
    //    If no such index, `right_idx = start_idx`.
    //    The segment `a[right_idx ... n-1]` is non-decreasing.
    // 2. Find the longest non-increasing suffix from the right.
    //    `right_dec_idx` is the first index from the right such that `a[right_dec_idx-1] < a[right_dec_idx]`.
    //    If no such index, `right_dec_idx = start_idx`.
    //    The segment `a[right_dec_idx ... n-1]` is non-increasing.

    // The actual condition for a good array `b` is that it must be "bitonic" or "unimodal" in a specific way.
    // It must be possible to pick elements from ends to form a non-decreasing sequence.
    // This means the elements that are picked last must form a non-decreasing sequence.
    // These elements are the "middle" elements.
    // The elements picked first are from the ends.
    // So, the array `b` must be of the form `[P_1, P_2, ..., P_k, M_1, ..., M_p, S_q, ..., S_1]`
    // where `P_1 <= ... <= P_k`, `M_1 <= ... <= M_p`, `S_1 <= ... <= S_q`.
    // And `P_k <= M_1` and `S_q <= M_1`.
    // This means the array `b` must look like `[inc_prefix] [middle_inc_part] [inc_suffix_reversed]`.
    // The `inc_suffix_reversed` means `S_q, ..., S_1` is non-decreasing.
    // So `b` looks like `[inc_prefix] [middle_inc_part] [dec_suffix]`.
    // And `max(inc_prefix) <= min(middle_inc_part)` and `max(dec_suffix) <= min(middle_inc_part)`.
    // This is the condition for a "good" array.

    // Let's find the `dec_suffix` part.
    // `right_idx` is the first index from the right such that `a[right_idx-1] > a[right_idx]`.
    // `a[right_idx ... n-1]` is non-decreasing.
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // `n=7`, `start_idx=0`.
    // `right_idx` starts at `n-1 = 6`.
    // `a[5]=2, a[6]=1`. `a[5] > a[6]`. So `right_idx` stops at `6`.
    // `a[6]` is `1`. `a[right_idx ... n-1]` is `[1]`.
    // This is not what the example implies. The example says `[1, 1, 2, 2, 3, 4, 4]` is formed.
    // The elements `1, 2, 3` are from the left. `1, 2, 4` are from the right.
    // The remaining `4` is from the middle.
    // This means the array `b` is good if it can be split into `b_L`, `b_M`, `b_R` such that:
    // `b_L` is `[b_1, ..., b_k]`
    // `b_M` is `[b_{k+1}, ..., b_{m-p}]`
    // `b_R` is `[b_{m-p+1}, ..., b_m]`
    // And `b_L` is non-decreasing, `b_M` is non-decreasing, `b_R` is non-decreasing (when read from right to left).
    // And `b_k <= b_{k+1}` (if `b_L` and `b_M` exist)
    // And `b_{m-p} <= b_{m-p+1}` (if `b_M` and `b_R` exist)
    // This is equivalent to saying that the array `b` must be of the form:
    // `[inc_prefix] [dec_part] [inc_suffix]`
    // where `inc_prefix` is `a[start_idx ... i]`, `dec_part` is `a[i ... j]`, `inc_suffix` is `a[j ... n-1]`.
    // `a[start_idx ... i]` is non-decreasing.
    // `a[j ... n-1]` is non-decreasing.
    // `a[i ... j]` is non-increasing.
    // This is the "mountain" shape.
    // Example: `[1, 2, 3, 4, 3, 2, 1]` is good.
    // `[1, 2, 3, 4, 4, 2, 1]`
    // `inc_prefix = [1, 2, 3, 4]` (up to index 3)
    // `dec_part = [4, 2, 1]` (from index 4 to 6)
    // `inc_suffix` is empty.
    // This is a "mountain" shape.
    // The condition for a good array is that it must be a "mountain" shape.
    // That is, it must be non-decreasing up to some point, then non-increasing.
    // `a[start_idx ... k]` is non-decreasing, `a[k ... n-1]` is non-increasing.
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // `k=3`: `[1,2,3,4]` (inc), `[4,2,1]` (dec). This is good.
    // Example: `[4, 5, 2]`
    // `k=1`: `[4,5]` (inc), `[5,2]` (dec). This is good.

    // So, the check for `is_good` is:
    // Find the peak.
    // `peak_idx` is the first index `i` such that `a[i] > a[i+1]`.
    // If no such `i`, the array is non-decreasing, which is good.
    // If such `i` exists, then `a[start_idx ... i]` must be non-decreasing.
    // And `a[i ... n-1]` must be non-increasing.

    // Let's find the first index `i` from `start_idx` such that `a[i] > a[i+1]`.
    // This `i` would be the end of the non-decreasing prefix.
    int i = start_idx;
    while (i < n - 1 && a[i] <= a[i+1]) {
        i++;
    }
    // Now `a[start_idx ... i]` is non-decreasing.
    // We need to check if `a[i ... n-1]` is non-increasing.
    int j = i;
    while (j < n - 1 && a[j] >= a[j+1]) {
        j++;
    }
    // If `j` reached `n-1`, it means `a[i ... n-1]` is non-increasing.
    // So the array `a[start_idx ... n-1]` is good if `j == n-1`.
    return j == n - 1;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // The problem asks for the shortest prefix to erase.
    // This means we want the longest suffix that is "good".
    // We can iterate `start_idx` from `0` to `n-1`.
    // The first `start_idx` for which `a[start_idx ... n-1]` is good is our answer.
    // The length of the prefix to erase is `start_idx`.

    // The `is_good` function checks if `a[start_idx ... n-1]` is good.
    // We need to find the smallest `start_idx` such that `is_good(a, start_idx)` is true.
    // We can iterate `start_idx` from `n-1` down to `0`.
    // The first `start_idx` for which `is_good(a, start_idx)` is true, that `start_idx` is the answer.
    // No, this is wrong. We want the shortest prefix to erase.
    // This means we want the largest `start_idx` such that `a[start_idx ... n-1]` is good.
    // The length of the prefix to erase is `start_idx`.
    // So we iterate `start_idx` from `n-1` down to `0`.
    // The first `start_idx` for which `is_good(a, start_idx)` is true, that `start_idx` is the answer.
    // Example: `a = [4, 3, 3, 8, 4, 5, 2]`, `n=7`.
    // `start_idx = 6`: `[2]`. Good. Answer `6`.
    // `start_idx = 5`: `[5, 2]`. Good. Answer `5`.
    // `start_idx = 4`: `[4, 5, 2]`. Good. Answer `4`.
    // `start_idx = 3`: `[8, 4, 5, 2]`. `i=3 (val 8)`. `j=4 (val 4)`. `a[4]=4, a[5]=5`. `a[4] < a[5]`. Not non-increasing. Not good.
    // So the answer is `4`.

    int ans_start_idx = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (is_good(a, i)) {
            ans_start_idx = i;
            break;
        }
    }
    std::cout << ans_start_idx << std::endl;
}

