// Function to check if a subarray forms a permutation of 1 to `len`
// `arr` is the original array, `start_idx` is the 0-based starting index, `len` is the length
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // Permutations must have non-zero length
        return false;
    }
    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for values
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // After checking all elements, ensure max_val is exactly len
    // and all numbers from 1 to len were seen (implicitly checked by seen array and max_val)
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix permutation validity
    // `prefix_is_perm[i]` is true if a[0...i-1] is a permutation of 1 to i
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix_val = 0;
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > i + 1 || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            if (val > max_prefix_val) {
                max_prefix_val = val;
            }
            if (max_prefix_val == i + 1) { // Check if all numbers from 1 to i+1 are present
                prefix_is_perm[i + 1] = true;
            }
        }
    }

    // Precompute suffix permutation validity
    // `suffix_is_perm[i]` is true if a[i...n-1] is a permutation of 1 to n-i
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i; // Length of the suffix a[i...n-1]
        int val = a[i];
        if (val < 1 || val > len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            if (val > max_suffix_val) {
                max_suffix_val = val;
            }
            if (max_suffix_val == len) { // Check if all numbers from 1 to len are present
                suffix_is_perm[i] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 is length of p1, from 1 to n-1
        int l2 = n - l1; // l2 is length of p2
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) { // suffix_is_perm[l1] means a[l1...n-1] is perm of 1 to n-l1
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

