#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: N=2, take 1 coin
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    // Taking N/2 leaves an odd number of coins for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // Taking 1 leaves an even number of coins for opponent.
                    // Opponent will take N'/2, leaving an odd number for Chanek.
                    // This is the tricky part.
                    // If N/2 is odd, and N > 2:
                    // Option 1: Take 1. N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // Option 2: Take N/2. N becomes N/2 (odd). Opponent takes 1. N becomes N/2-1 (even).
                    // Since both players play optimally to maximize their own score,
                    // Chanek wants to maximize his coins, and opponent wants to maximize theirs.
                    // If Chanek takes N/2, he gets N/2. Opponent gets to play on N/2 (odd).
                    // If Chanek takes 1, he gets 1. Opponent gets to play on N-1 (odd).
                    // The opponent will always take 1 if N is odd.
                    // So if Chanek takes N/2, opponent takes 1. Chanek gets N/2, opponent gets 1.
                    // If Chanek takes 1, opponent takes 1. Chanek gets 1, opponent gets 1.
                    // Chanek prefers N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // Taking N/2 leaves an even number of coins for opponent.
                    // Opponent can take N'/2.
                    // Taking 1 leaves an odd number of coins for opponent.
                    // Opponent will take 1.
                    // Chanek wants to maximize his coins.
                    // If Chanek takes N/2, he gets N/2. Opponent plays on N/2 (even).
                    // If Chanek takes 1, he gets 1. Opponent plays on N-1 (odd).
                    // Chanek will take N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

