int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually pass this 'b'.
            // Each 'a' to its left that passes this 'b' will generate
            // a new 'b' (from 'ab' -> 'bba').
            // So, the number of 'a's that will pass this 'b' is `count_a`.
            // Each such 'a' will contribute `count_a` steps to pass this 'b'
            // and the 'b's generated by other 'a's.
            // The total steps added by this 'b' is `count_a`.
            // This `count_a` also doubles for the next 'b' to its left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // pass all 'b's to its right.
            // The number of 'b's it needs to pass (including those generated
            // by other 'a's) is `count_a`.
            // This 'a' itself becomes one of the 'a's that needs to pass
            // 'b's further to the left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

