// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The pattern is built from right to left, so we need to reverse it
    // and then pad. Or, more simply, just pad and then reverse.
    // Since we are comparing patterns of fixed length 18,
    // we can just pad the pattern string to 18 characters.
    // Example: 241 -> "100". If pattern is "010", 241 matches.
    // The problem states "i-th from the right digit".
    // So, 241 (1 is 1st from right, 4 is 2nd, 2 is 3rd)
    // Pattern "010" (0 is 1st from right, 1 is 2nd, 0 is 3rd)
    // 1 (odd) matches 0 (even) -> NO
    // This means my interpretation of pattern generation is wrong.
    // The example says 241 matches 010.
    // 241: 1 (odd), 4 (even), 2 (even)
    // 010: 0 (even), 1 (odd), 0 (even)
    // If we align from right:
    // Number: ...00000000000000241
    // Pattern: ...00000000000000010
    // 1st from right: 1 (odd) vs 0 (even) -> MISMATCH
    // This contradicts the example.

    // Let's re-read: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means both are effectively padded to the maximum possible length (18) with '0's from the left.
    // Then, we compare digit by digit.
    // Example: s = 010, integer = 92
    // 92 as 18-digit number: 000000000000000092
    // 010 as 18-digit pattern: 000000000000000010
    // Parity of 92: ...00000000000000010 (9 is odd, 2 is even)
    // Pattern 010: ...00000000000000010
    // They match.

    // So, for a number `n`, we need to generate an 18-digit string where each character is '0' if the corresponding digit of `n` is even, and '1' if odd.
    // If `n` has fewer than 18 digits, it's padded with '0's from the left, which means its parity pattern will have '0's at the beginning.
    std::string full_pattern = "";
    for (int i = 0; i < 18; ++i) {
        if ((n % 10) % 2 == 0) {
            full_pattern += '0';
        } else {
            full_pattern += '1';
        }
        n /= 10;
    }
    std::reverse(full_pattern.begin(), full_pattern.end()); // Reverse to get correct order (most significant digit first)
    return full_pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to 18 characters
            std::string padded_s = std::string(18 - s.length(), '0') + s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long current_p = p;
        while (current_p % temp_q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

