#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i - 1]);
            adj[s[i - 1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting point for a chain: a character with only one neighbor in the password graph
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in s have 2 neighbors (i.e., form a cycle), pick any character from s as start
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    // Build the layout chain
    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first character

        while (visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0') break; // End of chain
        }
    }

    // Check if all characters from s are included in the built chain
    if (layout_str.length() != used_in_s.size()) {
        std::cout << "NO\n"; // This means there's a cycle or multiple disconnected components in the password graph
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

