int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> next_char_pos(n, std::vector<int>(26, n));
    for (int i = n - 1; i >= 0; --i) {
        if (i < n - 1) {
            next_char_pos[i] = next_char_pos[i + 1];
        }
        next_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> prev_char_pos(n, std::vector<int>(26, -1));
    for (int i = 0; i < n; ++i) {
        if (i > 0) {
            prev_char_pos[i] = prev_char_pos[i - 1];
        }
        prev_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> count_pairs(26, std::vector<int>(26, 0));
    std::vector<int> count_first_char(26, 0);

    for (int k = 0; k < n; ++k) {
        count_first_char[s[k] - 'a']++;
        for (int p = 1; p < n; ++p) {
            count_pairs[s[k] - 'a'][s[(k + p) % n] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int first_char_val = 0; first_char_val < 26; ++first_char_val) {
        if (count_first_char[first_char_val] == 0) {
            continue;
        }

        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < n; ++p) {
            int current_p_win_count = 0;
            for (int second_char_val = 0; second_char_val < 26; ++second_char_val) {
                int count = 0;
                for (int k = 0; k < n; ++k) {
                    if (s[k] - 'a' == first_char_val && s[(k + p) % n] - 'a' == second_char_val) {
                        count++;
                    }
                }
                if (count == 1) {
                    current_p_win_count++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)current_p_win_count / count_first_char[first_char_val]);
        }
        total_win_prob += max_win_prob_for_char * count_first_char[first_char_val];
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::string t(n, ' ');
        int last1 = -1; // last digit placed in color 1
        int first2 = 10; // first digit placed in color 2

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                t[i] = '1';
                if (d[i] < last1) { // S1 must be non-decreasing
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                t[i] = '2';
                if (d[i] < first2) { // S2 must be non-decreasing
                    first2 = d[i];
                }
            }
        }

        if (!possible_p) {
            continue;
        }

        // Now handle digits equal to p
        // Digits equal to p that appear before the first d_i > p must be 1
        // Digits equal to p that appear after the first d_i > p must be 2
        // This is not quite right.
        // The rule is: if d_i == p, it can be 1 or 2.
        // If it's 1, it must be >= last1.
        // If it's 2, it must be <= first2.
        // And last1 (overall) must be <= first2 (overall).

        // Let's refine the strategy for digits equal to p.
        // We want to find the "split point" among digits equal to p.
        // All d_i = p before this split point are color 1.
        // All d_i = p after this split point are color 2.
        // This split point is the first occurrence of 'p' that we assign to color 2.
        // All 'p's before it are color 1. All 'p's after it are color 2.

        int split_idx_for_p = -1; // Index of the first 'p' that goes to color 2
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (d[i] >= last1) { // Can be color 1
                    t[i] = '1';
                    last1 = d[i];
                } else { // Must be color 2
                    t[i] = '2';
                    if (split_idx_for_p == -1) {
                        split_idx_for_p = i;
                    }
                }
            }
        }

        // Now, if we assigned any 'p' to color 2, all subsequent 'p's must also be color 2.
        // And all 'p's before the first 'p' assigned to color 2 must be color 1.
        // This is the logic:
        // Iterate through d_i.
        // If d_i < p, it's '1'. Update last1.
        // If d_i > p, it's '2'. Update first2.
        // If d_i == p:
        //   If d_i >= last1, we can assign it '1'. Update last1.
        //   Else, we must assign it '2'.
        // This greedy approach for 'p's might not work.
        // Example: 1 0 1 0, p=0.
        // d[0]=1 > p, t[0]='2'. first2=1.
        // d[1]=0 == p. last1=-1. d[1] >= last1. t[1]='1'. last1=0.
        // d[2]=1 > p, t[2]='2'. first2=1.
        // d[3]=0 == p. last1=0. d[3] >= last1. t[3]='1'. last1=0.
        // Result: 2121. S1: 00, S2: 11. Valid.

        // Example: 0 1 0, p=0.
        // d[0]=0 == p. last1=-1. d[0] >= last1. t[0]='1'. last1=0.
        // d[1]=1 > p. t[1]='2'. first2=1.
        // d[2]=0 == p. last1=0. d[2] >= last1. t[2]='1'. last1=0.
        // Result: 121. S1: 00, S2: 1. Valid.

        // The issue is that if d[i] == p and d[i] < last1, it *must* be '2'.
        // But if d[i] == p and d[i] >= last1, it *can* be '1' or '2'.
        // To maximize chances of success, we should try to put it in '1' if possible.
        // This is what the previous loop did.

        // Let's re-evaluate the conditions for a valid coloring for a fixed p:
        // 1. All d_i < p are color 1.
        // 2. All d_i > p are color 2.
        // 3. For d_i = p:
        //    There exists an index k (0 <= k <= n) such that:
        //    All d_j = p with j < k are color 1.
        //    All d_j = p with j >= k are color 2.
        // 4. The sequence of all color 1 digits must be non-decreasing.
        // 5. The sequence of all color 2 digits must be non-decreasing.
        // 6. The last color 1 digit must be <= the first color 2 digit.

        // Let's try to find the optimal k for each p.
        // We can iterate through all possible k (0 to n).
        // For a fixed p and k:
        // Construct S1 and S2.
        // S1: all d_i < p, plus all d_j = p with j < k.
        // S2: all d_i > p, plus all d_j = p with j >= k.
        // Check if S1 is sorted, S2 is sorted, and last(S1) <= first(S2).

        // This is too slow (10 * N * N).
        // A better approach for fixed p:
        // Initialize t with '1' for d_i < p, '2' for d_i > p.
        // For d_i = p, initially assign '1'.
        // Then, find the first index `idx_p_to_2` such that `d[idx_p_to_2] == p` and `d[idx_p_to_2]` must be '2'
        // because `d[idx_p_to_2] < last1_so_far`.
        // If such an `idx_p_to_2` exists, then all `d_j = p` for `j >= idx_p_to_2` must be '2'.
        // All `d_j = p` for `j < idx_p_to_2` must be '1'.

        std::string current_t(n, ' ');
        int current_last1 = -1;
        int current_first2 = 10;
        bool possible_coloring = true;

        // First pass: assign d_i < p to 1, d_i > p to 2.
        // For d_i = p, tentatively assign to 1.
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                current_t[i] = '1';
                if (d[i] < current_last1) {
                    possible_coloring = false;
                    break;
                }
                current_last1 = d[i];
            } else if (d[i] > p) {
                current_t[i] = '2';
            } else { // d[i] == p
                current_t[i] = '1'; // Tentatively assign to 1
            }
        }

        if (!possible_coloring) {
            continue;
        }

        // Second pass: adjust d_i = p assignments.
        // Find the first 'p' that must be '2'.
        int first_p_to_2_idx = -1;
        int temp_last1 = -1; // Track last1 for digits < p and p assigned to 1
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                temp_last1 = d[i];
            } else if (d[i] == p) {
                if (d[i] < temp_last1) { // This 'p' cannot be '1'
                    first_p_to_2_idx = i;
                    break;
                }
                temp_last1 = d[i];
            }
        }

        // Now, apply the split point for 'p's.
        // All d_i = p before first_p_to_2_idx are '1'.
        // All d_i = p from first_p_to_2_idx onwards are '2'.
        current_last1 = -1;
        current_first2 = 10;
        possible_coloring = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                current_t[i] = '1';
                if (d[i] < current_last1) {
                    possible_coloring = false;
                    break;
                }
                current_last1 = d[i];
            } else if (d[i] > p) {
                current_t[i] = '2';
                if (d[i] < current_first2) {
                    current_first2 = d[i];
                }
            } else { // d[i] == p
                if (first_p_to_2_idx == -1 || i < first_p_to_2_idx) {
                    current_t[i] = '1';
                    if (d[i] < current_last1) {
                        possible_coloring = false;
                        break;
                    }
                    current_last1 = d[i];
                } else {
                    current_t[i] = '2';
                    if (d[i] < current_first2) {
                        current_first2 = d[i];
                    }
                }
            }
        }

        if (!possible_coloring) {
            continue;
        }

        // Final check: last1 <= first2
        // Reconstruct S1 and S2 to get the actual last1 and first2.
        std::string s1_digits = "";
        std::string s2_digits = "";
        for (int i = 0; i < n; ++i) {
            if (current_t[i] == '1') {
                s1_digits += d_str[i];
            } else {
                s2_digits += d_str[i];
            }
        }

        bool s1_sorted = true;
        if (!s1_digits.empty()) {
            for (size_t i = 0; i < s1_digits.length() - 1; ++i) {
                if (s1_digits[i] > s1_digits[i+1]) {
                    s1_sorted = false;
                    break;
                }
            }
        }
        if (!s1_sorted) continue;

        bool s2_sorted = true;
        if (!s2_digits.empty()) {
            for (size_t i = 0; i < s2_digits.length() - 1; ++i) {
                if (s2_digits[i] > s2_digits[i+1]) {
                    s2_sorted = false;
                    break;
                }
            }
        }
        if (!s2_sorted) continue;

        bool combined_sorted = true;
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                combined_sorted = false;
            }
        }
        if (!combined_sorted) continue;

        std::cout << current_t << "\n";
        return;
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total difference
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Precompute prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s) - (count of 2s) among jars a_1, ..., a_k
    // We are interested in the remaining jars, so we need to consider
    // the difference of jars a_{k+1}, ..., a_n.
    // Let's define diff_L_removed[k] as the difference of jars a_1, ..., a_k
    // This is the difference of jars removed from the left.
    std::vector<int> diff_L_removed(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L_removed[i + 1] = diff_L_removed[i] + (a[i] == 1 ? 1 : -1);
    }

    // Precompute prefix sums for the right side (jars n+1 to 2n)
    // diff_R_removed[k] = (count of 1s) - (count of 2s) among jars a_{2n}, ..., a_{2n-k+1}
    // This is the difference of jars removed from the right.
    std::vector<int> diff_R_removed(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R_removed[i + 1] = diff_R_removed[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store indices for each difference value for the left side
    // map_L[diff_val] = k (number of jars removed from left)
    std::map<int, int> map_L;
    for (int k = 0; k <= n; ++k) {
        // We want to find the minimum k for a given diff_L_removed[k]
        // So, if a diff_val is encountered again, we don't update it
        // because we already stored the smaller k.
        if (map_L.find(diff_L_removed[k]) == map_L.end()) {
            map_L[diff_L_removed[k]] = k;
        }
    }

    int min_removed = 2 * n; // Max possible jars to remove

    // Iterate through all possible numbers of jars removed from the right side
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_R_removed = diff_R_removed[k_R];

        // The target difference for the left removed jars is such that
        // initial_diff - current_diff_L_removed - current_diff_R_removed = 0
        // current_diff_L_removed = initial_diff - current_diff_R_removed
        int target_diff_L_removed = initial_diff - current_diff_R_removed;

        if (map_L.count(target_diff_L_removed)) {
            int k_L = map_L[target_diff_L_removed];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track what happens to an input bit 0 and an input bit 1.
    // initial_val_if_input_bit_is_0[bit_idx]
    // initial_val_if_input_bit_is_1[bit_idx]
    // Initially, if input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
    std::vector<int> val_if_input_bit_is_0(10); // Stores the final state of bit_idx if input bit_idx was 0
    std::vector<int> val_if_input_bit_is_1(10); // Stores the final state of bit_idx if input bit_idx was 1

    for (int i = 0; i < 10; ++i) {
        val_if_input_bit_is_0[i] = 0;
        val_if_input_bit_is_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int i = 0; i < 10; ++i) {
            int bit_x = (x >> i) & 1;
            if (op_char == '&') {
                val_if_input_bit_is_0[i] &= bit_x;
                val_if_input_bit_is_1[i] &= bit_x;
            } else if (op_char == '|') {
                val_if_input_bit_is_0[i] |= bit_x;
                val_if_input_bit_is_1[i] |= bit_x;
            } else { // '^'
                val_if_input_bit_is_0[i] ^= bit_x;
                val_if_input_bit_is_1[i] ^= bit_x;
            }
        }
    }

    // Now, we have the final state for each bit.
    // We need to find a minimal sequence of operations to achieve this.
    // The target is to transform (0,1) to (val_if_input_bit_is_0[i], val_if_input_bit_is_1[i]) for each bit i.
    // Possible transformations for (input_bit_0, input_bit_1):
    // (0,1) -> (0,0) : AND 0
    // (0,1) -> (0,1) : No change (identity)
    // (0,1) -> (1,0) : XOR 1
    // (0,1) -> (1,1) : OR 1

    // Let's find the combined constants for AND, OR, XOR operations.
    // We want to find A, O, X such that:
    // (x & A | O) ^ X
    // This is equivalent to:
    // (x | O') & A' ^ X'
    // Or, more simply, we can find a sequence of at most 3 operations.
    // A single AND, OR, XOR operation can achieve some transformations.
    // For example, if all bits map (0,1) -> (0,0), then it's just `& 0`.
    // If all bits map (0,1) -> (1,1), then it's just `| 1023`.
    // If all bits map (0,1) -> (1,0), then it's just `^ 1023`.

    // Let's try to construct the final constants for a sequence of operations.
    // We can use the property that (x & A | O) ^ X can represent any function.
    // Specifically, we can determine A, O, X for each bit.
    // For each bit i:
    // Let (v0, v1) = (val_if_input_bit_is_0[i], val_if_input_bit_is_1[i])
    //
    // If (v0, v1) = (0,0): This bit must become 0 regardless of input.
    //   (0 & A_i | O_i) ^ X_i = 0
    //   (1 & A_i | O_i) ^ X_i = 0
    //   This implies A_i=0, O_i=0, X_i=0 (if we want to keep it simple)
    //   Or, A_i=0, O_i=1, X_i=1
    //   Simplest: A_i=0, O_i=0, X_i=0. This means the bit is forced to 0.
    //   This means the final AND constant must have 0 at this bit.
    //   And the final OR constant must have 0 at this bit.
    //   And the final XOR constant must have 0 at this bit.
    //   This is achieved by `& 0` for this bit.
    //
    // If (v0, v1) = (0,1): This bit must be equal to the input bit.
    //   (0 & A_i | O_i) ^ X_i = 0
    //   (1 & A_i | O_i) ^ X_i = 1
    //   This implies A_i=1, O_i=0, X_i=0. This means the bit is unchanged.
    //   This is achieved by `& 1` for this bit, `| 0` for this bit, `^ 0` for this bit.
    //
    // If (v0, v1) = (1,0): This bit must be the inverse of the input bit.
    //   (0 & A_i | O_i) ^ X_i = 1
    //   (1 & A_i | O_i) ^ X_i = 0
    //   This implies A_i=1, O_i=0, X_i=1. This means the bit is flipped.
    //   This is achieved by `& 1` for this bit, `| 0` for this bit, `^ 1` for this bit.
    //
    // If (v0, v1) = (1,1): This bit must become 1 regardless of input.
    //   (0 & A_i | O_i) ^ X_i = 1
    //   (1 & A_i | O_i) ^ X_i = 1
    //   This implies A_i=0, O_i=1, X_i=0. This means the bit is forced to 1.
    //   This is achieved by `| 1` for this bit.

    // Let's define three constants:
    // `and_const`: bits that must be 0 in the output (force to 0)
    // `or_const`: bits that must be 1 in the output (force to 1)
    // `xor_const`: bits that must be flipped from the input (invert)

    int final_and_val = 1023; // All bits are 1 initially for AND mask
    int final_or_val = 0;     // All bits are 0 initially for OR mask
    int final_xor_val = 0;    // All bits are 0 initially for XOR mask

    for (int i = 0; i < 10; ++i) {
        int v0 = val_if_input_bit_is_0[i];
        int v1 = val_if_input_bit_is_1[i];

        if (v0 == 0 && v1 == 0) { // Bit must be 0 regardless of input
            // This means the bit must be forced to 0.
            // Achieved by `& 0` for this bit.
            final_and_val &= ~(1 << i); // Set i-th bit of final_and_val to 0
        } else if (v0 == 0 && v1 == 1) { // Bit must be same as input
            // Achieved by `& 1`, `| 0`, `^ 0` for this bit.
            // No change to final_and_val, final_or_val, final_xor_val for this bit.
        } else if (v0 == 1 && v1 == 0) { // Bit must be inverse of input
            // Achieved by `& 1`, `| 0`, `^ 1` for this bit.
            final_xor_val |= (1 << i); // Set i-th bit of final_xor_val to 1
        } else { // v0 == 1 && v1 == 1 // Bit must be 1 regardless of input
            // This means the bit must be forced to 1.
            // Achieved by `| 1` for this bit.
            final_or_val |= (1 << i); // Set i-th bit of final_or_val to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n); // a_suffix[k] stores a_{k+1}
    for (int k = 0; k < n - 1; ++k) {
        std::cin >> a_suffix[k];
    }

    // dp_x[k] stores the final x value if we start at index k+1 with a_k+1
    // dp_y[k] stores the final y value if we start at index k+1 with a_k+1
    // dp_x[k] = 0 means it terminates at x <= 0
    // dp_x[k] = n+1 means it terminates at x > n
    // dp_x[k] = -1 means it's part of a cycle (non-terminating)
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection

    // Base cases:
    // If x + a_x <= 0, then x becomes <= 0.
    // If x + a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_add.
    // The y value is just a_x.
    // The final x value is 0 or n+1 respectively.
    //
    // If x - a_x <= 0, then x becomes <= 0.
    // If x - a_x > n, then x becomes > n.
    // In these cases, the program terminates after step_sub.
    // The y value is a_x + a_x = 2*a_x.
    // The final x value is 0 or n+1 respectively.

    // Iterate backwards from n to 1
    for (int k = n; k >= 1; --k) {
        long long current_a_val = a_suffix[k - 1]; // a_k

        long long next_x_after_add = k + current_a_val;
        long long next_x_after_sub = k - current_a_val;

        if (next_x_after_add <= 0) { // Terminates after step_add
            dp_x[k] = 0;
            dp_y[k] = current_a_val;
        } else if (next_x_after_add > n) { // Terminates after step_add
            dp_x[k] = n + 1;
            dp_y[k] = current_a_val;
        } else { // Continues to step_sub
            if (next_x_after_sub <= 0) { // Terminates after step_sub
                dp_x[k] = 0;
                dp_y[k] = current_a_val + current_a_val;
            } else if (next_x_after_sub > n) { // Terminates after step_sub
                dp_x[k] = n + 1;
                dp_y[k] = current_a_val + current_a_val;
            } else { // Continues to next iteration
                // This is where we use DP. The next state is (next_x_after_sub, current_a_val + current_a_val + dp_y[next_x_after_sub])
                // We need to handle cycles.

                // Simulate the path from k to detect cycles or find a known state
                std::vector<int> path;
                int current_pos = k;
                long long current_total_y = 0;

                while (current_pos >= 1 && current_pos <= n && !visited[current_pos] && dp_x[current_pos] == 0) { // dp_x[current_pos] == 0 means not yet computed
                    visited[current_pos] = true;
                    path.push_back(current_pos);

                    long long val_at_pos = a_suffix[current_pos - 1];
                    current_total_y += val_at_pos; // y after step_add

                    long long next_x_after_add_path = current_pos + val_at_pos;
                    if (next_x_after_add_path <= 0 || next_x_after_add_path > n) {
                        current_pos = (next_x_after_add_path <= 0) ? 0 : n + 1;
                        break;
                    }

                    current_total_y += val_at_pos; // y after step_sub
                    current_pos = next_x_after_add_path - val_at_pos; // x after step_sub
                }

                if (current_pos <= 0 || current_pos > n) { // Terminated
                    for (int p_idx = 0; p_idx < path.size(); ++p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = current_pos;
                        dp_y[p] = current_total_y;
                        current_total_y -= (2 * a_suffix[p - 1]); // Subtract 2*a_p to get y for previous state
                    }
                } else if (dp_x[current_pos] == -1) { // Cycle detected
                    for (int p : path) {
                        dp_x[p] = -1;
                        dp_y[p] = -1;
                    }
                } else { // Reached a previously computed state
                    long long final_x_from_known = dp_x[current_pos];
                    long long final_y_from_known = dp_y[current_pos];

                    for (int p_idx = path.size() - 1; p_idx >= 0; --p_idx) {
                        int p = path[p_idx];
                        dp_x[p] = final_x_from_known;
                        dp_y[p] = final_y_from_known + (2 * a_suffix[p - 1]);
                        final_y_from_known = dp_y[p]; // Update for the next iteration (previous state in path)
                    }
                }

                // Reset visited for the current path
                for (int p : path) {
                    visited[p] = false;
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        long long a1_val = i;
        long long current_y = 0;
        int current_x = 1;

        // First step_add
        current_y += a1_val;
        int next_x_after_add = current_x + a1_val;

        if (next_x_after_add <= 0 || next_x_after_add > n) {
            std::cout << current_y << "\n";
        } else {
            // First step_sub
            current_y += a1_val;
            int next_x_after_sub = next_x_after_add - a1_val;

            if (next_x_after_sub <= 0 || next_x_after_sub > n) {
