#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i = 0 for all i.
    // b_i represents the minimum possible initial value for a_i.
    // We want to find a_0[i] such that a_0[i] + b_i is maximized,
    // but also satisfies a_0[i] + b_i <= m_k - sum_d_k(i) for all type 2 ops.
    // So, a_0[i] <= m_k - sum_d_k(i) - b_i.
    // To maximize a_0[i], we want a_0[i] = min(m_k - sum_d_k(i) - b_i).
    // This is equivalent to a_0[i] = min(m_k - (sum_d_k(i) + b_i)).
    // Let's define a_0[i] = min_val_for_a0[i].
    // Initially, a_0[i] can be anything, so we set it to a large value.
    std::vector<long long> a0_initial_values(n, 2000000000LL); // Max possible initial value for a_0[i]

    // current_delta[j] stores the sum of d_i for type 1 operations
    // that affect index j *up to the current point in the simulation*.
    // This is used to calculate sum_d_k(j) for type 2 operations.
    std::vector<long long> current_delta(n, 0);

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Type 1 operation: 1 l r d
            // This operation adds d to a_j for l <= j <= r.
            // This means that for any future type 2 operation,
            // the effective sum of deltas for j in [l, r] increases by d.
            // So, we update current_delta for the range [l, r].
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else {
            // Type 2 operation: 2 l r m
            // The maximum of a_j in [l, r] is m.
            // For each j in [l, r], we know that a_0[j] + current_delta[j] <= m.
            // This implies a_0[j] <= m - current_delta[j].
            // We update a0_initial_values[j] with this new upper bound.
            for (int j = op.l; j <= op.r; ++j) {
                a0_initial_values[j] = std::min(a0_initial_values[j], op.val - current_delta[j]);
            }
        }
    }

    // Now we have a candidate initial array a0_initial_values.
    // We need to verify if this array satisfies all type 2 operations.
    // To do this, we simulate the operations again with this initial array.
    std::vector<long long> current_a(n);
    for (int i = 0; i < n; ++i) {
        current_a[i] = a0_initial_values[i];
    }

    // Reset current_delta for the second pass simulation
    std::fill(current_delta.begin(), current_delta.end(), 0);

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Type 1 operation: 1 l r d
            // This operation adds d to the current values.
            // We track this by updating current_delta.
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else {
            // Type 2 operation: 2 l r m
            // Check if the maximum in [l, r] is indeed m.
            long long max_val_in_range = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a0_initial_values[j] + current_delta[j]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print "YES" and the initial array.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0_initial_values[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

