        // If `p[p_idx]` is too far to the left for `h[h_idx]` (i.e., `p[p_idx] > h[h_idx] + T`),
        // then `h[h_idx]` cannot cover `p[p_idx]`. We must use the next head.
        // If `p[p_idx]` is too far to the right for `h[h_idx]` (i.e., `p[p_idx] < h[h_idx] - T`),
        // then `h[h_idx]` cannot cover `p[p_idx]`.
        // Since `h` is sorted, `h[h_idx+1]` will be even further right, so it also cannot cover `p[p_idx]`.
        // This means `p[p_idx]` cannot be covered by any remaining head. So, return false.
        // If `h[h_idx] - T <= p[p_idx] <= h[h_idx] + T`, then `h[h_idx]` can cover `p[p_idx]`.
        // To maximize coverage, `h[h_idx]` should cover all tracks from `p[p_idx]` up to `h[h_idx] + T`.
        // So, we advance `p_idx` past all tracks that are `<= h[h_idx] + T`.

        // This logic seems correct.
        // `p_idx` is the index of the first *uncovered* track.
        // `h_idx` is the index of the current head we are trying to use.
        // We iterate `h_idx` from `0` to `n-1`.
        // Inside the loop:
        //   If `p_idx == m`, all tracks are covered. Return true.
        //   `current_head_left_reach = h[h_idx] - T;`
        //   `current_head_right_reach = h[h_idx] + T;`
        //   If `p[p_idx] > current_head_right_reach`:
        //     This head is too far left to cover `p[p_idx]`. It cannot cover `p[p_idx]` or any subsequent tracks.
        //     So, this head is useless for `p[p_idx]`. Move to the next head (`h_idx++`).
        //     `continue;`
        //   If `p[p_idx] < current_head_left_reach`:
        //     This head is too far right to cover `p[p_idx]`.
        //     Since `p` is sorted and `h` is sorted, any subsequent head `h[h_idx+k]` will have `h[h_idx+k] - T >= current_head_left_reach`.
        //     So, no subsequent head can cover `p[p_idx]` either.
        //     Thus, `p[p_idx]` cannot be covered. Return `false`.
        //   Otherwise (`current_head_left_reach <= p[p_idx] <= current_head_right_reach`):
        //     This head can cover `p[p_idx]`.
        //     To maximize coverage, this head should cover all tracks from `p[p_idx]` up to `current_head_right_reach`.
        //     Advance `p_idx` past all tracks `p[k]` such that `p[k] <= current_head_right_reach`.
        //     `while (p_idx < m && p[p_idx] <= current_head_right_reach) p_idx++;`
        // After the loop, if `p_idx == m`, all tracks are covered. Return true.
        // Otherwise, some tracks are not covered. Return false.

        // Let's trace example 1:
        // n=3, m=4
        // h = [2, 5, 6]
        // p = [1, 3, 6, 8]
        // Try T=2
        // head_left_reach = [0, 3, 4]
        // head_right_reach = [4, 7, 8]

        // p_idx = 0 (p[0]=1)
        // h_idx = 0 (h[0]=2)
        //   current_head_left_reach = 0, current_head_right_reach = 4
        //   p[0]=1. Is p[0] > 4? No.
        //   Is p[0] < 0? No.
        //   So, 0 <= 1 <= 4. Head 0 covers p[0].
        //   Advance p_idx:
        //     p[0]=1 <= 4. p_idx becomes 1.
        //     p[1]=3 <= 4. p_idx becomes 2.
        //     p[2]=6 > 4. Stop.
        //   p_idx is now 2. (Tracks 1, 3 covered by head 0)

        // h_idx = 1 (h[1]=5)
        //   p_idx = 2 (p[2]=6)
        //   current_head_left_reach = 3, current_head_right_reach = 7
        //   p[2]=6. Is p[2] > 7? No.
        //   Is p[2] < 3? No.
        //   So, 3 <= 6 <= 7. Head 1 covers p[2].
        //   Advance p_idx:
        //     p[2]=6 <= 7. p_idx becomes 3.
        //     p[3]=8 > 7. Stop.
        //   p_idx is now 3. (Track 6 covered by head 1)

        // h_idx = 2 (h[2]=6)
        //   p_idx = 3 (p[3]=8)
        //   current_head_left_reach = 4, current_head_right_reach = 8
        //   p[3]=8. Is p[3] > 8? No.
        //   Is p[3] < 4? No.
        //   So, 4 <= 8 <= 8. Head 2 covers p[3].
        //   Advance p_idx:
        //     p[3]=8 <= 8. p_idx becomes 4.
        //     p_idx is now 4. Loop condition `p_idx < m` (4 < 4) is false. Stop.
        //   p_idx is now 4. (Track 8 covered by head 2)

        // Loop for h_idx finishes.
        // p_idx is 4. Since p_idx == m, all tracks are covered. Return true.
        // This matches example output.

        // Let's trace example 3:
        // n=1, m=2
        // h = [165]
        // p = [142, 200]
        // Try T=81
        // head_left_reach = [165-81 = 84]
        // head_right_reach = [165+81 = 246]

        // p_idx = 0 (p[0]=142)
        // h_idx = 0 (h[0]=165)
        //   current_head_left_reach = 84, current_head_right_reach = 246
        //   p[0]=142. Is p[0] > 246? No.
        //   Is p[0] < 84? No.
        //   So, 84 <= 142 <= 246. Head 0 covers p[0].
        //   Advance p_idx:
        //     p[0]=142 <= 246. p_idx becomes 1.
        //     p[1]=200 <= 246. p_idx becomes 2.
        //     p_idx is now 2. Loop condition `p_idx < m` (2 < 2) is false. Stop.
        //   p_idx is now 2. (Tracks 142, 200 covered by head 0)

        // Loop for h_idx finishes.
        // p_idx is 2. Since p_idx == m, all tracks are covered. Return true.
        // This matches example output.

        // The logic seems solid.

        long long current_head_left_reach = h[h_idx] - T;
        long long current_head_right_reach = h[h_idx] + T;

        // If p[p_idx] is to the right of current head's reach, this head cannot cover p[p_idx].
        // This head is too far left. Try next head.
        if (p[p_idx] > current_head_right_reach) {
            continue;
        }

        // If p[p_idx] is to the left of current head's reach, this head cannot cover p[p_idx].
        // This head is too far right. Since heads are sorted, no subsequent head can cover p[p_idx].
        // So, p[p_idx] cannot be covered.
        if (p[p_idx] < current_head_left_reach) {
            return false;
        }

        // Otherwise, p[p_idx] is within the current head's reach.
        // This head can cover p[p_idx].
        // Greedily cover all tracks up to current_head_right_reach.
        while (p_idx < m && p[p_idx] <= current_head_right_reach) {
            p_idx++;
        }
    }

    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2 * 10^10 is a safe upper bound.
                                    // (p_m - h_1) or (h_n - p_1) could be 10^10.
                                    // If h_1=1, p_m=10^10, T could be 10^10.
                                    // If h_1=10^10, p_1=1, T could be 10^10.
                                    // Max value of p_i or h_i is 10^10.
                                    // Max difference is 10^10 - 1.
                                    // So 10^10 is a good upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}
